// ─── BTS Opticien-Lunetier ───
const T={accent:"#FFB259",green:"#4AEAAC",blue:"#5EB5FF",red:"#FF6370",text2:"#A199B2",text3:"#6B6280"};

// ─── BANQUES DE QUESTIONS ───

export const QB_OL_OPTIQUE_GEO = [
  {id:"ol_og1",prompt:"La vergence d'un système optique est exprimée en :",choices:["Mètres (m)","Dioptries (δ)","Nanomètres (nm)","Radians (rad)"],answer:1,diff:1,explication:"Vergence V = 1/f' (en dioptries). f' = distance focale image en mètres. V positive = système convergent. V négative = système divergent.",tags:["Optique","Vergence","Système optique"]},
  {id:"ol_og2",prompt:"Un verre de -3.00 dioptries est destiné à corriger :",choices:["L'hypermétropie","La presbytie","La myopie (verre divergent)","L'astigmatisme"],answer:2,diff:1,explication:"Verre divergent (vergence négative) compense la trop grande convergence de l'œil myope. Le punctum remotum (PR) du myope est en avant de la rétine.",tags:["Optique","Myopie","Vergence"]},
  {id:"ol_og3",prompt:"Pour un verre de +2.50 δ, la distance focale image est de :",choices:["25 cm","40 cm","2.5 mm","100 cm"],answer:1,diff:2,explication:"f' = 1/V = 1/2.50 = 0.40 m = 40 cm. C'est la distance à laquelle un verre convergent (+) donne une image d'un objet à l'infini.",tags:["Optique","Vergence","Focale"]},
  {id:"ol_og4",prompt:"La relation de conjugaison d'un dioptre mince (formule de Descartes) est :",choices:["n'/OA' - n/OA = (n'-n)/R","1/OA' - 1/OA = V","n'/v - n/u = (n'-n)/R","Toutes sont équivalentes"],answer:1,diff:3,explication:"Formule de conjugaison dioptre : n'/OA' - n/OA = (n'-n)/R où n et n' sont les indices de réfraction, R le rayon de courbure, OA et OA' les distances algébriques.",tags:["Optique","Dioptre","Conjugaison"]},
  {id:"ol_og5",prompt:"Un prisme de 2Δ (2 dioptries prismatiques) dévie la lumière de :",choices:["2° exactement","Environ 2 cm à 1 mètre","2 mm à 1 cm","Dépend de la couleur"],answer:1,diff:2,explication:"1 dioptrie prismatique = déviation de 1 cm à 1 mètre. 2Δ = déviation de 2 cm à 1 mètre. Formule : Δ = d (cm) / D (m).",tags:["Optique","Prisme","Dioptrie prismatique"]},
  {id:"ol_og6",prompt:"L'indice de réfraction d'un verre ophtalmique standard (blanc basique) est d'environ :",choices:["1.00","1.50","1.70","2.00"],answer:1,diff:1,explication:"Verre standard (organique CR39) : n ≈ 1.50. Verres haute index : 1.60, 1.67, 1.74. Plus l'indice est élevé, plus le verre est mince à vergence égale.",tags:["Optique","Indice de réfraction","Verre ophtalmique"]},
  {id:"ol_og7",prompt:"Le grossissement commercial d'un système optique est défini par :",choices:["Le rapport des distances focales","G = -OA'/OA (rapport des distances image/objet)","G = V × n","G = f' / f"],answer:1,diff:2,explication:"Grossissement transversal G = -OA'/OA = A'B'/AB. G > 0 = image droite. G < 0 = image renversée. |G| > 1 = agrandissement.",tags:["Optique","Grossissement","Systèmes optiques"]},
  {id:"ol_og8",prompt:"L'aberration chromatique est due au fait que :",choices:["Le verre est trop épais","L'indice de réfraction varie avec la longueur d'onde (dispersion)","La pupille est trop grande","La cornée est asphérique"],answer:1,diff:2,explication:"Dispersion : n varie avec λ (loi de Cauchy). Blanc → spectre → foyer varie selon la couleur. Quantifiée par le nombre d'Abbe (Vd). Vd élevé = peu de dispersion = verre de qualité.",tags:["Optique","Aberration chromatique","Nombre d'Abbe"]},
  {id:"ol_og9",prompt:"Le nombre d'Abbe (Vd) élevé indique :",choices:["Une grande aberration chromatique","Une faible aberration chromatique (verre de qualité)","Un indice de réfraction élevé","Un verre divergent"],answer:1,diff:2,explication:"Vd = (nd - 1)/(nF - nC). Vd élevé (> 50) = faible dispersion = meilleure qualité optique. CR39 : Vd ≈ 58. Haute index 1.74 : Vd ≈ 33 (plus de dispersion).",tags:["Optique","Nombre d'Abbe","Aberration"]},
  {id:"ol_og10",prompt:"Pour une lentille mince de vergence V, la formule des verriers est :",choices:["V = (n-1)(1/R1 - 1/R2)","V = n × R","V = f'/n","V = (n-1) × R"],answer:0,diff:3,explication:"Formule des verriers : V = (n-1)(1/R1 - 1/R2). R1 et R2 : rayons de courbure des faces (en mètres). n : indice du verre. Permet de calculer la vergence à partir de la géométrie.",tags:["Optique","Formule des verriers","Lentille"]},
  {id:"ol_og11",prompt:"Un miroir plan forme d'un objet réel une image :",choices:["Réelle, renversée","Virtuelle, droite, de même taille","Virtuelle, plus petite","Réelle, agrandie"],answer:1,diff:1,explication:"Miroir plan : image virtuelle (derrière le miroir), droite, symétrique de l'objet par rapport au miroir (même taille). Applications : optométrie (réduction de la distance d'examen).",tags:["Optique","Miroir plan","Image"]},
  {id:"ol_og12",prompt:"La profondeur de champ augmente quand :",choices:["Le diamètre pupillaire augmente","La vergence du verre augmente","Le diamètre pupillaire diminue (pupille petite)","L'indice du verre diminue"],answer:2,diff:2,explication:"Profondeur de champ ∝ 1/pupille. Pupille étroite (soleil, vieillissement) → grande profondeur de champ → masque la presbytie. C'est pourquoi les myopes sans lunettes plissent les yeux.",tags:["Optique","Profondeur de champ","Pupille"]},
];

export const QB_OL_OPTIQUE_PHYSIO = [
  {id:"ol_op1",prompt:"L'accommodation est la capacité de l'œil à :",choices:["Voir les couleurs","Modifier sa vergence pour voir net à différentes distances (bombement du cristallin)","S'adapter à l'obscurité","Distinguer deux points proches"],answer:1,diff:1,explication:"Accommodation = augmentation de la vergence cristallinienne (contraction du muscle ciliaire, bombement du cristallin). Permet de voir net du punctum proximum (PP) au punctum remotum (PR).",tags:["Optique physiologique","Accommodation","Cristallin"]},
  {id:"ol_op2",prompt:"La presbytie est due à :",choices:["Une trop grande convergence du cristallin","La perte de l'élasticité du cristallin avec l'âge (réduction de l'accommodation)","Une cornée trop plate","Un globe trop long"],answer:1,diff:1,explication:"Presbytie : perte progressive de la souplesse cristallinienne (sclérose). Le PP s'éloigne progressivement. Débute vers 40-45 ans. Non pathologique = évolution naturelle.",tags:["Optique physiologique","Presbytie","Cristallin","Accommodation"]},
  {id:"ol_op3",prompt:"Un œil myope ne corrigé :",choices:["Voit mal de loin, bien de près","Voit bien de loin et de près","Voit mal de loin ET de près","Voit seulement en monoculaire"],answer:0,diff:1,explication:"Myopie : œil trop long ou cornée trop cambrée → image se forme en avant de la rétine. Voit bien de près (PR rapproché), mal de loin. Correction : verre divergent.",tags:["Optique physiologique","Myopie","Réfraction"]},
  {id:"ol_op4",prompt:"L'hypermétropie se caractérise par :",choices:["Un globe trop long","Un globe trop court ou une cornée trop plate → images forment en arrière de la rétine","Une cornée trop cambrée","Un cristallin trop convexe"],answer:1,diff:1,explication:"Hypermétropie : globe trop court ou faible courbure cornée → image en arrière de la rétine. Compensée par accommodation. Correction : verre convergent (+). Fatigue visuelle si non corrigée.",tags:["Optique physiologique","Hypermétropie","Réfraction"]},
  {id:"ol_op5",prompt:"L'astigmatisme est dû à :",choices:["Une longueur axiale anormale","Une asymétrie de courbure de la cornée ou du cristallin → deux foyers distincts","Un trouble de l'accommodation","Une opacité du cristallin"],answer:1,diff:1,explication:"Astigmatisme : deux méridiens principaux de courbure différents (conoid de Sturm). Voit flou à toutes distances. Correction : verre cylindrique (tore). Prescription : sphère / cylindre × axe.",tags:["Optique physiologique","Astigmatisme","Cornée","Tore"]},
  {id:"ol_op6",prompt:"L'acuité visuelle de loin est mesurée avec :",choices:["La règle de Jaeger","L'échelle de Monoyer (Snellen)","Le test de Parinaud","L'optotype Landolt"],answer:1,diff:1,explication:"AV de loin : échelle de Monoyer (lettres) ou Snellen (optotypes). Mesurée à 5 mètres. AV = 10/10 = normale. AV de près : Parinaud (P2 = excellent, P14 = acuité réduite).",tags:["Optique physiologique","Acuité visuelle","Monoyer","Parinaud"]},
  {id:"ol_op7",prompt:"La réfraction objective est réalisée par :",choices:["L'acuité visuelle uniquement","L'auto-réfractomètre ou la skiascopie (sans coopération du patient)","Le test de Worth","L'examen du fond d'œil"],answer:1,diff:1,explication:"Réfraction objective : auto-réfractomètre (mesure automatique du défaut réfractif) ou skiascopie (ombre de la pupille à l'éclairage mouvant). Permet d'objectiver l'amétropie sans subjectivité.",tags:["Optique physiologique","Réfraction objective","Skiascopie","Autoréfractomètre"]},
  {id:"ol_op8",prompt:"La réfraction subjective est basée sur :",choices:["L'examen de la cornée au topographe","Les préférences du patient pour les verres d'essai (choix du meilleur verre subjectivement)","La tonométrie","L'examen en lampe à fente"],answer:1,diff:1,explication:"Réfraction subjective : technique des verres d'essai (boîte de verres ou phoropter). Le patient choisit le verre qui lui donne la meilleure vision. Affine la réfraction objective.",tags:["Optique physiologique","Réfraction subjective","Phoropter","Verre d'essai"]},
  {id:"ol_op9",prompt:"L'ECL (Écart Cornée-Lunettes) influence la correction prescrite car :",choices:["La couleur du verre change","La distance entre le verre et la cornée modifie l'effet vergent effectif sur l'œil","L'indice de réfraction varie avec l'ECL","La monture change de poids"],answer:1,diff:2,explication:"ECL ≈ 12-13 mm. Pour fortes corrections : ECL réduit la vergence effective d'un verre convergent, l'augmente pour divergent. Formule de transposition de la vergence : Veff = V/(1 - e×V) où e = ECL en mètres.",tags:["Optique physiologique","ECL","Vergence effective","Correction"]},
  {id:"ol_op10",prompt:"La vision binoculaire normale nécessite :",choices:["Une seule bonne acuité visuelle","La fusion des images des deux yeux (horopter) et un bon alignement oculomoteur","Une pupille dilatée","Un seul œil fonctionnel"],answer:1,diff:2,explication:"Vision binoculaire : fusion cortex visuel des images rétiniennes des 2 yeux → vision stéréoscopique, perception du relief. Requiert alignment oculomoteur (orthophorie), acuité comparable des 2 yeux.",tags:["Optique physiologique","Vision binoculaire","Fusion","Stéréoscopie"]},
  {id:"ol_og13",prompt:"Le test de Worth (4 points lumineux) sert à évaluer :",choices:["L'acuité visuelle","La fusion binoculaire et la dominance oculaire","La pression intraoculaire","L'accommodation"],answer:1,diff:2,explication:"Test de Worth : 4 points (1 blanc, 2 verts, 1 rouge). Avec filtres colorés : patient voit 4 = fusion, 3 (rouges) = suppression OG, 2 (verts) = suppression OD, 5 = diplopie.",tags:["Optique physiologique","Vision binoculaire","Test de Worth","Fusion"]},
  {id:"ol_op12",prompt:"Les verres progressifs (ADD) corrigent :",choices:["La myopie seulement","La presbytie en associant une zone de loin, une zone de près et une progression intermédiaire","L'astigmatisme uniquement","La diplopie"],answer:1,diff:1,explication:"Verres progressifs : zone distance en haut, zone intermédiaire au milieu, zone proche en bas. L'ADD (addition) est la différence de vergence entre zone loin et zone proche. ADD augmente avec l'âge.",tags:["Optique physiologique","Verres progressifs","ADD","Presbytie"]},
];

export const QB_OL_REALI_TECH = [
  {id:"ol_rt1",prompt:"La mesure de l'écart pupillaire (EP) est nécessaire pour :",choices:["Choisir la couleur de la monture","Centrer les verres (le centre optique doit correspondre au centre de la pupille)","Déterminer la vergence","Choisir le traitement antireflet"],answer:1,diff:1,explication:"EP = distance entre les deux pupilles. Centrage des verres : le centre optique doit être devant la pupille pour éviter les effets prismatiques indésirables. Mesuré en vision de loin et de près.",tags:["Réalisation technique","Centrage","EP","Montage"]},
  {id:"ol_rt2",prompt:"La hauteur de montage est mesurée pour les verres progressifs :",choices:["N'est pas nécessaire pour les progressifs","Est la distance verticale entre le centre de la pupille et le bas du verre (pour positionner la zone de loin)","Correspond à l'EP","Concerne uniquement les bifocaux"],answer:1,diff:2,explication:"Hauteur de montage = distance verticale entre le centre pupillaire et le bas du verre. Permet de positionner correctement la zone de loin des progressifs (et l'ADD en zone basse).",tags:["Réalisation technique","Hauteur de montage","Progressifs","Mesures"]},
  {id:"ol_rt3",prompt:"Le frontal d'une monture est l'angle entre :",choices:["Les branches et le plan du verre","Le plan du verre et le plan frontal du visage (inclinaison vers le bas, typiquement 8-12°)","Les deux verres","Le nasale et le temporal"],answer:1,diff:2,explication:"Frontal (ou pantoscopique) : inclinaison vers le bas du verre par rapport au plan frontal du visage. Idéalement 8-12°. Modifie l'astigmatisme oblique induit et la position de l'axe.",tags:["Réalisation technique","Frontal","Angle pantoscopique","Monture"]},
  {id:"ol_rt4",prompt:"Le contrôle d'un verre monté se fait avec :",choices:["Un réfractomètre","Un frontofocusmètre (mesure vergence, axe, prisme, centrage)","Un autoréfractomètre","Un kératomètre"],answer:1,diff:1,explication:"Frontofocusmètre : mesure la vergence sphère et cylindre, l'axe de cylindre, le prisme (base et direction), la position du centre optique. Vérification avant livraison au client.",tags:["Réalisation technique","Frontofocusmètre","Contrôle","Verre monté"]},
  {id:"ol_rt5",prompt:"Le traitement antireflet fonctionne par :",choices:["Teinte absorbante","Interférences destructives (couches minces λ/4) qui annulent les reflets","Absorption UV","Polarisation"],answer:1,diff:2,explication:"AR : dépôt de couches minces (oxyde métal) d'épaisseur λ/4. Interférences destructives → annulation reflet (8% d'un verre non traité → < 0.5%). Améliore la transmission et le rendu esthétique.",tags:["Réalisation technique","Traitement antireflet","Optique des couches"]},
  {id:"ol_rt6",prompt:"Un verre photochromique (Transitions®) change de couleur sous :",choices:["La chaleur","Le rayonnement ultraviolet (UV)","La lumière visible uniquement","L'humidité"],answer:1,diff:1,explication:"Verre photochromique : molécules (spiropyrane, naphtoxazine) s'activent sous UV → assombrissement. Déactivation à l'obscurité. Moins efficace derrière un pare-brise (bloque UV).",tags:["Réalisation technique","Photochromique","Verres","UV"]},
  {id:"ol_rt7",prompt:"Pour un œil qui pique à gauche (correction + prisme), la base du prisme doit être :",choices:["Base temporale OD","Base nasale OG","Base interne (nasale) côté œil dévié = OG (base nasale)","Base supérieure"],answer:2,diff:3,explication:"Strabisme convergent OG = œil dévié en dedans. Prisme base externe (temporale) OG pour dévier l'image en dedans et compenser. Règle : base du prisme du côté de la déviation pour correction prismatique.",tags:["Réalisation technique","Prisme","Strabisme","Correction prismatique"]},
  {id:"ol_rt8",prompt:"La tolérance sur la vergence sphérique d'un verre monté (norme NF EN ISO 21987) est de :",choices:["± 0.01 δ","± 0.09 δ pour < 6 δ","± 0.50 δ","± 1.00 δ"],answer:1,diff:3,explication:"ISO 21987 : tolérance vergence sphérique ± 0.09 δ pour V < 6 δ, ± 0.12 δ pour 6-12 δ, ± 1.5% pour > 12 δ. Cylindre : ± 0.09 δ. Axe : ± 2° pour < 0.25 δ, ± 0.5° pour > 0.25 δ.",tags:["Réalisation technique","Normes","ISO 21987","Contrôle qualité"]},
];

export const QB_OL_GESTION = [
  {id:"ol_g1",prompt:"La marge commerciale d'un magasin d'optique est calculée par :",choices:["CA - Charges totales","CA - Coût d'achat des marchandises vendues","VA - Salaires","EBE - Amortissements"],answer:1,diff:1,explication:"Marge commerciale = CA (ventes montures, lentilles, verres...) - Coût d'achat des marchandises vendues. Exemple : ventes 100 000 € - achats revendus 40 000 € = marge 60 000 € (60%). Premier solde intermédiaire de gestion (SIG).",tags:["Gestion","SIG","Marge commerciale","Optique"]},
  {id:"ol_g2",prompt:"La Valeur Ajoutée (VA) représente :",choices:["Le chiffre d'affaires brut","La richesse créée par le magasin après déduction de toutes les consommations externes (loyer, fournisseurs, frais généraux)","Le résultat net","Le salaire des opticiens"],answer:1,diff:1,explication:"VA = Marge commerciale + Production propre - Consommations externes (loyer, électricité, publicité, frais généraux). Mesure la richesse créée par l'entreprise. Base de calcul des cotisations patronales.",tags:["Gestion","SIG","Valeur Ajoutée","Optique"]},
  {id:"ol_g3",prompt:"L'EBE (Excédent Brut d'Exploitation) est calculé par :",choices:["VA + Salaires","VA - Salaires et charges sociales","CA - Coût d'achat","REX + Amortissements"],answer:1,diff:2,explication:"EBE = VA - Salaires (nets) - Charges sociales (patronales + salariales). Représente ce qui reste après avoir rémunéré le travail. Indicateur de performance opérationnelle avant prise en compte des investissements.",tags:["Gestion","SIG","EBE","Charges salariales"]},
  {id:"ol_g4",prompt:"Le Résultat d'Exploitation (REX) intègre par rapport à l'EBE :",choices:["Les charges financières","Les dotations aux amortissements (usure du matériel, mobilier de magasin)","Les impôts sur les sociétés","Le remboursement des emprunts"],answer:1,diff:2,explication:"REX = EBE - Dotations aux amortissements (et provisions). Amortissements = répartition du coût d'un équipement sur sa durée d'utilisation (ex : frontofocusmètre 5 ans → amortissement annuel = coût/5). REX = résultat du 'vrai métier' d'opticien.",tags:["Gestion","SIG","REX","Amortissements"]},
  {id:"ol_g5",prompt:"La CAF (Capacité d'AutoFinancement) est calculée par :",choices:["CA - Charges","Résultat Net + Dotations aux amortissements","EBE + Résultat financier","VA × Taux de marge"],answer:1,diff:2,explication:"CAF = Résultat Net + Amortissements. Les amortissements sont ajoutés car ils représentent une charge comptable sans sortie de trésorerie réelle. La CAF mesure la trésorerie potentiellement disponible pour investir ou rembourser.",tags:["Gestion","CAF","Autofinancement","Trésorerie"]},
  {id:"ol_g6",prompt:"Le seuil de rentabilité (ou point mort) est le niveau de CA pour lequel :",choices:["Le résultat net est maximum","Les charges fixes sont égales à la marge sur coût variable (résultat = 0)","La VA est maximale","Les charges variables dépassent les charges fixes"],answer:1,diff:2,explication:"Seuil de rentabilité = Charges fixes / Taux de marge sur coût variable. En dessous = perte. Au-dessus = bénéfice. Indicateur critique pour un opticien (loyer, salaires = charges fixes importantes).",tags:["Gestion","Seuil de rentabilité","Point mort","Charges fixes"]},
  {id:"ol_g7",prompt:"Pour un opticien créateur, la forme juridique SARL (ou EURL) offre l'avantage de :",choices:["Aucune formalité administrative","Responsabilité limitée aux apports (protection du patrimoine personnel)","Une rémunération assimilée salarié","L'absence totale d'impôts"],answer:1,diff:1,explication:"SARL/EURL : la responsabilité de l'associé est limitée à ses apports dans le capital. Contrairement à l'EI, les biens personnels sont protégés en cas de dettes professionnelles. Forme très répandue pour les magasins d'optique.",tags:["Gestion","Statuts juridiques","SARL","EURL","Responsabilité"]},
  {id:"ol_g8",prompt:"Dans une SAS (Société par Actions Simplifiée), le dirigeant (Président) est :",choices:["Travailleur Non Salarié (TNS) comme dans la SARL","Assimilé salarié (cotise au régime général, protection sociale similaire à un salarié)","Non soumis à cotisations sociales","Uniquement actionnaire sans rémunération"],answer:1,diff:2,explication:"SAS/SASU : le Président est assimilé salarié → régime général de la Sécurité sociale. Cotisations plus élevées que TNS (SARL gérant majoritaire) mais meilleure protection. Grande flexibilité statutaire (intéressant pour investisseurs).",tags:["Gestion","SAS","Statuts juridiques","Assimilé salarié"]},
  {id:"ol_g9",prompt:"Le chiffre d'affaires d'un magasin d'optique comprend :",choices:["Uniquement la vente de montures","Vente de montures + verres correcteurs + lentilles de contact + accessoires + prestations (examens de vue facturés)","Uniquement le tiers payant","Les remboursements de la Sécurité sociale uniquement"],answer:1,diff:1,explication:"CA opticien = ensemble des ventes (équipements de santé, verres, montures, lentilles, contactologie, solaires, accessoires) + prestations (examen de vue, adaptation lentilles). TVA à 20% sur produits non médicaux, 5.5% sur certains dispositifs médicaux.",tags:["Gestion","Chiffre d'affaires","Magasin d'optique","CA"]},
  {id:"ol_g10",prompt:"Le remboursement 100% Santé (réforme RAC0 2020) en optique concerne :",choices:["Tous les équipements sans condition","Uniquement les montures à moins de 30€","Une gamme de verres et montures standardisés (panier A/classe 1) sans reste à charge pour les assurés complémentaire","Uniquement les lunettes pour enfants"],answer:2,diff:2,explication:"Réforme 100% Santé (panier A/classe 1) : opticiens proposent obligatoirement des équipements sans reste à charge pour les bénéficiaires d'une complémentaire santé. Panier A = verre unifocaux + montures ≤ 30€. Panier B = libre.",tags:["Gestion","100% Santé","RAC0","Remboursement","Complémentaire"]},
  {id:"ol_g11",prompt:"La marge sur coût variable (MCV) est définie par :",choices:["CA × 0.20","CA - Charges variables (achats marchandises revendues + commissions)","CA - Charges fixes","Résultat net + Amortissements"],answer:1,diff:2,explication:"MCV = CA - Charges variables. Charges variables : varient proportionnellement au CA (achats marchandises, commissions, emballages). Taux MCV = MCV/CA. Utile pour calculer le seuil de rentabilité = CF / Taux MCV.",tags:["Gestion","Marge sur coût variable","Seuil de rentabilité","Charges variables"]},
  {id:"ol_g12",prompt:"La LPPR (Liste des Produits et Prestations Remboursables) en optique détermine :",choices:["Le prix de vente des montures","Les bases de remboursement de la Sécurité sociale pour les équipements optiques","Les normes de fabrication des verres","Les critères d'accréditation des opticiens"],answer:1,diff:2,explication:"LPPR (ou LPP) : liste officielle fixant les tarifs de remboursement SS pour les dispositifs médicaux, dont les lunettes. Base SS optique : 2.84€ pour verre unifocal (très faible). D'où l'importance des complémentaires santé et contrats responsables.",tags:["Gestion","LPPR","Remboursement","Sécurité sociale","Optique"]},
];

export const QB_OL_MARQUES = [
  {id:"ol_mq1",prompt:"Quel organisme français gère l'enregistrement des marques déposées ?",choices:["L'AFNOR","L'INPI (Institut National de la Propriété Industrielle)","L'EUIPO","La DGCCRF"],answer:1,diff:1,explication:"L'INPI est l'organisme compétent pour l'enregistrement des marques en France. Le dépôt coûte environ 250 € par classe de produits/services et confère une protection de 10 ans renouvelable indéfiniment.",tags:["Marques","INPI","Propriété industrielle"]},
  {id:"ol_mq2",prompt:"Quelle est la durée de protection d'une marque déposée à l'INPI ?",choices:["5 ans non renouvelable","10 ans renouvelables indéfiniment","20 ans comme un brevet","Illimitée sans formalité"],answer:1,diff:1,explication:"Une marque nationale déposée à l'INPI est protégée pour 10 ans à compter de la date de dépôt. Elle peut être renouvelée indéfiniment par tranches de 10 ans, à condition de payer les taxes de renouvellement.",tags:["Marques","INPI","Durée de protection"]},
  {id:"ol_mq3",prompt:"Une marque valide doit réunir trois conditions : distinctivité, licéité et :",choices:["Notoriété","Disponibilité (ne pas être déjà déposée ou utilisée par un tiers)","Ancienneté","Originalité artistique"],answer:1,diff:2,explication:"Les trois conditions cumulatives de validité d'une marque sont : (1) distinctivité — permettre d'identifier l'origine des produits, (2) licéité — ne pas être contraire à l'ordre public ou trompeuse, (3) disponibilité — ne pas être déjà appropriée par un tiers.",tags:["Marques","Conditions de validité","Distinctivité"]},
  {id:"ol_mq4",prompt:"L'EUIPO est l'organisme compétent pour déposer :",choices:["Une marque nationale française","Une marque communautaire (valable dans toute l'UE)","Une marque internationale via le protocole de Madrid","Un brevet européen"],answer:1,diff:2,explication:"L'EUIPO (European Union Intellectual Property Office, basé à Alicante) gère les marques de l'Union européenne (ex-marque communautaire), valables dans les 27 États membres de l'UE avec un seul dépôt. La marque internationale relève de l'OMPI/système de Madrid.",tags:["Marques","EUIPO","Marque communautaire"]},
  {id:"ol_mq5",prompt:"Pour les lunettes, le règlement UE 952/2013 (Code des douanes de l'Union) permet d'apposer 'Made in France' si :",choices:["La conception est française","La dernière transformation substantielle a eu lieu en France","Le siège social est en France","Les matières premières sont françaises"],answer:1,diff:2,explication:"Le règlement UE 952/2013 établit la règle de la 'dernière transformation substantielle' pour déterminer l'origine non préférentielle d'un produit. Pour les montures, cela implique notamment une fabrication (usinage, assemblage) en France avec au moins 45 % de valeur ajoutée locale.",tags:["Made in France","Origine","Règlement UE 952/2013"]},
  {id:"ol_mq6",prompt:"Le label 'Origine France Garantie' (OFG) est :",choices:["Un label officiel d'État géré par le ministère de l'Économie","Un label privé géré par l'association Pro France, avec audit indépendant","Une obligation légale pour les exportateurs","Synonyme du marquage CE"],answer:1,diff:2,explication:"'Origine France Garantie' (OFG) est un label privé créé par l'association Pro France. Il certifie qu'un produit est fabriqué en France selon des critères stricts : l'outil de production est situé en France et au moins 50 % du prix de revient unitaire est d'origine française. Il fait l'objet d'un audit par un organisme indépendant.",tags:["Made in France","OFG","Origine France Garantie","Label"]},
  {id:"ol_mq7",prompt:"Le marquage CE sur des verres correcteurs signifie que :",choices:["Le produit est fabriqué en Europe","Le produit est conforme aux exigences essentielles de sécurité européennes applicables aux dispositifs médicaux","Le produit est de haute qualité certifiée","Le produit est remboursé par la Sécurité sociale"],answer:1,diff:1,explication:"Le marquage CE est une déclaration du fabricant attestant que le produit est conforme aux exigences essentielles des directives/règlements européens applicables. Pour les verres correcteurs (dispositifs médicaux de classe IIa), il s'agit du Règlement UE 2017/745. Ce n'est pas un label qualité.",tags:["Marquage CE","Dispositifs médicaux","Conformité"]},
  {id:"ol_mq8",prompt:"Le label 'EPV' (Entreprise du Patrimoine Vivant) distingue :",choices:["Les entreprises ayant le plus de salariés en France","Les entreprises possédant un savoir-faire artisanal ou industriel rare et d'excellence","Les entreprises exportant plus de 50 % de leur production","Les entreprises certifiées ISO 9001"],answer:1,diff:2,explication:"Le label EPV (Entreprise du Patrimoine Vivant) est un label d'État français décerné par le ministère chargé de l'industrie. Il récompense des entreprises françaises aux savoir-faire artisanaux et industriels d'excellence, souvent transmis de génération en génération. Morel (Oyonnax) est une entreprise optique labellisée EPV.",tags:["EPV","Label d'État","Savoir-faire","Artisanat"]},
  {id:"ol_mq9",prompt:"Luxottica, Safilo et Kering Eyewear sont des acteurs qui :",choices:["Fabriquent et vendent leurs propres marques exclusivement","Détiennent des licences pour fabriquer des lunettes sous des marques de luxe (Chanel, Gucci, Cartier...)","Gèrent uniquement la distribution optique en France","Sont des organismes de certification des verres ophtalmiques"],answer:1,diff:2,explication:"Ces groupes sont des fabricants-distributeurs qui détiennent des contrats de licence avec de grandes maisons de luxe et de mode (Chanel, Gucci, Prada, Cartier...). Ils fabriquent et commercialisent les collections eyewear sous ces marques en échange de royalties. Luxottica (groupe EssilorLuxottica) est le leader mondial.",tags:["Marques de luxe","Licences","Luxottica","Safilo","Kering Eyewear"]},
  {id:"ol_mq10",prompt:"Morel Eyewear, fabricant de montures basé à Oyonnax, est connu pour :",choices:["Être une filiale de Luxottica","Être une entreprise française indépendante, labellisée EPV, spécialisée dans la fabrication de montures haut de gamme","Fabriquer uniquement des verres organiques","Être le seul fabricant autorisé à utiliser 'Made in France'"],answer:1,diff:2,explication:"Morel est un fabricant français indépendant basé à Oyonnax (Ain), berceau historique de l'industrie de la plasturgie et de la lunetterie française. L'entreprise est labellisée EPV et incarne le savoir-faire français dans la fabrication de montures premium.",tags:["Morel","Oyonnax","Made in France","Fabricant français"]},
  {id:"ol_mq11",prompt:"En cas de contrefaçon d'une marque d'optique, la juridiction compétente est :",choices:["Le Conseil des prud'hommes","Le Tribunal de commerce","Le Tribunal judiciaire","La Cour d'appel administrative"],answer:2,diff:3,explication:"Les litiges en matière de contrefaçon de marques relèvent du Tribunal judiciaire (TJ). Le titulaire de la marque peut engager une action civile (dommages-intérêts) et/ou une action pénale. La procédure de saisie-contrefaçon permet de constituer des preuves avant tout procès.",tags:["Contrefaçon","Tribunal judiciaire","Action en justice","Marques"]},
  {id:"ol_mq12",prompt:"La norme ISO 9001 dans le secteur optique certifie :",choices:["La qualité optique des verres (indice, traitement)","Le système de management de la qualité de l'entreprise (processus, amélioration continue)","L'origine française des produits","La conformité au marquage CE"],answer:1,diff:2,explication:"ISO 9001 est une norme internationale de management de la qualité. Elle certifie que l'entreprise a mis en place un système organisationnel garantissant la satisfaction client et l'amélioration continue des processus. Elle ne certifie pas le produit lui-même mais l'organisation qui le produit.",tags:["ISO 9001","Qualité","Certification","Management"]},
];

export const QB_OL_AV = [
  {id:"ol_av1",prompt:"La cataracte est définie comme :",choices:["Un trouble de la pression intra-oculaire","Une opacification partielle ou totale du cristallin entraînant une baisse de la transmission lumineuse","Un décollement de la rétine","Une dégénérescence de la cornée"],answer:1,diff:1,explication:"La cataracte est l'opacification progressive du cristallin. La lumière ne traverse plus correctement ce milieu transparent → baisse d'acuité visuelle, halos, éblouissements. Le traitement est chirurgical (phacoémulsification + implant).",tags:["Cataracte","Cristallin","Pathologie oculaire"]},
  {id:"ol_av2",prompt:"La mesure de la pression intra-oculaire (PIO) par un ophtalmologiste sert au dépistage de :",choices:["La cataracte","Le glaucome (hypertension oculaire)","La dégénérescence maculaire liée à l'âge (DMLA)","La myopie forte"],answer:1,diff:2,explication:"La tonométrie mesure la PIO. Une PIO élevée (> 21 mmHg) est le principal facteur de risque du glaucome (neuropathie optique progressive). La cataracte est diagnostiquée à l'examen à la lampe à fente (biomicroscopie) et non par tonométrie.",tags:["Cataracte","Pression intra-oculaire","Glaucome","Dépistage"]},
  {id:"ol_av3",prompt:"Parmi les symptômes suivants, lequel N'EST PAS un signe typique de cataracte ?",choices:["Vision floue et brumeuse","Halos lumineux et éblouissements","Douleur oculaire intense et soudaine","Diplopie monoculaire ou changement de réfraction"],answer:2,diff:2,explication:"La douleur oculaire intense et soudaine est un signe d'urgence (glaucome aigu, kératite, uvéite) mais PAS de la cataracte, qui évolue lentement et sans douleur. Les signes typiques de cataracte : vision floue, halos, éblouissements, diplopie monoculaire, baisse de perception des contrastes, changement fréquent de lunettes.",tags:["Cataracte","Symptômes","Pathologie oculaire"]},
  {id:"ol_av4",prompt:"La sphère équivalente (Seq) d'une compensation -1.00 (-0.50) 90° est :",choices:["-1.00 δ","-1.25 δ","-0.75 δ","-1.50 δ"],answer:1,diff:1,explication:"Sphère équivalente : Seq = S + C/2 = -1.00 + (-0.50)/2 = -1.00 - 0.25 = -1.25 δ. La Seq permet de comparer les compensations entre elles et est utilisée notamment lors de l'autoréfractométrie et du calcul de l'anisométropie sphérique équivalente.",tags:["Sphère équivalente","Calcul","Autoréfractomètre","Formule"]},
  {id:"ol_av5",prompt:"Au cadran de Parent, le méridien perçu le plus NOIR (le plus contrasté) indique :",choices:["L'axe du cylindre négatif compensateur","L'axe de la focale arrière (et donc l'axe du cylindre positif)","La direction du méridien le plus réfractif","L'axe de la focale avant"],answer:1,diff:2,explication:"Au cadran de Parent (sujet légèrement myopisé) : le méridien vu le PLUS NET est celui passant par la focale arrière (car la focale arrière est la plus proche de la rétine). L'axe du cylindre NÉGATIF compensateur est perpendiculaire à ce méridien (soit 90° de plus ou 90° de moins).",tags:["Cadran de Parent","Astigmatisme","Axe","Réfraction subjective"]},
  {id:"ol_av6",prompt:"Lors d'un test du masquage unilatéral, un mouvement de l'œil est perçu au DÉMASQUAGE (non au masquage). Cela traduit :",choices:["Une hétérotropie (tropia) — déviation manifeste permanente","Une hétérophorie — déviation latente (masquée par la fusion binoculaire)","Une fixation excentrique","Une amblyopie profonde"],answer:1,diff:2,explication:"Au cover-uncover test : mouvement au MASQUAGE = l'œil était dévié en vision binoculaire → tropia (ésotropie, exotropie...). Mouvement au DÉMASQUAGE UNIQUEMENT = l'œil était aligné mais nécessitait un effort fusionnel → phorie (déviation latente). L'œil se déplace pour retrouver sa position de repos puis re-fusionne.",tags:["Cover test","Masquage","Hétérophorie","Hétérotropie","Vision binoculaire"]},
  {id:"ol_av7",prompt:"Le cylindre de Maddox (250 Δ) utilisé pour mesurer les phories présente l'inconvénient principal de :",choices:["Mesurer uniquement les phories verticales","Provoquer une dissociation très forte, peu représentative de la vision binoculaire habituelle","Ne pas permettre la mesure en vision de près","Être trop coûteux pour un cabinet optique"],answer:1,diff:2,explication:"Le cylindre de Maddox dissociait très fortement la vision (le verre transforme le point lumineux en barre rouge visible par un seul œil). Cette forte dissociation peut faire apparaître des phories plus importantes que celles qui existent en condition binoculaire normale. Comparé à la méthode de von Graefe (dissociation par prisme), le Maddox sur-estime parfois les phories.",tags:["Test de Maddox","Phorie","Dissociation","Vision binoculaire"]},
  {id:"ol_av8",prompt:"L'aniséiconie liée à l'anisométropie est considérablement RÉDUITE lors de l'adaptation en lentilles de contact car :",choices:["Les lentilles ont un indice plus élevé que les verres","La distance lentille-œil (distance verre-sommet cornée) est quasi nulle, réduisant l'effet grossissant différentiel","Les lentilles corrigent l'astigmatisme plus précisément","Les lentilles de contact n'induisent pas de prismes"],answer:1,diff:2,explication:"L'aniséiconie en lunettes provient de la différence de grossissement entre OD et OG : M ≈ 1 + d×P/1000 où d = distance verre-nœud (≈ 27 mm). En lentilles de contact, d ≈ 0 mm → M ≈ 1 pour les deux yeux → aniséiconie quasi nulle. C'est un avantage majeur des LC pour les fortes anisométropies.",tags:["Aniséiconie","Lentilles de contact","Anisométropie","Grossissement"]},
  {id:"ol_av9",prompt:"Le prisme de Prentice permet de calculer l'effet prismatique d'une lentille à distance de son centre optique. Pour un verre de -4.75 δ, avec la ligne de regard passant 1 cm au-dessus du centre optique, l'effet prisme est :",choices:["1.90 Δ base inférieure","4.75 Δ base supérieure","4.75 Δ base inférieure","0.475 Δ base inférieure"],answer:2,diff:3,explication:"Formule de Prentice : P = D × d (d en cm). P = 4.75 × 1 = 4.75 Δ. Pour un verre DIVERGENT (-4.75), le rayon s'éloigne de l'axe optique → l'effet prismatique a sa base côté centre optique, donc base INFÉRIEURE quand le regard est au-dessus du CO. C'est cet effet qui explique les problèmes de vision double avec une forte correction en regard vers le haut.",tags:["Prisme de Prentice","Effet prismatique","Calcul","Anisométropie"]},
  {id:"ol_av10",prompt:"Le BUT (Break Up Time) évalue le film lacrymal. La valeur considérée comme NORMALE est :",choices:["< 5 secondes","≥ 10 secondes","Entre 5 et 7 secondes","Exactement 20 secondes"],answer:1,diff:1,explication:"Le BUT mesure le temps (en secondes) avant l'apparition de la première tache sèche sur le film lacrymal après un clignement complet. BUT ≥ 10 s = normal. BUT < 10 s = instabilité du film lacrymal = facteur de risque pour l'adaptation en lentilles de contact (sécheresse, inconfort, dépôts). Dans l'annale 2024, BUT = 12 s → adapté aux lentilles.",tags:["BUT","Film lacrymal","Examen pré-adaptation","Lentilles de contact"]},
  {id:"ol_av11",prompt:"La valeur Dk/e d'une lentille de contact exprime :",choices:["La résistance mécanique de la lentille à la déformation","La transmissibilité à l'oxygène de la lentille (capacité à laisser passer l'O₂ vers la cornée)","La durée de vie recommandée de la lentille","L'hydrophilie du matériau"],answer:1,diff:1,explication:"Dk/e (aussi noté Dk/t) est la transmissibilité à l'oxygène : D = coefficient de diffusion, k = coefficient de solubilité, e = épaisseur. Les lentilles silicone hydrogel ont Dk/e > 100 Fatt units (ex: Pure Vision, Air Optix). Les hydrogels classiques ont Dk/e < 24. Une forte Dk/e est indispensable pour le port prolongé / permanent.",tags:["Dk/e","Transmissibilité O2","Lentilles de contact","Silicone hydrogel"]},
  {id:"ol_av12",prompt:"Pour un client plombier exposé à des projections métalliques, le type de port de lentilles le plus approprié est :",choices:["Port permanent (dormir avec les lentilles)","Port journalier avec retrait obligatoire chaque soir, associé à des lunettes de protection","Port hebdomadaire","Port bimensuel sans restriction"],answer:1,diff:1,explication:"Le port journalier (daily wear) avec retrait chaque soir est conseillé pour la plupart des clients, surtout en contexte professionnel à risque. Les lunettes de protection complémentaires sont indispensables lors des activités à risque de projection. Le port permanent (extended wear) est réservé à des indications médicales spécifiques avec lentilles silicone hydrogel à très haute Dk/e.",tags:["Type de port","Lentilles de contact","Port journalier","Sécurité professionnelle"]},
];

// ─── BANQUE PROGRESSIFS ───
export const QB_OL_PROGRESSIFS = [
  {id:"ol_pr1",prompt:"Comment varie la vergence dans un verre progressif ?",choices:["Elle est identique sur toute la surface du verre","Elle augmente de façon continue du bas (loin) vers le haut (près)","Elle varie de façon continue du haut (zone loin) vers le bas (zone près), sans rupture visible","Elle varie brusquement entre la zone loin et la zone près"],answer:2,diff:1,explication:"Le verre progressif présente une variation continue et progressive de vergence : la zone de vision de loin se situe en haut, la zone de vision de près en bas. Il n'y a pas de rupture visible (contrairement au bifocal), ce qui réduit la stigmatisation. C'est cette progression graduelle qui permet la vision à toutes les distances.",tags:["Progressif","Vergence","Zone loin","Zone près","Presbytie"]},
  {id:"ol_pr2",prompt:"Quelles sont les trois zones principales d'un verre progressif ?",choices:["Zone droite, zone gauche, zone centrale","Zone loin (haut), corridor progressif (centre), zone près (bas)","Zone UV, zone visible, zone infrarouge","Zone de confort, zone de travail, zone de repos"],answer:1,diff:1,explication:"Un verre progressif est structuré en trois zones : la zone de vision de loin en haut (vergence faible/prescrite), le corridor progressif en centre (vergence intermédiaire croissante) et la zone de vision de près en bas (vergence maximale = loin + ADD). Les aberrations latérales augmentent en s'éloignant du corridor central.",tags:["Progressif","Zones","Corridor","ADD"]},
  {id:"ol_pr3",prompt:"Qu'est-ce que l'ADD (addition) d'un verre progressif ?",choices:["Le type de traitement antireflet du verre","La différence de vergence entre la zone de vision de loin et la zone de vision de près","La hauteur de montage du verre progressif","Le rayon de courbure de la face avant du verre"],answer:1,diff:1,explication:"L'ADD (addition) représente la différence de vergence entre la zone loin et la zone près : ADD = V(près) - V(loin). Elle augmente avec l'âge du presbyte : de +0.75 δ en début de presbytie (vers 45 ans) jusqu'à +3.50 δ en presbytie totale. Elle est toujours positive et inscrite sur l'ordonnance.",tags:["ADD","Addition","Presbytie","Vergence","Progressif"]},
  {id:"ol_pr4",prompt:"Selon le décret de 2021 (Loi Porteur), pour un adulte de 30 ans, à quelle condition un opticien peut-il renouveler une prescription de lunettes ?",choices:["La prescription doit dater de moins de 5 ans et la variation sphère doit être < 1.00 δ","La prescription doit dater de moins de 3 ans et l'écart sphère doit être < 0.75 δ sur les deux yeux","La prescription doit dater de moins de 2 ans, sans condition de variation","La prescription doit dater de moins de 5 ans sans condition de variation"],answer:1,diff:2,explication:"Le décret 2021 (Loi Porteur) pour les adultes de 16 à 42 ans : renouvellement possible si la prescription date de moins de 3 ans ET si l'écart sphérique est inférieur à 0.75 δ sur chacun des deux yeux. Au-delà de ces seuils, une consultation ophtalmologique est obligatoire.",tags:["Loi Porteur","Renouvellement","Décret 2021","Prescription","Adulte"]},
  {id:"ol_pr5",prompt:"Parmi les mesures suivantes, laquelle est INDISPENSABLE et SPÉCIFIQUE à la réalisation d'un verre progressif ?",choices:["L'écart pupillaire monoculaire de loin","La hauteur de montage (centre pupillaire → bord inférieur du verre)","L'indice de réfraction du verre","La teinte du traitement antireflet"],answer:1,diff:2,explication:"La hauteur de montage (distance entre le centre de la pupille et le bord inférieur du verre) est spécifique et indispensable pour les verres progressifs. Sans cette mesure, le laboratoire ne peut pas positionner correctement les zones. L'EP de loin binoculaire est aussi nécessaire (et non juste OD+OG séparément pour les progressifs).",tags:["Hauteur de montage","Progressif","Mesures","Montage"]},
  {id:"ol_pr6",prompt:"Si la hauteur de montage d'un verre progressif est trop basse, quelle conséquence en résulte pour le porteur ?",choices:["La zone de vision de près disparaît — il est impossible de voir de près","La zone de vision de loin se retrouve dans le corridor progressif — vision de loin perturbée","La pupille se situe dans la zone de transition : l'ADD est alors correcte","Il n'y a aucune conséquence, le cerveau s'adapte automatiquement"],answer:1,diff:2,explication:"Si la hauteur de montage est trop basse, la pupille est positionnée trop bas sur le verre : le regard de loin passe par le corridor ou la zone de près. La vision de loin devient floue et inconfortable. Si la hauteur est trop haute, la pupille est dans la zone loin mais le bord inférieur ne laisse plus de place pour la zone de près.",tags:["Hauteur de montage","Progressif","Conséquences","Zone loin","Montage"]},
  {id:"ol_pr7",prompt:"Plus un verre progressif est de haute gamme, plus son corridor progressif est :",choices:["Étroit, concentrant les aberrations latérales sur les bords","Large, réduisant les zones d'aberrations latérales","Identique à un verre d'entrée de gamme (la technologie ne change pas)","Plus court verticalement"],answer:1,diff:2,explication:"Les verres progressifs de haute gamme bénéficient de technologies de calcul avancées (optimisation face libre, personnalisation) qui permettent d'élargir le corridor progressif et de réduire les zones d'aberrations latérales sur les côtés. Les verres courts (petite hauteur) ont inévitablement plus d'aberrations latérales que les verres de grande hauteur.",tags:["Progressif","Corridor","Gamme","Aberrations latérales","Qualité"]},
  {id:"ol_pr8",prompt:"L'angle pantoscopique d'une monture est idéalement compris entre :",choices:["0° et 2°","8° et 12°","15° et 20°","25° et 30°"],answer:1,diff:2,explication:"L'angle pantoscopique correspond à l'inclinaison verticale des verres par rapport au plan frontal du visage. La valeur idéale est de 8 à 12°. Il influence directement la position des zones optiques du progressif sur la cornée. Trop faible ou trop grand, il déplace les zones loin et près, perturbant la vision. Il se mesure avec une règle pantoscopique ou visuellement sur le patient portant la monture.",tags:["Angle pantoscopique","Mesures","Progressif","Monture"]},
  {id:"ol_pr9",prompt:"Un patient presbyte adapté en verres progressifs se plaint de devoir 'balancer la tête' pour lire au lieu de bouger les yeux. Quelle est l'explication principale ?",choices:["L'addition est trop faible","Le patient présente des aberrations latérales importantes qui perturbent la vision en regard excentré — il compense en tournant la tête pour rester dans le corridor","La monture est trop légère","La hauteur de montage est trop haute"],answer:1,diff:2,explication:"Les aberrations latérales sont présentes sur les côtés du verre progressif, en dehors du corridor central. Le patient apprend à tourner la tête pour pointer son regard dans le corridor étroit (plutôt que de déplacer latéralement les yeux). C'est un phénomène d'adaptation normal, plus marqué avec les verres d'entrée de gamme à corridor étroit.",tags:["Progressif","Adaptation","Aberrations latérales","Corridor","Presbyte"]},
  {id:"ol_pr10",prompt:"Pour la réalisation d'un équipement progressif, quelle est la hauteur de monture minimale recommandée ?",choices:["18 à 20 mm","28 à 30 mm","35 à 40 mm","Moins de 20 mm"],answer:1,diff:2,explication:"Les verres progressifs nécessitent une hauteur de monture d'au moins 28 à 30 mm pour que les trois zones (loin, corridor, près) soient toutes présentes et utilisables. Les montures trop petites (< 25 mm) ne permettent pas d'intégrer un verre progressif fonctionnel — une solution de verre de bureau ou bifocal peut alors être proposée.",tags:["Progressif","Monture","Hauteur","Adaptation","Montage"]},
  {id:"ol_pr11",prompt:"Pour vérifier l'ADD réellement réalisée sur un verre progressif avec un frontofocusmètre, quelle procédure faut-il suivre ?",choices:["Mesurer uniquement la zone de loin, l'ADD est toujours gravée sur le verre","Mesurer la vergence en zone de loin puis en zone de près ; la différence = ADD réalisée. Vérifier les tolérances ISO 21987","Mesurer le diamètre du verre pour calculer l'ADD","Utiliser une lampe de Wood pour révéler les gravures permanentes"],answer:1,diff:2,explication:"Pour contrôler l'ADD d'un progressif au frontofocusmètre : 1) Positionner le verre en zone de loin et noter la vergence. 2) Déplacer le verre vers le bas jusqu'en zone de près et noter la nouvelle vergence. 3) ADD = V(près) - V(loin). La tolérance ISO 21987 s'applique à la valeur prescrite. Les gravures permanentes (croix nasale, croix temporale) aident à identifier les zones.",tags:["Frontofocusmètre","ADD","Contrôle","ISO 21987","Progressif"]},
  {id:"ol_pr12",prompt:"Quelle est la principale différence entre un verre progressif et un verre de bureau (occupationnel) ?",choices:["Le verre de bureau est plus fin et plus léger","Le verre de bureau distribue une ADD plus grande sur toute la hauteur du verre pour optimiser vision intermédiaire et près, sans zone de loin efficace (ou à distance réduite)","Le verre de bureau est un bifocal avec segment visible","Le verre de bureau corrige l'astigmatisme contrairement au progressif"],answer:1,diff:2,explication:"Les verres occupationnels (de bureau) sont conçus pour les distances de travail (40 cm à 1-2 m). Ils répartissent une grande plage de vision intermédiaire et de près sur toute la hauteur du verre. La zone de loin est soit absente, soit réduite à 2-3 mètres maximum. Ils sont idéaux pour le travail sur écran mais inutilisables pour la conduite.",tags:["Verre de bureau","Occupationnel","Progressif","ADD","Vision intermédiaire"]},
];

// ─── BANQUE RÉFRACTION SUBJECTIVE ───
export const QB_OL_REFRACTION = [
  {id:"ol_rf1",prompt:"Le brouillard (fogging) en réfraction subjective consiste à :",choices:["Mettre des verres négatifs pour simuler la myopie","Ajouter des sphères positives pour myopiser l'œil et forcer le relâchement de l'accommodation avant la mesure","Mesurer l'acuité visuelle dans un environnement sombre","Utiliser un filtre coloré sur l'écran de projection"],answer:1,diff:1,explication:"Le brouillard consiste à ajouter des verres sphériques positifs (+) en excès pour 'myopiser' artificiellement l'œil. L'accommodation se relâche car elle ne peut pas compenser la surcorrection (+). Un minimum de +0.75 δ est nécessaire pour assurer un relâchement complet. La réfraction commence ensuite avec l'œil au repos accommodatif.",tags:["Brouillard","Fogging","Réfraction","Accommodation","Subjective"]},
  {id:"ol_rf2",prompt:"La loi du maximum convexe en réfraction subjective stipule que :",choices:["On doit toujours prescrire le verre le plus négatif possible","On doit prescrire la sphère la plus positive (la plus convergente) qui maintient l'acuité visuelle maximale","On doit prescrire la sphère la plus négative possible pour améliorer l'acuité","On doit prescrire le cylindre le plus fort possible"],answer:1,diff:2,explication:"La loi du maximum convexe (ou des sphères maximum convexes) stipule qu'on doit prescrire la sphère la plus positive (+) qui maintient l'acuité visuelle maximale. Ce principe évite de sur-corriger en négatif, ce qui forcerait l'accommodation du patient. Il est particulièrement important chez les hypermétropes et les presbytes.",tags:["Maximum convexe","Sphère","Réfraction","Accommodation","Prescription"]},
  {id:"ol_rf3",prompt:"Lors du test bichromique (duochrome), un patient voit MIEUX les lettres sur fond ROUGE que sur fond VERT. Cela indique :",choices:["Une correction cylindrique insuffisante","Une myopie résiduelle ou une surcorrection en sphère positive","Une hypermétropie résiduelle ou une sous-correction en sphère positive","Une dominance oculaire droite"],answer:1,diff:2,explication:"Le test bichromique exploite l'aberration chromatique : les longueurs d'onde rouges (plus longues) focalisent légèrement en arrière des vertes. Si rouge est meilleur : la correction est trop positive ou myopie résiduelle (foyer trop en arrière de la rétine). Si vert est meilleur : sous-correction positive ou hypermétropie résiduelle. Si identiques : équilibre parfait.",tags:["Bichromique","Duochrome","Réfraction","Aberration chromatique","Myopie","Hypermétropie"]},
  {id:"ol_rf4",prompt:"L'équilibre binoculaire en réfraction subjective vise à :",choices:["Corriger uniquement l'œil dominant","Éviter de créer une dominance oculaire iatrogène en équilibrant progressivement les deux yeux après la correction monoculaire","Mesurer la phorie avant la prescription","Tester la vision des couleurs de chaque œil séparément"],answer:1,diff:2,explication:"Après la réfraction monoculaire de chaque œil, l'équilibre binoculaire consiste à introduire un brouillard binoculaire puis à retirer progressivement les verres des deux yeux ensemble pour éviter de favoriser un œil sur l'autre. Sans équilibre binoculaire, on risque de créer une dominance iatrogène (une correction monoculaire peut stimuler l'accommodation de l'autre œil).",tags:["Équilibre binoculaire","Réfraction","Brouillard","Dominance oculaire","Binoculaire"]},
  {id:"ol_rf5",prompt:"Au test de Worth (lampe de Worth), un patient voit 5 points lumineux (1 rouge + 3 verts + 1 rouge). Cela indique :",choices:["Une fusion normale","Une suppression de l'œil gauche (OG)","Une diplopie — les deux yeux ne fusionnent pas","Une bonne stéréoscopie"],answer:2,diff:2,explication:"La lampe de Worth présente 4 points : 1 rouge (haut), 2 verts (côtés), 1 blanc (bas) visible rouge par OD et vert par OG. Résultats : 4 points = fusion normale ; 2 rouges = suppression OG ; 3 verts = suppression OD ; 5 points (2 rouges + 3 verts) = diplopie (les deux yeux voient mais ne fusionnent pas). La vision de 5 points indique une absence de fusion binoculaire.",tags:["Test de Worth","Diplopie","Fusion","Suppression","Binoculaire"]},
  {id:"ol_rf6",prompt:"Le test de Maddox mesure les phories. Quelle valeur de phorie est considérée comme PHYSIOLOGIQUE (normale) en vision de près ?",choices:["Ésophorie de 5 à 8 Δ","Exophorie légère de 2 à 3 Δ","Hyperphorie de 2 Δ","Orthophorie stricte (0 Δ)"],answer:1,diff:2,explication:"Une légère exophorie de 2 à 3 Δ est physiologique en vision de près (la convergence nécessaire pour la vision de près crée une légère tendance à diverger au repos). L'ésophorie est moins fréquente et peut être liée à une hypermétropie sous-corrigée. L'hyperphorie (déviation verticale) est toujours pathologique. L'orthophorie stricte est idéale mais rare.",tags:["Phorie","Maddox","Exophorie","Binoculaire","Physiologique"]},
  {id:"ol_rf7",prompt:"Que mesure le test des réserves de vergence ?",choices:["La précision de la réfraction sphérique","La capacité du système binoculaire à maintenir la fusion malgré un prisme ajouté progressivement (convergence ou divergence forcée)","L'amplitude d'accommodation résiduelle","La sensibilité aux contrastes"],answer:1,diff:2,explication:"Les réserves de vergence mesurent la capacité fusionnelle du patient. On ajoute progressivement un prisme jusqu'au point de bris (diplopie) puis au point de récupération (fusion retrouvée). Les réserves fusionnelles positives (BO = base extérieure, convergence forcée) et négatives (BI = base intérieure, divergence forcée) reflètent la santé du système binoculaire.",tags:["Réserves de vergence","Fusion","Binoculaire","Prisme","Vergence"]},
  {id:"ol_rf8",prompt:"L'étoile de Maddox sert à :",choices:["Mesurer la phorie horizontale uniquement","Déterminer l'axe et la valeur de l'astigmatisme résiduel — le rayon perçu le moins net indique le méridien à compenser","Mesurer l'acuité visuelle en vision de près","Évaluer l'équilibre binoculaire"],answer:1,diff:2,explication:"L'étoile de Maddox est une mire composée de lignes rayonnantes. En vision monoculaire légèrement myopisée, le méridien vu le MOINS NET correspond à la focale la plus éloignée → c'est l'axe du cylindre à compenser. Cette méthode est complémentaire du cadran de Parent pour affiner l'axe et la valeur du cylindre résiduel.",tags:["Étoile de Maddox","Astigmatisme","Axe","Cylindre","Réfraction"]},
  {id:"ol_rf9",prompt:"Un patient obtient 40 secondes d'arc au test TNO. Cela signifie :",choices:["Sa stéréoscopie est insuffisante pour la conduite automobile","Il présente une stéréoscopie normale et suffisante pour la plupart des activités, y compris la conduite","Il souffre d'amblyopie profonde","Sa fusion binoculaire est absente"],answer:1,diff:2,explication:"Le test TNO mesure la stéréoscopie (perception de la profondeur par disparité binoculaire). 40 secondes d'arc est une excellente stéréoscopie. Une stéréoscopie ≤ 200 secondes d'arc est considérée comme suffisante pour la conduite et les activités quotidiennes. Les valeurs > 800 secondes d'arc indiquent une stéréoscopie insuffisante, souvent liée à une amblyopie ou une suppression.",tags:["Stéréoscopie","TNO","Vision binoculaire","Conduite","Binoculaire"]},
  {id:"ol_rf10",prompt:"La sensibilité aux contrastes évalue :",choices:["Uniquement l'acuité visuelle de loin à fort contraste (échelle de Monoyer)","La qualité visuelle au-delà de l'AV — capacité à distinguer des objets de faible contraste spatial — diminuée dans la cataracte, DMLA, glaucome","La réfraction objective par analyse de la réflexion rétinienne","L'amplitude d'accommodation résiduelle"],answer:1,diff:2,explication:"La sensibilité aux contrastes complète l'examen de la vision : l'AV teste uniquement les hautes fréquences spatiales à fort contraste. La sensibilité aux contrastes (tests Pelli-Robson, Vistech) évalue les basses et moyennes fréquences. Elle diminue significativement dans la cataracte (avant même la chute d'AV), la DMLA, le glaucome, la névrite optique.",tags:["Sensibilité aux contrastes","Pelli-Robson","Cataracte","DMLA","Glaucome","Qualité visuelle"]},
  {id:"ol_rf11",prompt:"Selon la règle de Donders et la méthode de Sheard, quelle fraction de l'amplitude d'accommodation peut être utilisée confortablement de façon prolongée ?",choices:["La totalité (100 %)","La moitié (50 %)","Un tiers (1/3) maximum","Un quart (25 %)"],answer:2,diff:2,explication:"La méthode de Sheard stipule qu'on ne peut utiliser confortablement qu'un tiers (1/3) de l'amplitude d'accommodation en vision prolongée. Les 2/3 restants constituent la réserve accommodative. Exemple : amplitude de 9 δ → confort maximum à 3 δ d'accommodation → distance confortable ≈ 33 cm. Au-delà, une fatigue accommodative (asthénopie) apparaît.",tags:["Accommodation","Sheard","Donders","Amplitude","Confort","Presbytie"]},
  {id:"ol_rf12",prompt:"Lors de la prescription finale, quel principe doit toujours guider le choix de la correction cylindrique ?",choices:["Toujours prescrire le cylindre maximal mesuré pour une correction parfaite","Ne pas mettre plus de cylindre que nécessaire pour maintenir le confort du patient, et toujours comparer avec l'ancienne correction","Prescrire uniquement des cylindres ronds (0.25 δ près)","Prescrire systématiquement la sphère équivalente sans cylindre"],answer:1,diff:2,explication:"La prescription cylindrique doit respecter la règle du confort : ne pas prescrire plus de cylindre que ce qui est toléré par le patient (une trop grande variation d'axe ou de valeur peut créer une maladaptation). Comparer avec l'ancienne correction permet d'éviter les changements brusques. Respecter la loi du maximum convexe pour la sphère associée.",tags:["Cylindre","Prescription","Confort","Réfraction","Adaptation"]},
];

// ─── BANQUE RÉGLEMENTATION ───
export const QB_OL_REGLEMENT = [
  {id:"ol_rg1",prompt:"Selon le règlement UE 2017/745 (MDR), dans quelle classe de dispositifs médicaux se trouvent les verres ophtalmiques correcteurs ?",choices:["Classe I (risque minimal)","Classe IIa","Classe IIb","Classe III (risque élevé)"],answer:1,diff:2,explication:"Depuis 2021, le règlement UE 2017/745 (MDR) classe les verres ophtalmiques correcteurs en classe IIa. Cette classification implique : marquage CE obligatoire, documentation technique complète, identifiant unique de dispositif (IUD/UDI), déclaration de conformité, traçabilité sur l'ensemble de la chaîne de distribution.",tags:["MDR","Règlement UE","Dispositif médical","Classe IIa","Marquage CE"]},
  {id:"ol_rg2",prompt:"Le devis normalisé en optique (arrêté 2014 modifié 2022) est obligatoire :",choices:["Uniquement pour les équipements progressifs","Avant toute vente d'équipement optique avec prise en charge Sécurité Sociale. Il comporte 3 colonnes : dénomination, prix de vente, prise en charge","Uniquement si le client est bénéficiaire de la CMU-C","Uniquement pour les lentilles de contact"],answer:1,diff:1,explication:"Le devis normalisé est obligatoire avant toute vente d'équipement avec prise en charge SS. Il doit comporter : la dénomination précise du produit (verre, monture), le prix de vente, et la prise en charge (SS + complémentaire). Le client dispose de 14 jours pour accepter ou refuser.",tags:["Devis normalisé","Arrêté 2014","Réglementation","Prise en charge","SS"]},
  {id:"ol_rg3",prompt:"Dans le cadre du 100% Santé (décret 2018), le Panier A (classe 1) est défini comme :",choices:["Le panier premium sans limite de prix","Le panier sans reste à charge pour l'assuré — tarifs plafonnés (monture 30 € max adulte, verres selon âge/amétropie)","Le panier des verres de luxe avec remboursement partiel","Le panier réservé aux mineurs uniquement"],answer:1,diff:1,explication:"Le Panier A (classe 1) est le dispositif sans reste à charge : les prix sont plafonnés (monture max 30 € pour adulte, verres tarifés selon classe d'amétropie et d'âge). La SS + mutuelle couvrent 100% du prix plafonné. Le Panier B (classe 2) est à libre tarification mais le remboursement SS est très faible (LPPR, souvent < 3 €).",tags:["100% Santé","Panier A","Classe 1","Sans reste à charge","Monture"]},
  {id:"ol_rg4",prompt:"La LPPR (Liste des Produits et Prestations Remboursables) en optique correspond à :",choices:["La liste des marques de verres agréées par la Sécurité Sociale","Les tarifs de remboursement SS pour les verres ophtalmiques — indexés sur des codes LPP, très inférieurs aux prix du marché","La liste des prescripteurs autorisés à rédiger une ordonnance optique","Le catalogue des montures 100% Santé"],answer:1,diff:2,explication:"La LPPR fixe les tarifs de remboursement de la Sécurité Sociale pour les verres ophtalmiques. Ces tarifs sont indexés sur des codes LPP selon la puissance du verre. Ils sont très inférieurs aux prix réels du marché : par exemple, 0 € à 3.22 € selon le type pour les verres du Panier B. C'est la mutuelle qui complète la différence.",tags:["LPPR","Remboursement","SS","Codes LPP","Optique","100% Santé"]},
  {id:"ol_rg5",prompt:"Depuis la loi Santé 2016, l'opticien doit proposer le tiers payant obligatoirement à :",choices:["Tous les clients sans exception","Les bénéficiaires de la CMU-C, ACS/CSS, ALD et victimes d'accident de travail","Uniquement aux clients de plus de 60 ans","Uniquement pour les équipements Panier A"],answer:1,diff:1,explication:"Le tiers payant (SS + mutuelle) est obligatoire pour les bénéficiaires de : CMU-C (aujourd'hui CSS = Complémentaire Santé Solidaire), ACS, ALD (affection de longue durée) et victimes d'accident de travail. Pour les autres clients, le tiers payant partiel (SS uniquement) est possible et le tiers payant complet est facultatif mais de plus en plus pratiqué.",tags:["Tiers payant","CMU-C","CSS","ALD","Loi Santé","Réglementation"]},
  {id:"ol_rg6",prompt:"Pour un adulte de 35 ans, le renouvellement de prescription est possible selon le décret 2016 modifié si :",choices:["La Rx date de moins de 5 ans ET la variation est ≤ 0.50 δ en sphère ET cylindre","La Rx date de moins de 3 ans (décret Porteur 2021) ET l'écart sphère < 0.75 δ sur chaque œil","La Rx date de moins de 2 ans sans condition de variation","La Rx date de moins de 5 ans ET la variation est < 1.00 δ"],answer:1,diff:2,explication:"Pour les adultes entre 16 et 42 ans, le décret de renouvellement (modifié en 2021) autorise l'adaptation/renouvellement si la prescription date de moins de 3 ans ET si l'écart est inférieur à 0.75 δ sur la sphère de chacun des deux yeux. Pour les presbytes (> 42 ans), une adaptation de ±0.50 δ est possible. Pour les mineurs < 16 ans, l'ordonnance médicale reste obligatoire.",tags:["Renouvellement","Décret","Prescription","Adulte","Opticien","Porteur"]},
  {id:"ol_rg7",prompt:"La loi AGEC (ex-Egalim, REP) impose aux opticiens de :",choices:["Recycler tous les verres usagés sur place","Collecter l'éco-contribution pour les équipements relevant de la REP (Responsabilité Élargie du Producteur) — visible sur le devis","Ne vendre que des montures Made in France","Obtenir une certification environnementale annuelle"],answer:1,diff:2,explication:"La Responsabilité Élargie du Producteur (REP) s'applique aux équipements électriques et électroniques, ce qui inclut certaines montures (avec composants électroniques, LED, etc.). L'éco-contribution, visible sur le devis, finance les filières de recyclage. L'opticien collecte et reverse cette contribution à l'éco-organisme agréé (ex: Écologic, ESR).",tags:["REP","Éco-contribution","AGEC","Environnement","Devis","Réglementation"]},
  {id:"ol_rg8",prompt:"La garantie légale de conformité en optique couvre :",choices:["6 mois à compter de l'achat, uniquement pour les verres","2 ans à compter de la délivrance pour tout défaut de conformité de l'équipement délivré","10 ans pour les montures de luxe","1 an uniquement si le client a souscrit une garantie commerciale"],answer:1,diff:1,explication:"La garantie légale de conformité (Code de la consommation, art. L217-4) couvre tout défaut de conformité existant lors de la délivrance, pendant 2 ans. Elle est distincte de la garantie commerciale (facultative) et de la garantie des vices cachés. En vente à distance ou hors établissement, le droit de rétractation est de 14 jours.",tags:["Garantie légale","Conformité","2 ans","Réglementation","Consommateur","Optique"]},
  {id:"ol_rg9",prompt:"Le code de déontologie de l'opticien-lunetier (CSP L4362 et R4362) impose notamment :",choices:["De vendre uniquement les marques partenaires du groupement","L'obligation de conseil, le respect de la prescription, l'information sur les alternatives et l'interdiction de démarchage","De réaliser l'examen de vue avant toute délivrance de lunettes","De disposer d'un ophtalmologiste dans le magasin"],answer:1,diff:1,explication:"Le code de déontologie des opticiens-lunetiers (Code de la santé publique L4362 et R4362) impose : l'obligation de conseil (adapter la correction aux besoins), le respect de la prescription médicale, l'information sur les alternatives thérapeutiques, et l'interdiction du démarchage commercial. L'opticien exerce sous sa responsabilité professionnelle.",tags:["Déontologie","CSP","Opticien","Conseil","Prescription","Démarchage"]},
  {id:"ol_rg10",prompt:"Depuis la réforme du système de santé 2021, les opticiens peuvent renouveler ou adapter une correction sans ordonnance médicale préalable dans le cadre de :",choices:["L'accès direct aux ophtalmologistes uniquement","L'accès direct aux opticiens pour les adultes — dans les conditions légales (décret Porteur) et via les protocoles de coopération (CPTS)","La télémédecine uniquement","Le renouvellement par internet exclusivement"],answer:1,diff:2,explication:"La réforme 2021 a facilité l'accès direct aux opticiens pour le renouvellement et l'adaptation des corrections, sans nécessité de passer d'abord chez un ophtalmologiste, dans les conditions définies par le décret Porteur (limites d'âge, de variation). Les CPTS (Communautés Professionnelles Territoriales de Santé) et les protocoles de coopération encadrent cette pratique.",tags:["Accès direct","Réforme 2021","CPTS","Protocoles","Renouvellement","Opticien"]},
  {id:"ol_rg11",prompt:"La Complémentaire Santé Solidaire (CSS, anciennement CMU-C) oblige l'opticien à :",choices:["Refuser la prise en charge et orienter vers un centre optique social","Proposer obligatoirement un équipement du Panier A sans reste à charge au bénéficiaire","Appliquer une réduction de 50 % sur tous les produits","Ne vendre que des montures en Panier A"],answer:1,diff:1,explication:"Les bénéficiaires de la CSS (Complémentaire Santé Solidaire) ont droit à un équipement sans reste à charge. L'opticien est tenu de proposer au moins un équipement du Panier A (classe 1) dans les tarifs plafonnés. Le tiers payant est obligatoire pour ces bénéficiaires. Refuser de les servir ou ne proposer que le Panier B constituerait une violation des obligations légales.",tags:["CSS","CMU-C","Panier A","Sans reste à charge","Tiers payant","Réglementation"]},
  {id:"ol_rg12",prompt:"Les actes réservés aux opticiens-lunetiers comprennent :",choices:["La prescription de médicaments oculaires","La délivrance de verres correcteurs et lentilles sur prescription médicale, et le renouvellement/adaptation dans les conditions légales. La mesure d'AV et la réfraction sont des actes optométriques","Les injections intra-vitréennes","Le diagnostic des pathologies oculaires"],answer:1,diff:1,explication:"L'opticien-lunetier (L4362 CSP) peut : délivrer des équipements sur prescription médicale, renouveler et adapter la correction dans les conditions légales, réaliser des examens de vue (mesure AV, réfraction). Il ne peut pas diagnostiquer des pathologies ni prescrire des médicaments. Tout signe pathologique doit être orienté vers l'ophtalmologiste.",tags:["Actes réservés","Opticien","CSP","Prescription","Réfraction","Compétences"]},
];

// ─── BANQUE LENTILLES 2 ───
export const QB_OL_LENTILLES2 = [
  {id:"ol_lc1",prompt:"La kératométrie mesure :",choices:["L'épaisseur centrale de la cornée","Les rayons de courbure de la cornée centrale (K1 méridien plat, K2 méridien courbe) — la différence K1-K2 = astigmatisme cornéen","La pression intra-oculaire","L'acuité visuelle corrigée"],answer:1,diff:1,explication:"La kératométrie mesure les rayons de courbure de la cornée centrale sur ses deux méridiens principaux : K1 (méridien plat) et K2 (méridien courbe). La différence K1-K2 donne l'astigmatisme cornéen. K moyen permet de calculer le rayon de base de la lentille : Rb ≈ Kmoy + 0.1 mm (principe 'flatter than K') pour les lentilles rigides.",tags:["Kératométrie","Cornée","K1","K2","Astigmatisme cornéen","Lentilles"]},
  {id:"ol_lc2",prompt:"La topographie cornéenne est indispensable pour :",choices:["Choisir la couleur d'une lentille cosmétique","Cartographier complète la cornée — indispensable pour détecter le kératocône, planifier la chirurgie réfractive et adapter les lentilles spéciales","Mesurer l'acuité visuelle de loin","Calculer l'addition presbytique"],answer:1,diff:2,explication:"La topographie cornéenne (placido, Scheimpflug) cartographie toute la surface cornéenne via des maps axiales, tangentielles et d'élévation. Elle est indispensable pour : dépister le kératocône (déformation conique), la chirurgie réfractive (LASIK, PKR), l'adaptation de lentilles rigides ou sclérales. La kératométrie standard n'explore que la cornée centrale.",tags:["Topographie cornéenne","Kératocône","Chirurgie réfractive","Cornée","Lentilles spéciales"]},
  {id:"ol_lc3",prompt:"Le kératocône est caractérisé par :",choices:["Un épaississement progressif de la cornée avec astigmatisme régulier corrigeable par lunettes","Une déformation progressive en cône de la cornée entraînant un astigmatisme irrégulier croissant mal corrigé par lunettes — nécessite des LRPG ou lentilles hybrides","Une opacification de la cornée secondaire à une infection","Une augmentation de la pression intra-oculaire"],answer:1,diff:2,explication:"Le kératocône est une ectasie cornéenne progressive : la cornée se déforme en cône, créant un astigmatisme irrégulier de plus en plus important, impossible à corriger correctement par des lunettes. Les LRPG (lentilles rigides perméables au gaz) ou les lentilles hybrides/sclérales s'appuient sur la cornée pour créer une surface optique régulière. Le crosslinking cornéen stabilise l'évolution.",tags:["Kératocône","LRPG","Astigmatisme irrégulier","Crosslinking","Lentilles rigides"]},
  {id:"ol_lc4",prompt:"Quelle est la principale différence entre les lentilles hydrogel (HEMA) et les lentilles silicone hydrogel ?",choices:["Les lentilles hydrogel sont plus résistantes mécaniquement","Les lentilles silicone hydrogel ont une transmissibilité à l'oxygène (Dk/e) très supérieure (> 100 Fatt vs < 24 pour l'hydrogel) — réduisant le risque de néovascularisation cornéenne","Les lentilles hydrogel sont toujours plus confortables","Les lentilles silicone hydrogel ne peuvent pas corriger l'astigmatisme"],answer:1,diff:1,explication:"Les lentilles hydrogel classiques (HEMA, teneur en eau 38-70%) ont un Dk/e < 24 Fatt, insuffisant pour le port prolongé. Les lentilles silicone hydrogel intègrent des polymères siliconés qui augmentent drastiquement la perméabilité à l'O₂ (Dk/e > 100 Fatt), permettant le port prolongé approuvé et réduisant le risque de néovascularisation cornéenne par hypoxie.",tags:["Hydrogel","Silicone hydrogel","Dk/e","Transmissibilité O2","Port prolongé","Lentilles"]},
  {id:"ol_lc5",prompt:"Lors de la pose d'une lentille rigide perméable au gaz (LRPG), le pattern fluorescéine idéal montre :",choices:["Un contact central intense (appui fort au centre)","Un léger alignement central avec soulèvement périphérique (fluorescéine visible à la périphérie) — pas d'appui cornéen fort","Un soulèvement central important (grand lac de fluorescéine au centre)","Aucune fluorescéine visible (contact total)"],answer:1,diff:3,explication:"Le pattern fluorescéine idéal d'une LRPG en fit aligné : léger alignement au centre (peu de fluorescéine), bande de soutien médio-périphérique, soulèvement périphérique avec fluorescéine visible. Un appui central fort (centre sombre = black spot) indique un Rb trop court (too steep). Un soulèvement central (lac central) indique un Rb trop plat (too flat).",tags:["LRPG","Fluorescéine","Pattern","Fit","Rayon de base","Kératométrie"]},
  {id:"ol_lc6",prompt:"La néovascularisation cornéenne est une complication liée au port de lentilles de contact principalement causée par :",choices:["Une allergie au produit d'entretien","Une hypoxie cornéenne chronique — la cornée développe des néovaisseaux pour compenser le manque d'oxygène","Un traumatisme cornéen lors du retrait","Une infection bactérienne aiguë"],answer:1,diff:2,explication:"La néovascularisation cornéenne survient quand la cornée manque d'oxygène de façon chronique (port trop long, lentilles à faible Dk/e). La cornée normalement avasculaire développe des néovaisseaux depuis le limbe pour s'oxygéner. C'est irréversible partiellement. La solution est des lentilles silicone hydrogel haute Dk/e et la réduction du temps de port.",tags:["Néovascularisation","Hypoxie","Dk/e","Complication","Cornée","Lentilles"]},
  {id:"ol_lc7",prompt:"Le syndrome oculaire sec est une contre-indication aux lentilles de contact si le BUT est :",choices:["< 7 secondes","≥ 10 secondes","Entre 10 et 15 secondes","Supérieur à 20 secondes"],answer:0,diff:2,explication:"Un BUT (Break Up Time) < 7 secondes indique une forte instabilité du film lacrymal, contre-indiquant généralement l'adaptation en lentilles de contact (risque d'inconfort majeur, dépôts, kératite ponctuée). Un BUT < 10 s est suspect. Des mesures complémentaires (Schirmer, osmolarité) permettent d'objectiver le syndrome oculaire sec. La valeur limite stricte la plus souvent citée est BUT < 7 s.",tags:["BUT","Film lacrymal","Syndrome oculaire sec","Contre-indication","Lentilles"]},
  {id:"ol_lc8",prompt:"Le port prolongé (dormir avec les lentilles) multiplie le risque d'infection cornéenne par :",choices:["2 fois","6 à 8 fois","50 fois","Il ne change pas le risque"],answer:1,diff:2,explication:"Le port prolongé (extended wear — dormir avec ses lentilles) multiplie le risque de kératite infectieuse par 6 à 8 par rapport au port journalier strict (daily wear). Ce risque est réduit mais non supprimé avec les lentilles silicone hydrogel ultra-Dk/e. Le port prolongé ne doit être prescrit que pour des indications médicales spécifiques (patient ne pouvant pas retirer ses lentilles).",tags:["Port prolongé","Risque infectieux","Kératite","Lentilles","Sécurité"]},
  {id:"ol_lc9",prompt:"La stabilisation d'une lentille torique souple repose principalement sur :",choices:["La couleur de la lentille qui indique le bas","Le lest inférieur (biseau biseauté) ou les zones minces à 3h et 9h (thin zones) — l'axe doit rester stable à ±10°","La forte teneur en eau qui colle la lentille à la cornée","Le rayon de base exclusivement"],answer:1,diff:2,explication:"Les lentilles toriques souples compensent l'astigmatisme. Pour que l'axe du cylindre reste stable, la lentille doit être anti-rotatoire. Deux méthodes principales : le lest (zone plus épaisse/alourdie en bas qui tombe sous la gravité) et les zones minces à 3h-9h (thin zones — la pression de la paupière maintient le repère). L'axe doit rester stable à ±10° lors des clignements.",tags:["Lentille torique","Stabilisation","Lest","Thin zones","Axe","Astigmatisme"]},
  {id:"ol_lc10",prompt:"Les lentilles multifocales pour presbytes en conception simultanée fonctionnent selon le principe :",choices:["D'une zone unique de loin par œil et une de près par l'autre œil (monovision)","De zones concentriques alternant loin et près sur la même lentille — le cerveau sélectionne la focalisation utile selon la distance","D'une translation verticale de la lentille comme les verres bifocaux","D'un verre de puissance fixe ajusté par la monture"],answer:1,diff:2,explication:"Les lentilles multifocales à conception simultanée présentent simultanément sur la même lentille des zones de vision de loin et de près (en anneaux concentriques). Le cerveau apprend à sélectionner la focalisation pertinente selon la distance regardée. Le compromis est une légère dégradation de la qualité visuelle par rapport aux monofocales. La conception alternante (translation) est utilisée pour les LRPG bifocales.",tags:["Lentille multifocale","Presbytie","Conception simultanée","Zones concentriques","Lentilles"]},
  {id:"ol_lc11",prompt:"Pourquoi ne faut-il JAMAIS rincer les lentilles de contact avec de l'eau du robinet ?",choices:["L'eau du robinet est trop froide et peut déformer la lentille","L'eau du robinet peut contenir Acanthamoeba — une amibe pouvant provoquer une kératite gravissime et résistante au traitement","L'eau du robinet contient du chlore qui décolore les lentilles colorées","L'eau du robinet est trop acide pour le confort oculaire"],answer:1,diff:1,explication:"L'eau du robinet peut contenir Acanthamoeba castellanii, une amibe résistante à la chloration standard. En contact avec les lentilles et la cornée, elle peut provoquer une Acanthamoeba kératitis : infection gravissime, extrêmement douloureuse, difficile à traiter (biguanides PHMB pendant 6-12 mois), pouvant laisser des cicatrices cornéennes définitives et altérer l'AV.",tags:["Acanthamoeba","Eau du robinet","Entretien","Kératite","Lentilles","Hygiène"]},
  {id:"ol_lc12",prompt:"Le traitement par solution eau oxygénée (H₂O2 à 3%) pour l'entretien des lentilles souples nécessite obligatoirement :",choices:["Un rinçage à l'eau du robinet après désinfection","Une neutralisation complète (catalyseur ou pastille de platine, minimum 6 heures) avant toute utilisation — sinon brûlure chimique cornéenne grave","Un rinçage au sérum physiologique uniquement","Aucune précaution particulière, c'est la solution la plus douce"],answer:1,diff:2,explication:"L'eau oxygénée à 3% est un excellent désinfectant pour les lentilles (très efficace contre les bactéries, virus, champignons et Acanthamoeba). Mais elle est corrosive pour la cornée. La neutralisation est OBLIGATOIRE avant le port (catalyseur inclus dans les étuis ou pastille de platine, minimum 6 heures). Mettre une lentille non neutralisée provoque une brûlure chimique de la cornée.",tags:["Eau oxygénée","H2O2","Entretien","Neutralisation","Brûlure","Lentilles","Sécurité"]},
];

export const QB_OL_AMETROPIES_PA = [
  {id:"ol_ap1",prompt:"La presbytie atteint sa correction maximale (ADD) vers :",choices:["40 ans (ADD +0,75)","55-60 ans (ADD +2,50-3,00)","65 ans et plus (ADD +3,00 à +3,50 — amplitude d'accommodation quasi nulle)","70 ans (ADD +5,00)"],answer:2,diff:1,explication:"ADD maximale : +3,00 à +3,50 δ (plafond habituel). Progression : 40 ans +0,75-1,00 ; 45 ans +1,00-1,25 ; 50 ans +1,50-1,75 ; 55 ans +2,00-2,25 ; 60 ans +2,50 ; 65+ ans +3,00-3,50. L'amplitude d'accommodation diminue avec l'âge (rigidification du cristallin). Règle de Donders-Duane.",tags:["ADD","Presbytie","Amplitude d'accommodation"]},
  {id:"ol_ap2",prompt:"La cataracte nucléaire provoque souvent :",choices:["Une hypermétropie progressive","Une myopie de l'index (sclérose du cristallin → augmentation de l'indice de réfraction)","Un astigmatisme irrégulier","Aucun symptôme visuel"],answer:1,diff:2,explication:"Cataracte nucléaire : sclérose progressive du noyau → augmentation de l'indice de réfraction → myopie de l'index. Le patient peut noter une amélioration transitoire de la vision de près avant la dégradation générale. Traitement définitif : chirurgie (phacoémulsification + implant LIO).",tags:["Cataracte nucléaire","Myopie de l'index","Cristallin","LIO"]},
  {id:"ol_ap3",prompt:"La dégénérescence maculaire liée à l'âge (DMLA) entraîne :",choices:["Une baisse de la vision périphérique uniquement","Une baisse de l'AV centrale (scotome central) avec préservation de la vision périphérique","Une cécité totale rapide","Une myopie progressive"],answer:1,diff:1,explication:"DMLA : atteinte de la macula (cônes). AV centrale ↓ + métamorphopsies (grille d'Amsler), vision périphérique préservée (déplacement autonome conservé). Formes : sèche (atrophique, lente) et humide (néovascularisation → anti-VEGF en urgence). Facteurs de risque : âge, tabac, UV.",tags:["DMLA","Macula","AV centrale","Métamorphopsies","Grille d'Amsler"]},
  {id:"ol_ap4",prompt:"Le glaucome chronique à angle ouvert (GCAO) est diagnostiqué par :",choices:["Un test d'acuité visuelle standard","Mesure PIO (tonomètre) + analyse nerf optique (excavation cup/disc) + périmétrie (scotome arciforme de Bjerrum)","Un test de vision des couleurs uniquement","Une simple inspection externe"],answer:1,diff:1,explication:"GCAO : triade : 1) PIO (normale < 21 mmHg, mais 30-50% GCAO ont PIO normale) 2) Excavation papillaire (C/D > 0,6-0,7) 3) Champ visuel : scotome arciforme de Bjerrum. Maladie silencieuse. Traitement : prostaglandines (collyre, 1ère intention).",tags:["Glaucome","PIO","Excavation papillaire","Champ visuel","GCAO"]},
  {id:"ol_ap5",prompt:"La basse vision (OMS) est définie par :",choices:["AV < 10/10","AV du meilleur oeil corrigé entre 1/20 et 3/10","Cécité totale uniquement","AV < 5/10"],answer:1,diff:2,explication:"Basse vision OMS : AV entre 1/20 et 3/10 du meilleur oeil corrigé (ou CV < 20°). Cécité légale France : AV ≤ 1/20 ou CV < 10°. Aides : loupes, systèmes télescopiques, logiciels d'agrandissement. Professionnel pouvant adapter : opticien formé à la basse vision.",tags:["Basse vision","AV","OMS","Cécité légale","Aides optiques"]},
  {id:"ol_ap6",prompt:"L'adaptation aux lentilles de contact chez le presbyte repose principalement sur :",choices:["L'abandon des lentilles (impossibles pour presbytes)","La monovision (oeil dominant de loin, autre de près) ou les lentilles multifocales à conception simultanée","Le port de lunettes par-dessus les lentilles","Des lentilles rigides uniquement"],answer:1,diff:1,explication:"Adaptation LC presbyte : 1) Monovision : oeil dominant = loin, oeil non dominant = près. Perte partielle de stéréoscopie. 2) Multifocales simultanées : zones loin + près superposées (neuradaptation). Détermination oeil dominant : test du trou (Miles). Test en simulation avant adaptation définitive.",tags:["Monovision","Multifocales","Presbytie","Lentilles","Oeil dominant"]},
  {id:"ol_ap7",prompt:"Le strabisme accommodatif convergent de l'enfant est associé à :",choices:["La myopie forte non corrigée","L'hypermétropie non corrigée (accommodation excessive → syncinésie convergente)","La presbytie débutante","L'astigmatisme oblique"],answer:1,diff:2,explication:"Strabisme accommodatif : hypermétropie → accommodation soutenue → syncinésie accommodo-convergente excessive → ésotropie. Traitement : verres convergents adaptés → réduction de l'accommodation → souvent correction du strabisme. Risque : amblyopie (oeil supprimé). Traitement amblyopie : occlusion de l'oeil dominant.",tags:["Strabisme","Ésotropie","Hypermétropie","Amblyopie","Occlusion"]},
  {id:"ol_ap8",prompt:"La vergence effective d'un verre de +4,00 δ porté à 12 mm de la cornée, ramenée en lentille de contact (ECL ≈ 0), est :",choices:["Identique : +4,00 δ","Légèrement inférieure : +4,00 / (1 + 0,012 × 4) ≈ +3,82 δ","Légèrement supérieure à +4,00 δ","Double : +8,00 δ"],answer:1,diff:3,explication:"Vergence effective : V_lc = V_lun / (1 + d × V_lun) où d = 0,012 m. V_lc = 4 / (1 + 0,012 × 4) = 4 / 1,048 ≈ +3,82 δ. Pour lentille convergente (+) : rapprocher de la cornée → vergence efficace ↓. Pour lentille divergente (-) : vergence efficace ↑. Formule de conjugaison avec le déplacement.",tags:["Vergence effective","ECL","Lentilles de contact","Formule"]},
  {id:"ol_ap9",prompt:"L'amblyopie fonctionnelle se définit comme :",choices:["Une baisse d'AV due à une lésion rétinienne","AV < 7/10 unilatérale sans cause organique, due à un manque de stimulation visuelle pendant la période sensible (0-7 ans)","Une myopie forte bilatérale","Une presbytie précoce"],answer:1,diff:1,explication:"Amblyopie fonctionnelle : AV irréductible sans cause organique. Causes : strabisme (suppression), anisométropie (flou différentiel), déprivation (cataracte congénitale, ptôsis). Traitement : 1) Corriger le défaut optique 2) Occlusion de l'oeil dominant. Pronostic excellent si traité avant 7 ans (plasticité cérébrale).",tags:["Amblyopie","Strabisme","Période sensible","Occlusion","AV"]},
  {id:"ol_ap10",prompt:"La grille d'Amsler est utilisée pour dépister :",choices:["Le glaucome","Les métamorphopsies et scotomes centraux (DMLA, maculopathies)","L'astigmatisme","La presbytie débutante"],answer:1,diff:1,explication:"Grille d'Amsler : quadrillage avec point de fixation. Détecte : métamorphopsies (lignes ondulées → DMLA humide), scotomes (zones manquantes). Test de dépistage rapide. La DMLA humide peut se décompenser rapidement → urgence ophtalmologique (anti-VEGF sous 48-72h).",tags:["Grille d'Amsler","DMLA","Métamorphopsies","Scotome","Dépistage"]},
];

export const QB_OL_ACUITEVIS_SCAL = [
  {id:"ol_av1",prompt:"Quelle est la correspondance entre 10/10 (échelle de Monoyer) et l'échelle de Snellen ?",choices:["20/200","20/100","20/20","20/15"],answer:2,diff:1,explication:"10/10 (Monoyer) = 20/20 (Snellen) : acuité visuelle normale, angle de résolution de 1 minute d'arc.",tags:["Acuité visuelle","Monoyer","Snellen"]},
  {id:"ol_av2",prompt:"Le minimum séparable correspond à quel critère anatomique ?",choices:["Diamètre d'un cône maculaire (3 µm)","Diamètre d'un bâtonnet (2 µm)","Distance entre deux cônes séparés par un cône (~6 µm, 1 minute d'arc)","Largeur de la fovéola (350 µm)"],answer:2,diff:2,explication:"Le minimum séparable (~1 minute d'arc) est limité par l'espacement inter-cônes : deux points sont séparés si leur image tombe sur deux cônes avec un cône non stimulé entre eux.",tags:["Minimum séparable","Cônes","Fovéola"]},
  {id:"ol_av3",prompt:"Quelle acuité visuelle correspond à la ligne P2 sur l'échelle de Parinaud ?",choices:["Acuité de près normale","Acuité insuffisante pour lire","Minimum légal pour le permis de conduire en vision de près","Acuité réservée aux malvoyants"],answer:2,diff:1,explication:"P2 à 33 cm correspond au minimum légal pour le permis de conduire en vision de près. P1.5 est l'acuité normale du sujet jeune.",tags:["Parinaud","Permis de conduire","Vision de près"]},
  {id:"ol_av4",prompt:"L'anneau de Landolt est l'étalon international car :",choices:["Il mesure la vision des couleurs","Il est indépendant de la reconnaissance des lettres (ISO 8596)","Il évalue uniquement la vision nocturne","Il teste le champ visuel central"],answer:1,diff:1,explication:"Les anneaux de Landolt (ISO 8596) ne nécessitent pas de reconnaître des lettres, ce qui les rend utilisables quelles que soient la langue et l'éducation du patient.",tags:["Landolt","ISO 8596","Acuité visuelle"]},
  {id:"ol_av5",prompt:"La réfraction subjective monoculaire débute par quelle étape ?",choices:["Test de la rosace pour l'axe du cylindre","Brouillard avec +3.00 D pour relâcher l'accommodation","Mesure de l'acuité de près","Skiascopie sous cycloplégie"],answer:1,diff:2,explication:"On commence par brouiller avec +3.00 D (méthode de brouillard) pour relâcher l'accommodation et partir d'un état hypermétrope contrôlé avant d'affiner la correction.",tags:["Réfraction subjective","Brouillard","Accommodation"]},
  {id:"ol_av6",prompt:"Le test de la rosace (cadran de Lancaster) détermine :",choices:["La déviation oculomotrice","L'axe du cylindre en réfraction subjective","Le seuil de vision des couleurs","L'acuité en vision nocturne"],answer:1,diff:2,explication:"La rosace présente des lignes à différents méridiens. Le patient indique la ligne la plus nette, révélant l'axe du cylindre à corriger.",tags:["Rosace Lancaster","Cylindre","Réfraction subjective"]},
  {id:"ol_av7",prompt:"En skiascopie à 1 mètre, que signifie un mouvement inverse du reflet ?",choices:["L'oeil est emmétrope","L'oeil est hypermétrope","L'oeil est myope (point neutre déjà dépassé)","L'oeil a un astigmatisme direct"],answer:2,diff:2,explication:"Un mouvement inverse signifie que le punctum remotum est entre l'opticien et le patient : l'oeil est myope. La lentille de travail de -1.00 D est soustraite au résultat final.",tags:["Skiascopie","Mouvement inverse","Myopie"]},
  {id:"ol_av8",prompt:"L'hyperacuité de Vernier correspond à un seuil de :",choices:["1 minute d'arc","5 minutes d'arc","5 secondes d'arc","30 secondes d'arc"],answer:2,diff:3,explication:"L'hyperacuité de Vernier (alignement de 2 segments) atteint ~5 secondes d'arc grâce à l'interpolation neuronale centrale, bien en deçà du minimum séparable (1 minute d'arc).",tags:["Hyperacuité","Vernier","Acuité visuelle"]},
  {id:"ol_av9",prompt:"Quel agent cycloplégique est utilisé pour la skiascopie chez l'enfant ?",choices:["Tropicamide 0,5 %","Cyclopentolate 1 % ou Atropine 1 %","Pilocarpine 2 %","Phényléphrine 10 %"],answer:1,diff:2,explication:"Chez l'enfant, le cyclopentolate 1 % (délai 45 min) ou l'atropine 1 % (délai 3 jours, cas d'ésotropie accommodative) sont utilisés pour bloquer l'accommodation lors de la skiascopie.",tags:["Cycloplégie","Skiascopie","Enfant"]},
  {id:"ol_av10",prompt:"Le minimum légal binoculaire pour le permis de conduire de groupe 1 en France est :",choices:["3/10 binoculaire","5/10 binoculaire (avec au moins 2/10 sur l'oeil le moins bon)","8/10 binoculaire","10/10 binoculaire"],answer:1,diff:2,explication:"Le groupe 1 (voitures particulières) exige 5/10 binoculaire minimum, avec au moins 2/10 sur l'oeil adelphe. En cas de monophtalmie : 5/10 après adaptation. Texte : arrêté du 28 mars 2022.",tags:["Permis de conduire","Acuité légale","Groupe 1"]}
];

export const QB_OL_ETSO_INSTR = [
  {id:"ol_ins1",prompt:"Le kératomètre (ophtalmomètre de Javal) mesure :",choices:["La pression intra-oculaire","Les rayons de courbure de la cornée dans les 2 méridiens principaux (astigmatisme cornéen + choix Rb LC)","L'épaisseur de la cornée","La longueur axiale de l'oeil"],answer:1,diff:1,explication:"Kératomètre de Javal : mesure des rayons de courbure cornéens (R horizontal et R vertical). Donne : astigmatisme cornéen (différence des 2 rayons) + rayons pour choix du Rb (rayon de base) d'une LC. Intégré dans les auto-réfractomètres modernes. Topographe : carte complète de la cornée.",tags:["Kératomètre","Cornée","Rayon de courbure","Astigmatisme","Lentilles de contact"]},
  {id:"ol_ins2",prompt:"Le tonomètre à aplanation de Goldmann mesure :",choices:["L'épaisseur de la cornée","La PIO (pression intra-oculaire) par aplanation d'une surface cornéenne de 3,06 mm (force = PIO)","La topographie cornéenne","L'AV de loin"],answer:1,diff:2,explication:"Tonomètre de Goldmann : méthode de référence PIO. Aplanation 3,06 mm (surface tensions + rigidité s'annulent). Anesthésie topique + fluorescéine. PIO normale : 10-21 mmHg. Biais : cornée fine → sous-estimation PIO.",tags:["Tonomètre Goldmann","PIO","Glaucome","Aplanation"]},
  {id:"ol_ins3",prompt:"La lampe à fente (biomicroscope) permet :",choices:["Uniquement la mesure de la réfraction","L'examen microscopique de l'oeil entier en lumière fissurante (cornée, chambre antérieure, cristallin, vitré) + fond d'oeil avec condenseur","La mesure de la PIO uniquement","Le dépistage de la DMLA uniquement"],answer:1,diff:1,explication:"Lampe à fente : éclairage en fente fine + microscope binoculaire. Examen : cornée (kératocône, kératite), chambre antérieure, iris, cristallin (cataracte). Avec condenseur 90 D ou 78 D : fond d'oeil (rétine, papille, macula, vitré). Fluorescéine : BUT, tonomètre Goldmann.",tags:["Lampe à fente","Biomicroscope","Cornée","Cristallin","Fond d'oeil"]},
  {id:"ol_ins4",prompt:"Le frontofocusmètre (lensomètre) permet de :",choices:["Mesurer la courbure de la monture","Mesurer la vergence d'un verre (S, C, axe) et l'éventuel prisme — pour contrôle et marquage","Mesurer l'épaisseur du verre","Identifier le traitement antireflet"],answer:1,diff:1,explication:"Frontofocusmètre : mesure vergence (S, C, axe), prisme (valeur + base) et permet le marquage du centre optique. Tolérances ISO 21987 : prisme ± 0,09 Δ pour |P| < 6 Δ. Indispensable pour : contrôle de conformité, marquage avant montage.",tags:["Frontofocusmètre","Vergence","Prisme","Contrôle","ISO 21987"]},
  {id:"ol_ins5",prompt:"La pachymétrie cornéenne mesure :",choices:["La courbure cornéenne","L'épaisseur de la cornée (normale : 540-560 µm) — importante pour glaucome et chirurgie réfractive","La PIO","L'astigmatisme cornéen"],answer:1,diff:2,explication:"Pachymétrie : épaisseur cornéenne centrale normale = 540-560 µm. Cornée fine → PIO Goldmann sous-estimée. Kératocône : cornée amincie (< 460 µm). Critère sécurité LASIK : épaisseur résiduelle ≥ 250-300 µm. Techniques : ultrasons (contact), OCT (non contact).",tags:["Pachymétrie","Épaisseur cornéenne","Glaucome","Kératocône","LASIK"]},
  {id:"ol_ins6",prompt:"L'OCT (Optical Coherence Tomography) permet :",choices:["Uniquement la mesure de la PIO","L'imagerie en coupe haute résolution de la rétine et du nerf optique sans contact (DMLA, glaucome RNFL, membrane épirétinienne)","La mesure des rayons de courbure","La périmétrie"],answer:1,diff:2,explication:"OCT : interférométrie → coupes transversales rétine (~10 µm résolution). Applications : DMLA (néovaisseaux, drusen), glaucome (RNFL — épaisseur fibres nerveuses), OMC, membrane épirétinienne. OCT-A : angiographie sans injection.",tags:["OCT","Rétine","DMLA","Glaucome","RNFL"]},
  {id:"ol_ins7",prompt:"L'auto-réfractomètre fournit :",choices:["Une mesure subjective définitive","Une mesure objective (infra-rouge, patient passif) S/C/axe — utilisée comme point de départ de la réfraction subjective","Une mesure de la PIO","Une mesure de l'accommodation"],answer:1,diff:1,explication:"Auto-réfractomètre : infra-rouge, rétino-réflectométrie. Point de départ de la réfraction subjective. Peut sur-estimer myopie/hypermétropie si accommodation active → cycloplégique recommandé chez l'enfant. Résultat = ticket de réfraction.",tags:["Auto-réfractomètre","Réfraction objective","Ticket de réfraction"]},
  {id:"ol_ins8",prompt:"Le BUT (Break-Up Time) mesure :",choices:["La PIO","Le temps de rupture du film lacrymal après clignement (normal ≥ 10 s) — qualité du film lacrymal","La courbure cornéenne","L'amplitude d'accommodation"],answer:1,diff:2,explication:"BUT (fluorescéine + lampe à fente, filtre cobalt) : patient ne cligne plus → mesure du délai avant apparition de la 1ère zone sèche. Normal ≥ 10 s. < 10 s → instabilité lacrymale → syndrome oeil sec. NIBUT (non-invasif, topographe) évite la fluorescéine.",tags:["BUT","Film lacrymal","Oeil sec","Fluorescéine"]},
  {id:"ol_ins9",prompt:"La skiascopie (rétinoscope) est particulièrement utile pour :",choices:["Mesurer la PIO","Déterminer la réfraction objective (mouvement du reflet rétinien neutralisé par verres d'essai) — indispensable chez l'enfant sous cycloplégique","Mesurer l'épaisseur cornéenne","Examiner le fond d'oeil"],answer:1,diff:2,explication:"Skiascopie : observation du reflet rétinien (mouvement concordant = myopie ; discordant = hypermétropie). Neutralisation par verres d'essai. Objectif (patient passif). Indispensable chez l'enfant sous cycloplégique (cyclopentolate). Précision ± 0,50 D.",tags:["Skiascopie","Rétinoscope","Réfraction objective","Enfant","Cycloplégique"]},
  {id:"ol_ins10",prompt:"Le topographe cornéen de type Placido permet de :",choices:["Mesurer la PIO","Cartographier toute la surface cornéenne pour détecter le kératocône, évaluer l'astigmatisme, planifier la chirurgie réfractive","Mesurer l'épaisseur de la cornée uniquement","Examiner la rétine"],answer:1,diff:2,explication:"Topographe cornéen (disques de Placido) : anneaux concentriques projetés sur la cornée → cartographie complète des rayons. Applications : dépistage kératocône (OBLIGATOIRE avant chirurgie réfractive), suivi, prescription LRPG, astigmatisme irrégulier.",tags:["Topographe","Placido","Kératocône","Chirurgie réfractive","Astigmatisme"]},
];

export const QB_OL_GESTION_AMORT = [
  {id:"ol_ga1",prompt:"Un magasin d'optique achète un équipement de 12 000 € HT amortissable en linéaire sur 4 ans. L'annuité est :",choices:["1 000 €/an","3 000 €/an (12 000 / 4)","4 000 €/an","6 000 €/an"],answer:1,diff:1,explication:"Amortissement linéaire : annuité = Valeur brute / Durée = 12 000 / 4 = 3 000 €/an. Taux = 100/4 = 25%/an. VNC après 2 ans = 12 000 - 2 × 3 000 = 6 000 €. L'amortissement est une charge (681x), réduit le résultat imposable.",tags:["Amortissement linéaire","Annuité","VNC","Comptabilité"]},
  {id:"ol_ga2",prompt:"L'amortissement dégressif présente des annuités :",choices:["Constantes sur toute la durée","Décroissantes (plus fortes en début de vie) — appliquées sur la VNC avec un taux majoré","Croissantes","Uniquement lors de la cession"],answer:1,diff:2,explication:"Amortissement dégressif : taux = taux linéaire × coefficient (1,25 si 3-4 ans, 1,75 si 5-6 ans, 2,25 si ≥ 7 ans). Annuité = VNC × taux dégressif. Basculer en linéaire quand annuité dégressive < annuité linéaire résiduelle. Avantage fiscal : charges plus importantes en début d'investissement.",tags:["Amortissement dégressif","VNC","Coefficient","Taux","Fiscalité"]},
  {id:"ol_ga3",prompt:"Dans un tableau d'amortissement d'emprunt à annuités constantes, d'une annuité à l'autre :",choices:["L'annuité totale augmente","La part d'intérêts diminue et la part de capital remboursé augmente, l'annuité totale restant CONSTANTE","L'annuité totale diminue","Le taux d'intérêt varie"],answer:1,diff:2,explication:"Annuités constantes (méthode française) : annuité = K × i / (1 - (1+i)^-n). Annuité fixe tout au long. Décomposition variable : intérêts ↓ (capital restant dû ↓) et capital remboursé ↑. Avantage : mensualités prévisibles pour la trésorerie.",tags:["Annuités constantes","Emprunt","Intérêts","Capital","Trésorerie"]},
  {id:"ol_ga4",prompt:"La Capacité d'AutoFinancement (CAF) est calculée par :",choices:["CA - Charges variables","Résultat net + Dotations aux amortissements","EBE - Charges financières","CA × Taux de marge"],answer:1,diff:2,explication:"CAF = Résultat net + Dotations aux amortissements (± reprises provisions ± VCE). Représente la trésorerie potentielle générée par l'activité. Sert à : rembourser emprunts, financer investissements. Ratio CAF/Dettes financières : < 3-5 ans = sain.",tags:["CAF","Autofinancement","Amortissements","Résultat net"]},
  {id:"ol_ga5",prompt:"Le Besoin en Fonds de Roulement (BFR) = :",choices:["Le cash disponible en banque","Stocks + Créances clients - Dettes fournisseurs","Les investissements réalisés","Le résultat net de l'exercice"],answer:1,diff:2,explication:"BFR = Stocks + Créances clients - Dettes fournisseurs. En optique : stocks montures/lentilles importants, créances mutuelles (15-45j). Si BFR > 0 : ressource de financement nécessaire. Trésorerie nette = Fonds de Roulement (FR) - BFR.",tags:["BFR","Fonds de roulement","Stocks","Créances","Trésorerie"]},
  {id:"ol_ga6",prompt:"Le seuil de rentabilité (SR) se calcule par :",choices:["CA - Charges fixes","Charges fixes / Taux de Marge sur Coût Variable (TMCV)","Résultat / CA","Charges variables / CA"],answer:1,diff:1,explication:"SR = Charges Fixes / TMCV. TMCV = (CA - Charges Variables) / CA. En dessous du SR → perte. Au-dessus → bénéfice. Point mort (en jours) = SR / (CA/360). Marge de sécurité = CA réel - SR. Exemple : CF = 80 000 €, TMCV = 40% → SR = 200 000 €.",tags:["Seuil de rentabilité","Charges fixes","TMCV","Point mort"]},
  {id:"ol_ga7",prompt:"Un emprunt de 30 000 € à 4%/an sur 3 ans avec amortissement constant du capital : la 1ère annuité est :",choices:["10 000 €","11 200 €","10 000 € capital + 1 200 € intérêts = 11 200 €","12 000 €"],answer:2,diff:2,explication:"Amortissement constant : capital remboursé/an = 30 000/3 = 10 000 €. Intérêts 1ère année = 30 000 × 4% = 1 200 €. Annuité 1 = 11 200 €. Annuité 2 = 10 000 + 800 = 10 800 €. Annuité 3 = 10 000 + 400 = 10 400 €. Total intérêts = 1 200 + 800 + 400 = 2 400 €.",tags:["Emprunt","Tableau d'amortissement","Annuité","Intérêts","Capital constant"]},
  {id:"ol_ga8",prompt:"La TVA applicable sur les ventes de lunettes de vue (verres + montures) est au taux de :",choices:["5,5%","10%","20% (taux normal)","0%"],answer:2,diff:2,explication:"TVA en optique : équipements optiques (verres + montures) soumis au taux normal de 20%. Lentilles de contact correctrices : 20% également. TVA à décaisser = TVA collectée (ventes) - TVA déductible (achats). Pas d'exonération spécifique pour l'optique.",tags:["TVA","20%","Optique","Comptabilité"]},
  {id:"ol_ga9",prompt:"La VNC (Valeur Nette Comptable) d'une immobilisation se calcule par :",choices:["Valeur d'achat brute uniquement","Valeur d'achat brute - Amortissements cumulés","Valeur de revente sur le marché","Valeur d'assurance"],answer:1,diff:1,explication:"VNC = Valeur brute - Cumul amortissements. Représente la valeur comptable résiduelle. Lors de la cession : prix de cession > VNC → plus-value (produit exceptionnel) ; prix < VNC → moins-value (charge exceptionnelle). La VNC décroît chaque année jusqu'à 0 (fin de durée d'amortissement).",tags:["VNC","Amortissements","Bilan","Cession","Immobilisations"]},
  {id:"ol_ga10",prompt:"La Marge Commerciale d'un opticien se calcule par :",choices:["CA - Toutes les charges","CA - Coût d'achat des marchandises vendues (CAMV)","CA × 20%","CA - Charges fixes uniquement"],answer:1,diff:1,explication:"Marge commerciale = CA - Coût d'Achat des Marchandises Vendues (CAMV). CAMV = Stock initial + Achats - Stock final. Taux de marge = MC / Prix d'achat. Taux de marque = MC / CA. En optique : taux de marque souvent 60-70% (taux de marge élevé car les verres progressifs haut de gamme ont une forte valeur ajoutée).",tags:["Marge commerciale","CAMV","Taux de marge","Taux de marque","SIG"]},
];

export const QB_OL_GESTION_MKT = [
  {id:"ol_mkt1",prompt:"Le merchandising en magasin d'optique consiste à :",choices:["La gestion des stocks uniquement","Organiser la surface de vente pour optimiser les achats (implantation, mise en valeur, flux client, PLV)","La publicité sur les réseaux sociaux uniquement","La fixation des prix"],answer:1,diff:1,explication:"Merchandising (4P en magasin) : Produit (assortiment), Place (implantation, zones chaudes/froides, facing), Prix (étiquetage), Promotion (PLV). Zones chaudes : parcours naturel client. Zones froides : à dynamiser (promotions, éclairage). En optique : vitrine (attirer), portoirs (essayage), espace conseils.",tags:["Merchandising","PLV","Zones chaudes","Implantation","Surface de vente"]},
  {id:"ol_mkt2",prompt:"Le positionnement marketing d'un opticien consiste à :",choices:["Fixer un prix plus bas que les concurrents","Définir l'image distinctive souhaitée dans l'esprit du client par rapport aux concurrents","Élargir la gamme de produits","Augmenter la surface du magasin"],answer:1,diff:1,explication:"Positionnement : choix de la perception souhaitée (axe différenciation). Ex : 'opticien expert et conseil' vs 'opticien low-cost'. Construit via : gamme, design, communication, prix, service. Lié au ciblage (à qui?) et au segment (groupe homogène de clients).",tags:["Positionnement","Marketing","Différenciation","Image","Concurrents"]},
  {id:"ol_mkt3",prompt:"Le taux de transformation en magasin d'optique représente :",choices:["Le CA sur lentilles / CA total","Le ratio actes d'achat / visiteurs — indicateur d'efficacité de la force de vente","Le % de clients satisfaits","Le taux de renouvellement des stocks"],answer:1,diff:2,explication:"Taux de transformation = (Nb achats / Nb entrées) × 100. Benchmark optique : 30-50%. Amélioration : accueil, argumentation, disponibilité, réduction du temps d'attente. KPI complémentaires : panier moyen (CA / nb actes) et taux de fidélisation.",tags:["Taux de transformation","KPI","Force de vente","Performance"]},
  {id:"ol_mkt4",prompt:"La communication digitale prioritaire d'un opticien comprend :",choices:["Uniquement les publicités TV","Site web SEO + Google My Business (avis) + réseaux sociaux + emailings (RGPD)","Uniquement les catalogues papier","Les panneaux publicitaires extérieurs uniquement"],answer:1,diff:1,explication:"Communication digitale : 1) Site web (SEO local : 'opticien + ville') 2) Google My Business : avis Google (note ≥ 4/5 crucial) 3) Réseaux sociaux : Instagram (photos), Facebook (événements) 4) Emailing/SMS (rappels renouvellement) — consentement RGPD obligatoire.",tags:["SEO","Google My Business","Réseaux sociaux","RGPD","Communication"]},
  {id:"ol_mkt5",prompt:"Le NPS (Net Promoter Score) mesure :",choices:["Le chiffre d'affaires par client","La propension à recommander (Promoteurs 9-10 − Détracteurs 0-6) — score entre -100 et +100","La satisfaction produit uniquement","Le nombre de clients perdus"],answer:1,diff:2,explication:"NPS = % Promoteurs (9-10) - % Détracteurs (0-6). Neutres (7-8) ne comptent pas. NPS > 50 = excellent. NPS < 0 = problème. Question unique : 'Recommanderiez-vous notre opticien à un proche ?' Simple et actionnable.",tags:["NPS","Satisfaction","Recommandation","Promoteurs","Détracteurs"]},
  {id:"ol_mkt6",prompt:"L'analyse SWOT d'un opticien identifie :",choices:["Uniquement les points forts","Forces et Faiblesses internes + Opportunités et Menaces externes (environnement/marché)","Uniquement les menaces concurrentielles","Le plan marketing sur 5 ans"],answer:1,diff:1,explication:"SWOT : Strengths (forces internes) + Weaknesses (faiblesses internes) + Opportunities (opportunités externes) + Threats (menaces externes). Ex opportunités : vieillissement population, télétravail ↑ myopie, renouvellement réglementaire. Ex menaces : e-commerce optique, low-cost, réseaux nationaux.",tags:["SWOT","Analyse stratégique","Forces","Faiblesses","Opportunités","Menaces"]},
  {id:"ol_mkt7",prompt:"La segmentation clientèle en optique permet de :",choices:["Vendre le même produit à tous","Identifier des groupes homogènes de clients pour adapter l'offre et le discours (par âge, amétropie, style de vie, budget)","Réduire l'assortiment","Augmenter les prix"],answer:1,diff:1,explication:"Segmentation : découpage en groupes homogènes. Critères : démographiques (âge, sexe), comportementaux (fréquence), psychographiques (style de vie). Segments optique : enfant (durabilité), presbyte actif (progressifs performants), sportif (LC, filtres), low-cost (panier A). Permet ciblage et positionnement précis.",tags:["Segmentation","Ciblage","Marketing","Clientèle"]},
  {id:"ol_mkt8",prompt:"La politique 100% Santé (classe 1) contraint l'opticien à :",choices:["Vendre toutes ses montures à 30 € maximum","Proposer obligatoirement un panier classe 1 (monture ≤ 30€ adulte + verres grille SS) à RAC zéro, côte à côte avec la classe 2 (devis normalisé)","Appliquer uniquement des prix libres","Ne vendre que des équipements remboursés"],answer:1,diff:1,explication:"100% Santé : classe 1 = sans reste à charge (monture adulte ≤ 30 €, verres selon grille SS + CMC responsable). Obligation : 20 modèles classe 1 minimum en vitrine. Devis normalisé : 2 paniers côte à côte. Classe 2 : prix librement fixé. Entré en vigueur le 1er janvier 2020.",tags:["100% Santé","Classe 1","Devis normalisé","RAC zéro","30€"]},
  {id:"ol_mkt9",prompt:"La fidélisation client en optique est stratégique car :",choices:["Le marché est peu concurrentiel","Le cycle de renouvellement est long (2-4 ans) — maintenir la relation entre 2 achats est essentiel","Les clients ne changent jamais d'opticien","Le prix est le seul facteur de fidélité"],answer:1,diff:1,explication:"Cycle vie client optique : renouvellement lunettes 2-4 ans, lentilles annuel/biannuel. Stratégies : rappels renouvellement (SMS/email), programme de fidélité, réparations gratuites, newsletter conseils. Coût d'acquisition client >> coût de fidélisation. CRM (Customer Relationship Management) : outil de gestion des données clients.",tags:["Fidélisation","Renouvellement","CRM","Relation client","Cycle client"]},
  {id:"ol_mkt10",prompt:"Le marketing sensoriel en magasin vise à :",choices:["Éliminer les mauvaises odeurs uniquement","Stimuler les 5 sens pour améliorer l'expérience client et favoriser l'achat (parfum, musique, éclairage, tactile)","Signaler les promotions","Attirer les clients depuis la rue"],answer:1,diff:2,explication:"Marketing sensoriel : olfactif (parfum signature → mémorisation, luxe), musical (tempo lent → visite longue → budget ↑), visuel (éclairage chaud/vitrine attractive), tactile (qualité de l'essayage). Ces techniques augmentent le taux de conversion et la durée de visite.",tags:["Marketing sensoriel","Olfactif","Expérience client","Conversion","Atmosphère"]},
];


export const QB_OL_PRISMES_SYS = [
  {id:"ol_ps1",prompt:"Dans un prisme à réflexion totale interne (n=1,5), combien de surfaces optiques numérotées compte-t-on dans l'ordre de traversée ?",choices:["1 dioptre plan","2 surfaces (S1 dioptre + S2 miroir)","3 surfaces (S1 dioptre entrée, S2 miroir, S3 dioptre sortie)","4 surfaces"],answer:2,diff:1,explication:"Un prisme standard comporte 3 surfaces dans l'ordre : S1 = dioptre plan d'entrée (air→verre, n=1→n=1,5) ; S2 = miroir plan de réflexion totale interne ; S3 = dioptre plan de sortie (verre→air, n=1,5→n=1). On 'déroule' le prisme pour les calculs de conjugaison.",tags:["Prisme","Surfaces optiques","ETSO","Réflexion totale"]},
  {id:"ol_ps2",prompt:"Pour un dioptre plan air→verre (n=1 → n=1,5), la formule de conjugaison est :",choices:["SA' = SA","SA' = (n/n') × SA = (2/3) × SA","SA' = (n'/n) × SA = 1,5 × SA","SA' = -SA"],answer:2,diff:2,explication:"Dioptre plan : n/SA = n'/SA' → SA' = (n'/n) × SA. Pour air→verre : n=1, n'=1,5 → SA' = 1,5 × SA. L'image est plus loin de la surface que l'objet (objet semble 'reculé' dans le verre). Pas de grossissement transversal (G=1) pour un dioptre plan.",tags:["Dioptre plan","Conjugaison","Indice","ETSO"]},
  {id:"ol_ps3",prompt:"Pour un dioptre plan verre→air (n=1,5 → n=1), la formule de conjugaison donne :",choices:["SA' = 1,5 × SA","SA' = (2/3) × SA","SA' = -SA","SA' = SA"],answer:1,diff:2,explication:"Dioptre plan verre→air : n=1,5, n'=1 → SA' = (n'/n) × SA = (1/1,5) × SA = (2/3) × SA. L'image se rapproche de la surface. Un objet à 15 mm dans le verre donne une image à 10 mm dans l'air (paraît 'remonter').",tags:["Dioptre plan","Verre vers air","Conjugaison","Indice"]},
  {id:"ol_ps4",prompt:"Pour un miroir plan en milieu d'indice n=1,5 (intérieur du prisme), la formule de conjugaison est :",choices:["SA' = (2/3) × SA","SA' = SA","SA' = -SA (image symétrique par rapport au miroir)","SA' = 1,5 × SA"],answer:2,diff:1,explication:"Miroir plan : SA' = -SA, quelle que soit l'indice du milieu. L'image est symétrique de l'objet par rapport au miroir. Le milieu reste le même avant et après (n=1,5 dans le prisme), donc la formule est identique à celle d'un miroir dans l'air.",tags:["Miroir plan","Conjugaison","Prisme","Symétrie"]},
  {id:"ol_ps5",prompt:"Pour construire graphiquement le faisceau dans un prisme (méthode ETSO), la première étape est :",choices:["Tracer directement les rayons dans l'air","Construire les conjugués antérieurs de l'image finale, surface par surface en remontant de S3 vers S1","Dessiner le prisme en 3D","Calculer le grossissement total du prisme"],answer:1,diff:2,explication:"Méthode de construction : on part de l'image finale P' et on remonte surface par surface (S3 → S2 → S1) pour trouver les conjugués intermédiaires et l'objet réel. On fait ensuite l'image du diaphragme pour trouver le faisceau limitant. Les rayons sont fléchés et coloriés (rouge = espace départ, vert = second espace).",tags:["Prisme","Construction graphique","Conjugués","ETSO","Méthode"]},
  {id:"ol_ps6",prompt:"Dans un oculaire de lunette astronomique réglé pour un œil emmétrope sans accommodation, la relation entre les foyers est :",choices:["F'1 = F1","F'1 = F2 (foyer image de L1 = foyer objet de L2 = Foc)","F'2 = F1","F1 = F2"],answer:1,diff:2,explication:"Dans un oculaire réglé pour l'emmétrope (image à l'infini) : le faisceau ressort parallèle de L2, donc l'objet placé en F2 (foyer objet de L2) sort à l'infini. Or L1 forme l'image de l'objet télescopique en F'1. Pour que ce soit en F2 : F'1 = F2 = Foc. C'est la condition de réglage de l'oculaire.",tags:["Lunette astronomique","Oculaire","Foc","Emmétrope","Conditions de réglage"]},
  {id:"ol_ps7",prompt:"La 'pupille' d'un système optique limite :",choices:["Le champ d'observation (angle de vue)","L'ouverture angulaire du faisceau pour un point sur l'axe (quantité de lumière)","La netteté de l'image","Le grossissement de l'instrument"],answer:1,diff:2,explication:"La pupille (diaphragme d'ouverture) limite l'ouverture angulaire du faisceau pour les points axiatifs → détermine la quantité de lumière collectée. La lucarne (diaphragme de champ) limite l'angle d'observation. L'image de la pupille côté objet = pupille d'entrée ; côté image = pupille de sortie.",tags:["Pupille","Diaphragme ouverture","Systèmes optiques","ETSO"]},
  {id:"ol_ps8",prompt:"La 'lucarne' d'un système optique limite :",choices:["La quantité de lumière (flux)","L'étendue angulaire du champ observable — image du diaphragme de champ côté objet","Le grossissement","L'aberration chromatique"],answer:1,diff:2,explication:"La lucarne d'entrée = image du diaphragme de champ côté objet. Elle détermine l'angle d'observation maximal (champ total). Sa distance angulaire vue depuis la pupille donne les limites de champ. Placer le diaphragme de champ dans un plan image intermédiaire supprime le champ de contour.",tags:["Lucarne","Diaphragme de champ","Champs","Systèmes optiques"]},
  {id:"ol_ps9",prompt:"Le 'champ de pleine lumière' (PL) est la zone où :",choices:["Aucune lumière ne passe","Chaque point reçoit 100 % du flux — le faisceau passe entièrement à travers tous les diaphragmes","Seuls quelques rayons passent","L'éclairement vaut 50 % du maximum"],answer:1,diff:2,explication:"Champ de pleine lumière (PL) : zone angulaire où chaque point objet envoie un faisceau qui traverse COMPLÈTEMENT tous les diaphragmes → éclairement = 100 %. Champ total (T) : au moins un rayon passe. Champ de contour : zone entre PL et T (0 < E < 100 %) — floue et moins éclairée.",tags:["Champ de pleine lumière","Vignettage","Éclairement","ETSO"]},
  {id:"ol_ps10",prompt:"Pour supprimer le champ de contour (zone de vignettage) dans un oculaire, on place un diaphragme de champ [Dc] :",choices:["N'importe où dans le système","Dans le plan image intermédiaire (plan focal image de L1 = plan focal objet de L2)","Sur la lentille L2","En dehors de l'oculaire"],answer:1,diff:3,explication:"Placer [Dc] dans le plan image intermédiaire (F'1 = F2 = Foc) donne une limite de champ nette (le diaphragme est 'en focus'). Le champ de contour disparaît : le champ total = champ de pleine lumière. L'image du diaphragme est nette sur la rétine, donnant une bordure franche du champ.",tags:["Diaphragme de champ","Champ de contour","Oculaire","Plan intermédiaire"]},
  {id:"ol_ps11",prompt:"L'éclairement relatif d'un point bord de champ par rapport à un point axial (pour un faisceau circulaire vignetté) est proportionnel à :",choices:["d_utile / d_max","(d_utile / d_max)²","d_max - d_utile","1 / d_utile"],answer:1,diff:3,explication:"Section = aire = π×r². Éclairement ∝ section utile ∝ r². Donc : E% = (d_utile / d_max)² × 100. Si la section utile a un diamètre moitié de la section maximale, l'éclairement est (1/2)² = 1/4 = 25%. Ce calcul est demandé dans les exercices 'Doublet section' (ETSO).",tags:["Éclairement","Section faisceau","Vignettage","ETSO","Calcul"]},
  {id:"ol_ps12",prompt:"Dans un prisme déroulé, les espaces optiques sont :",choices:["Tous à n=1,5 (verre partout)","Espaces 1 et 3 : n=1 (air) ; Espace 2 : n=1,5 (verre entre S1 et S3)","Tous à n=1 (air)","Espace 1 : n=1,5 ; Espaces 2 et 3 : n=1"],answer:1,diff:1,explication:"Dans le prisme déroulé pour les calculs : Espace 1 = avant S1 = air (n=1) ; Espace 2 = entre S1 et S3 (verre, n=1,5), contenant S2 (miroir) ; Espace 3 = après S3 = air (n=1). Les espaces géométriques ne correspondent pas toujours aux espaces optiques (le miroir S2 est dans l'espace 2).",tags:["Prisme","Espaces optiques","Indices","Déroulé"]},
];

export const QB_OL_PARCOURS_ACC = [
  {id:"ol_pa1",prompt:"Le ponctum remotum (R) d'un œil est défini comme :",choices:["Le point le plus proche vu net en accommodant à fond","Le conjugué objet de la rétine par l'œil NON ACCOMMODÉ (repos accommodatif)","Le point à 25 cm par convention","Le foyer image de la cornée"],answer:1,diff:1,explication:"Ponctum remotum (R) = conjugué objet de la rétine par l'œil au repos (accommodation = 0 δ). Sa position donne la réfraction R = 1/HR_barre. Emmétrope : R à l'infini (R=0 δ). Myope : R en espace objet réel (R<0). Hypermétrope : R en espace objet virtuel (R>0).",tags:["Ponctum remotum","Réfraction","Parcours accommodatif","R"]},
  {id:"ol_pa2",prompt:"La réfraction axiale R (en dioptries) d'un œil dont le ponctum remotum est à 40 cm en avant de H est :",choices:["+2,50 δ","-2,50 δ","+0,40 δ","-0,40 δ"],answer:1,diff:1,explication:"R = 1/HR_barre. HR_barre = -0,40 m (en avant de H = espace objet réel = signe négatif). R = 1/(-0,40) = -2,50 δ. Signe négatif = myope. La correction à mettre en lunettes est -2,50 δ (verre divergent).",tags:["Réfraction","Calcul","Myopie","Formule","Parcours accommodatif"]},
  {id:"ol_pa3",prompt:"La formule de l'amplitude accommodative maximale (pour un sujet de moins de 55 ans) est :",choices:["Amax = âge / 4","Amax = 15 - âge/4","Amax = 20 - âge/2","Amax = 10 - âge/5"],answer:1,diff:1,explication:"Formule d'amplitude accommodative : Amax = 15 - age/4 (exprimée en dioptries, valable pour moins de 55 ans). Exemples : 20 ans → Amax = 15 - 5 = 10 δ ; 40 ans → 15 - 10 = 5 δ ; 60 ans → valeur fixe = 1 δ. Diminue avec la rigidification du cristallin.",tags:["Accommodation","Amplitude","Âge","Formule","Presbytie"]},
  {id:"ol_pa4",prompt:"Pour un œil de réfraction R = -2,00 δ et un sujet de 24 ans, quelle est la proximité du ponctum proximum (P) ?",choices:["-2,00 δ","-11,00 δ","-10,00 δ","+9,00 δ"],answer:1,diff:2,explication:"Amax = 15 - 24/4 = 15 - 6 = 9 δ. P = R - Amax = -2,00 - 9,00 = -11,00 δ. Le ponctum proximum est à HP = 1/(-11) ≈ -91 mm (9,1 cm en avant de H). Le signe négatif indique l'espace objet réel.",tags:["Ponctum proximum","Calcul","Accommodation","Myopie"]},
  {id:"ol_pa5",prompt:"L'accommodation confortable (Aconf) est définie comme :",choices:["La totalité de l'amplitude accommodative","La moitié de l'amplitude maximale (Aconf = Amax / 2)","Un tiers de l'amplitude maximale","0 (l'accommodation confortable est nulle)"],answer:1,diff:1,explication:"Aconf = Amax / 2. C'est la limite au-delà de laquelle l'accommodation devient fatigante (asthénopie : maux de tête, yeux qui brûlent/piquent/tirent). La zone entre R et C est la zone de vision confortable ; entre C et P, la vision est possible mais inconfortable.",tags:["Accommodation confortable","Aconf","Asthénopie","Parcours accommodatif"]},
  {id:"ol_pa6",prompt:"Un patient se plaint de maux de tête et d'yeux qui piquent en lisant, mais voit net. Dans quelle zone du parcours accommodatif se situe sa distance de lecture ?",choices:["Hors parcours (au-delà de R)","Dans la zone confortable (entre R et C)","Dans la zone inconfortable (entre C et P)","Au niveau du ponctum remotum"],answer:2,diff:2,explication:"Vision nette mais inconfortable = l'objet est dans la zone entre C (point de confort) et P (proximum), soit Aconf < A utilisée ≤ Amax. Le patient voit net car il est dans le parcours accommodatif, mais dépasse son seuil de confort → plaintes asthénopiques (maux de tête, yeux piquent/tirent/brûlent).",tags:["Asthénopie","Zone inconfortable","Parcours accommodatif","Confort"]},
  {id:"ol_pa7",prompt:"Un hypermétrope a R = +2,00 δ. Où se situe son ponctum remotum ?",choices:["En espace objet réel, 50 cm en avant de H","En espace objet virtuel, 50 cm derrière H (HR = +0,50 m)","À l'infini","En espace image"],answer:1,diff:2,explication:"R = +2,00 δ → HR = 1/R = 1/2 = +0,50 m. Signe positif = espace objet VIRTUEL (derrière H, dans le sens de propagation de la lumière). Ce R virtuel signifie qu'aucun objet réel ne peut être vu net sans accommodation chez cet hypermétrope. Il accommode en permanence, même de loin.",tags:["Hypermétropie","Ponctum remotum","Espace virtuel","Parcours accommodatif"]},
  {id:"ol_pa8",prompt:"La proximité du ponctum proximum P s'exprime en dioptries. Sa valeur pour un emmétrope de 30 ans est :",choices:["0 δ","-7,50 δ","+7,50 δ","-15 δ"],answer:1,diff:2,explication:"Emmétrope : R = 0 δ. Amax = 15 - 30/4 = 15 - 7,5 = 7,5 δ. P = R - Amax = 0 - 7,5 = -7,5 δ. HP = 1/(-7,5) ≈ -0,133 m ≈ -13,3 cm. L'emmétrope de 30 ans voit net jusqu'à 13,3 cm, ce qui est normal et confortable pour la lecture.",tags:["Emmétrope","Ponctum proximum","Calcul","Accommodation"]},
  {id:"ol_pa9",prompt:"Lors de l'analyse du parcours accommodatif, la représentation sur un axe (de gauche à droite) place pour un myope de R = -3 δ :",choices:["R à droite de H (espace virtuel), C et P à gauche","R, C et P tous à l'infini","R, C, P tous dans l'espace objet réel (à gauche de H), P plus proche que R","R à l'infini, C et P à gauche"],answer:2,diff:2,explication:"Myope R = -3 δ : HR = 1/(-3) = -0,33 m = -33 cm (espace objet réel, à gauche de H). C et P sont encore plus à gauche (négatifs, plus grandes valeurs en valeur absolue). Sur l'axe : de gauche à droite = P, C, R, H. La zone de vision confortable s'étend de C à R (environ 33 cm à l'infini du myope non corrigé).",tags:["Myopie","Représentation","Parcours accommodatif","Axe"]},
  {id:"ol_pa10",prompt:"Pour un hypermétrope R = +1,50 δ et Amax = 6 δ, quel est le point de confort C ?",choices:["C = -1,50 δ (HC = -0,67 m = -67 cm)","C = +1,50 δ","C = -0,75 δ","C = +4,50 δ"],answer:0,diff:3,explication:"Aconf = Amax/2 = 3 δ. C = R - Aconf = +1,50 - 3,00 = -1,50 δ. HC = 1/(-1,50) = -0,67 m = -67 cm. Ce patient voit confortablement de -67 cm (espace réel) jusqu'à +333 mm (espace virtuel = loin sans lunettes mais avec accommodation). Au-delà de C vers P, la vision est fatigante.",tags:["Hypermétropie","Point de confort","Calcul","Parcours accommodatif"]},
  {id:"ol_pa11",prompt:"L'asthénopie accommodative (fatigue oculaire) se manifeste typiquement par :",choices:["Une vision floue permanente à toute distance","Des maux de tête, sensation de brûlure, larmoiement, vision trouble en fin de journée — après effort accommodation prolongé","Une diplopie binoculaire constante","Une perte de sensibilité aux couleurs"],answer:1,diff:1,explication:"Asthénopie accommodative : faisceau de symptômes suite à un effort accommodatif excessif prolongé : céphalées (souvent frontales), picotements/brûlures oculaires, larmoiement, vision floue en fin de journée, difficulté à maintenir la mise au point. Cause fréquente : hypermétropie non ou sous-corrigée, parcours de confort insuffisant pour la distance de travail.",tags:["Asthénopie","Accommodation","Symptômes","Hypermétropie","Fatigue oculaire"]},
  {id:"ol_pa12",prompt:"Pour un sujet de 55 ans et plus, l'amplitude maximale utilisée pour les calculs du parcours est :",choices:["Calculée selon Amax = 15 - age/4","1,00 δ (valeur fixe conventionnelle)","0 δ (aucune accommodation)","3,00 δ (valeur fixe)"],answer:1,diff:2,explication:"Pour les sujets de 55 ans et plus, la formule Amax = 15 - age/4 donnerait des valeurs négatives ou nulles. Par convention, on utilise Amax = 1,00 δ. Cela représente la faible accommodation résiduelle chez le presbyte confirmé. Le PP s'approche ainsi de HR = 1/P = 1/(R-1).",tags:["Presbytie","Amplitude","55 ans","Conventions","Calcul"]},
];

export const QB_OL_GESTION_JUR = [
  {id:"ol_gj1",prompt:"Un contrat de travail est valide s'il réunit trois éléments cumulatifs :",choices:["Signature, durée et salaire","Prestation de travail + lien de subordination + rémunération","Diplôme, expérience et âge minimum","CDD, CDI ou intérim"],answer:1,diff:1,explication:"Le contrat de travail implique : 1) une prestation de travail (fourniture d'un service) ; 2) un lien de subordination (l'employeur dirige, réglemente et sanctionne) ; 3) une rémunération. Ces 3 éléments sont cumulatifs et indispensables pour qualifier juridiquement un contrat de travail.",tags:["Contrat de travail","Lien de subordination","Éléments constitutifs","Droit du travail"]},
  {id:"ol_gj2",prompt:"L'indemnité de précarité d'un CDD ou d'une mission d'intérim est de :",choices:["5 % du salaire brut","10 % de la rémunération totale brute (art. L.1243-8)","15 % du dernier salaire","Aucune indemnité n'est prévue"],answer:1,diff:1,explication:"À la fin d'un CDD ou d'une mission d'intérim, le salarié perçoit une indemnité de précarité = 10 % de la rémunération totale brute versée (art. L.1243-8 Code du Travail). Elle compense l'instabilité de l'emploi temporaire. Exceptions : rupture pour faute grave, refus de CDI, contrat d'apprentissage.",tags:["CDD","Intérim","Indemnité de précarité","10%","Droit du travail"]},
  {id:"ol_gj3",prompt:"La clause de non-concurrence dans un contrat de travail est valide si elle respecte 5 conditions. Laquelle est souvent oubliée ?",choices:["Être écrite en français","Prévoir une contrepartie financière obligatoire (30-50% du dernier salaire)","Être mentionnée dans la convention collective","Dépasser 3 ans de durée"],answer:1,diff:2,explication:"Les 5 conditions cumulatives de validité : 1) Protection d'intérêts légitimes ; 2) Limite dans le temps (6 mois à 2 ans max) ; 3) Limite géographique ; 4) Ne pas empêcher le salarié de retrouver un emploi ; 5) Contrepartie financière (30-50% du dernier salaire). La contrepartie est la condition la plus souvent omise — sans elle, la clause est nulle.",tags:["Non-concurrence","Contrat de travail","Contrepartie financière","Validité"]},
  {id:"ol_gj4",prompt:"La rupture conventionnelle d'un CDI (accord mutuel) donne droit au salarié :",choices:["Ni aux allocations chômage, ni à une indemnité","Aux allocations chômage (Pôle Emploi) ET à une indemnité de rupture conventionnelle (au moins égale à l'indemnité légale de licenciement)","Uniquement à une indemnité sans allocations chômage","Uniquement aux allocations chômage sans indemnité"],answer:1,diff:1,explication:"La rupture conventionnelle (accord mutuel homologué par la DREETS/DIRECCTE) : le salarié perçoit une indemnité de rupture ≥ indemnité légale de licenciement ET peut bénéficier des allocations chômage. C'est l'un de ses avantages majeurs par rapport à la démission (qui ne donne pas droit au chômage).",tags:["Rupture conventionnelle","Chômage","Indemnité","CDI","DREETS"]},
  {id:"ol_gj5",prompt:"Dans une SARL, le régime social du gérant majoritaire est :",choices:["Assimilé salarié (régime général)","Travailleur Non Salarié (TNS) — Sécurité Sociale des Indépendants","Salarié de droit commun","Aucune protection sociale"],answer:1,diff:2,explication:"SARL : gérant majoritaire (>50% des parts) → TNS (Travailleur Non Salarié), affilié à la Sécurité Sociale des Indépendants (ex-RSI). Cotisations plus faibles mais protection moindre (pas d'assurance chômage). Gérant minoritaire ou égalitaire → assimilé salarié (régime général).",tags:["SARL","Gérant majoritaire","TNS","Régime social","Statuts juridiques"]},
  {id:"ol_gj6",prompt:"Dans une SAS/SASU, le Président est :",choices:["Travailleur Non Salarié (TNS)","Assimilé salarié — cotise au régime général de la Sécurité sociale","Salarié de droit commun (avec prud'hommes)","Non protégé socialement"],answer:1,diff:2,explication:"SAS/SASU : le Président est assimilé salarié → cotise au régime général (mêmes droits que les salariés sauf assurance chômage). Cotisations patronales + salariales plus élevées que le TNS mais meilleure protection sociale. Grande flexibilité statutaire. Forme adaptée si investisseurs ou réseau multi-magasins.",tags:["SAS","SASU","Président","Assimilé salarié","Régime général"]},
  {id:"ol_gj7",prompt:"Pourquoi l'entreprise individuelle (EI) est-elle fortement déconseillée pour un magasin d'optique ?",choices:["Elle est trop compliquée à créer","La responsabilité est illimitée — en cas de dettes, les biens personnels (maison, épargne) peuvent être saisis","Elle impose un capital minimum de 50 000 €","Elle est interdite aux opticiens par le CSP"],answer:1,diff:1,explication:"EI : le patrimoine professionnel et personnel se confondent. En cas de difficultés financières, les créanciers peuvent saisir les biens personnels de l'opticien (immobilier, comptes bancaires perso). EURL ou SASU offrent une responsabilité limitée aux apports, protégeant le patrimoine personnel. L'EI reste adaptée uniquement aux très petites activités à risque limité.",tags:["Entreprise individuelle","Responsabilité illimitée","Patrimoine","Risque","Statuts juridiques"]},
  {id:"ol_gj8",prompt:"Le fonds de commerce d'un magasin d'optique est juridiquement :",choices:["Un bien immobilier (les murs du local)","Un bien meuble incorporel regroupant les éléments permettant l'exploitation et l'attractivité de la clientèle","Un contrat de bail uniquement","Un titre de propriété du local"],answer:1,diff:1,explication:"Le fonds de commerce est un bien meuble incorporel — distinct des murs (bien immobilier). Il comprend : clientèle + achalandage (50-80% de la valeur), nom commercial, droit au bail, licences/autorisations, contrats fournisseurs, matériel, stocks. Il est cessible indépendamment du local (bâtiment). La clientèle est l'élément essentiel.",tags:["Fonds de commerce","Bien meuble incorporel","Clientèle","Cession","Optique"]},
  {id:"ol_gj9",prompt:"Parmi les méthodes d'évaluation d'un fonds de commerce, laquelle est considérée comme la plus fiable en optique ?",choices:["La méthode patrimoniale (valeur des stocks + matériel)","La méthode par multiple de l'EBE (Excédent Brut d'Exploitation)","La méthode par le chiffre d'affaires uniquement","L'estimation par le coût de remplacement du matériel"],answer:1,diff:2,explication:"La méthode par l'EBE est la plus fiable car l'EBE reflète la performance économique réelle de l'entreprise (avant investissements et charges financières). Le multiple standard est de 3 à 5 fois l'EBE annuel. La méthode par % du CA est rapide mais moins précise car elle ne tient pas compte de la rentabilité réelle.",tags:["Fonds de commerce","EBE","Évaluation","Méthodes","Reprise magasin"]},
  {id:"ol_gj10",prompt:"Lors d'une cession de fonds de commerce, la publication dans un journal d'annonces légales est obligatoire :",choices:["Avant la signature de la promesse de vente","15 jours après la signature de l'acte de vente (pour protéger les créanciers)","Uniquement si le fonds vaut plus de 100 000 €","Uniquement pour les cessions entre non-membres de la famille"],answer:1,diff:2,explication:"La publicité légale (journal d'annonces légales + BODACC) dans les 15 jours suivant la vente est OBLIGATOIRE. Elle informe les créanciers de l'ancien propriétaire, qui peuvent faire opposition sur le prix de vente. Une inscription modificative au RCS (greffe du tribunal de commerce) dans le mois suivant est également obligatoire.",tags:["Fonds de commerce","Journal d'annonces légales","Publicité légale","Cession","Créanciers"]},
  {id:"ol_gj11",prompt:"Le droit au bail (élément du fonds de commerce) correspond à :",choices:["La propriété des murs du local","Le droit du locataire de céder son bail commercial avec le fonds — élément incorporel transférable lors de la cession","Le contrat de location signé avec le propriétaire uniquement","La garantie bancaire du bail"],answer:1,diff:2,explication:"Le droit au bail est la valeur économique attachée au bail commercial (droit de jouissance du local). Il est cessible avec le fonds de commerce. Sa valeur dépend de l'emplacement, du loyer (si inférieur au marché), de la durée restante. Attention : vérifier la durée restante, les clauses de cession et le montant du loyer lors d'une reprise.",tags:["Droit au bail","Bail commercial","Fonds de commerce","Élément incorporel","Cession"]},
  {id:"ol_gj12",prompt:"Pour ouvrir un magasin d'optique, parmi les autorisations obligatoires figure :",choices:["Une licence commerciale délivrée par la mairie","L'enregistrement à l'ARS (Agence Régionale de Santé) comme condition sine qua non pour exercer légalement","Un agrément de l'Assurance Maladie uniquement","Une certification ISO 9001 obligatoire"],answer:1,diff:1,explication:"L'opticien doit obligatoirement : 1) Posséder le diplôme d'opticien-lunetier (ou employer un diplômé) 2) Enregistrer le diplôme à l'ARS et s'immatriculer (L4362-3 CSP) 3) S'immatriculer au RCS. L'enregistrement à l'ARS est indispensable — sans lui, l'exercice est illégal. Des normes d'accessibilité et d'hygiène s'appliquent également au local.",tags:["ARS","Ouverture magasin","Autorisation","CSP","Opticien-lunetier"]},
];



export const QB_OL_CHAMPS = [
  {id:"ol_ch1",prompt:"La 'pupille' [P] dans l'étude des champs (ETSO) est le diaphragme vu sous :",choices:["L'angle βmini depuis le centre de la lucarne","L'angle αmini depuis le centre du plan des champs (diaphragme le plus restrictif en ouverture)","Le plus grand angle depuis l'objet","Aucune notion d'angle — c'est le plus grand diaphragme"],answer:1,diff:2,explication:"Pupille [P] = diaphragme vu sous le plus petit angle αmini depuis le CENTRE DU PLAN DES CHAMPS. Elle limite l'ouverture angulaire du faisceau axial → détermine la quantité de lumière. À ne pas confondre avec la lucarne (βmini depuis le centre de la pupille → limite le champ).",tags:["Étude des champs","Pupille","Angle","ETSO","Optique instrumentale"]},
  {id:"ol_ch2",prompt:"La 'lucarne' [L] dans l'étude des champs est le diaphragme vu sous :",choices:["L'angle αmini depuis le plan des champs","L'angle βmini depuis le centre de la pupille [P] (diaphragme limitant l'étendue du champ)","L'angle le plus grand depuis la pupille","Le diamètre apparent le plus grand depuis l'objet"],answer:1,diff:2,explication:"Lucarne [L] = diaphragme vu sous le plus petit angle βmini depuis le CENTRE DE LA PUPILLE. C'est le diaphragme de champ — il limite l'étendue angulaire de l'image observable. Le rayon vers le bord de la lucarne donne le demi-champ moyen M.",tags:["Étude des champs","Lucarne","Champ","Angle","ETSO"]},
  {id:"ol_ch3",prompt:"La règle fondamentale pour comparer les diaphragmes dans l'étude des champs est :",choices:["Comparer tous les diaphragmes quelle que soit leur position","Les diaphragmes comparés doivent appartenir au MÊME espace optique — sinon, les conjuguer d'abord","Toujours travailler dans l'espace objet","Utiliser les plans principaux comme référence"],answer:1,diff:2,explication:"Règle d'or ETSO : pour comparer des diaphragmes et trouver pupille/lucarne, ils doivent être dans le MÊME espace (objet ou image). Si un diaphragme est dans un autre espace, on calcule son image (conjugué) dans l'espace voulu avant toute comparaison angulaire.",tags:["Étude des champs","Règle d'or","Espaces optiques","ETSO","Conjugaison"]},
  {id:"ol_ch4",prompt:"La relation de taille obligatoire entre les 3 champs (vérification à faire systématiquement) est :",choices:["ØT ≤ ØM ≤ ØPL","ØPL ≤ ØM ≤ ØT (champ de pleine lumière ≤ champ moyen ≤ champ total)","ØM = ØPL = ØT","Aucune relation obligatoire"],answer:1,diff:1,explication:"Relation obligatoire à toujours vérifier : ØPL ≤ ØM ≤ ØT. PL = 100% d'éclairement (le plus petit) ; T = 0% (le plus grand) ; M = ~50%. Si cette relation n'est pas respectée, il y a une erreur de construction ou de calcul.",tags:["Étude des champs","PL","Champ total","Champ moyen","Vérification"]},
  {id:"ol_ch5",prompt:"Le champ de contour (entre PL et T) dans un système optique est caractérisé par :",choices:["Une image plus floue que le champ de pleine lumière","Un assombrissement progressif (vignettage) — l'image est moins contrastée mais PAS plus floue","Une absence totale de lumière","Une résolution améliorée"],answer:1,diff:2,explication:"Champ de contour = zone entre PL (100%) et T (0%) → vignettage progressif. L'image n'est PAS plus floue (la géométrie reste correcte pour les rayons qui passent) mais elle est moins bien éclairée → moins contrastée et moins détaillée. Pour supprimer ce défaut : placer un diaphragme réel sur le plan image intermédiaire.",tags:["Champ de contour","Vignettage","ETSO","Image","Contraste"]},
  {id:"ol_ch6",prompt:"Pour supprimer le champ de contour dans un système optique, on place un diaphragme de champ [Dc] :",choices:["N'importe où dans le système","Sur un plan image intermédiaire RÉEL, à la taille du champ de pleine lumière PL","Sur la pupille de sortie","En amont du système optique"],answer:1,diff:2,explication:"Placer [Dc] sur un plan intermédiaire réel (où l'image est nette) donne une limite de champ NETTE car le diaphragme est conjugué de l'objet → son image sur la rétine est nette. Le champ de contour disparaît : champ total = champ de pleine lumière. Le diamètre de [Dc] = diamètre PL dans ce plan.",tags:["Diaphragme de champ","Champ de contour","Plan intermédiaire","ETSO","Optique instrumentale"]},
  {id:"ol_ch7",prompt:"En vue de gauche (section transversale), le champ de pleine lumière (PL) apparaît comme :",choices:["Un point sur l'axe","Une surface (disque) à colorier — représente la section du faisceau à 100% d'éclairement","Une ligne droite","Une ellipse"],answer:1,diff:2,explication:"Vue de gauche (vue transversale) : les champs sont représentés en vraie grandeur. PL = surface (disque) à colorier/remplir (100% d'éclairement = toute la section du faisceau utile). T et M = anneaux/lignes. La vue de gauche permet de coter les diamètres réels des champs.",tags:["Étude des champs","Vue de gauche","PL","Section","ETSO"]},
  {id:"ol_ch8",prompt:"Dans l'étude des champs d'une lunette astronomique, le plan des champs intermédiaire est situé :",choices:["Sur l'objectif","Au plan focal image de l'objectif = foyer objet de l'oculaire (F'obj = Foc)","Sur l'oculaire","Dans l'espace de l'observateur"],answer:1,diff:2,explication:"Dans une lunette astronomique, le plan image intermédiaire réel est en F'obj = Foc (foyer image de l'objectif = foyer objet de l'oculaire). C'est le seul plan où l'image est réelle et nette entre objectif et oculaire → plan privilégié pour placer le diaphragme de champ [Dc] afin d'éliminer le champ de contour.",tags:["Lunette astronomique","Champs","Plan intermédiaire","F'obj","Foc"]},
  {id:"ol_ch9",prompt:"Le champ moyen (M) dans un système optique correspond à :",choices:["Le champ où l'éclairement est maximal (100%)","La limite médiane entre PL et T — définie par le faisceau de demi-ouverture (rayon vers le bord de la lucarne), environ 50% d'éclairement","Le champ hors duquel il n'y a aucune lumière","Le diamètre de la pupille de sortie"],answer:1,diff:2,explication:"Champ moyen M = délimité par le faisceau de demi-ouverture (qui passe par le bord de la lucarne). C'est la limite entre le champ 'confortable' (proche de PL) et le champ 'dégradé' (proche de T). Relation : ØPL < ØM < ØT. Tracé avec un rayon passant par le bord de [L] et un rayon libre.",tags:["Champ moyen","Demi-ouverture","Lucarne","ETSO","Éclairement"]},
  {id:"ol_ch10",prompt:"Le plan des champs dans lequel on réalise l'étude est préférentiellement :",choices:["Toujours dans l'espace objet","Toujours dans l'espace image","L'espace où les conjugués des objets étudiés sont plus accessibles — souvent l'espace image final si objet à l'infini","L'espace du milieu du système"],answer:2,diff:2,explication:"On choisit l'espace le plus pratique. Pour un objet à l'infini (lunette, télescope), l'image intermédiaire est dans l'espace entre objectif et oculaire → étude des champs dans cet espace intermédiaire. Pour un objet fini, on peut rester dans l'espace objet si les conjugués sont accessibles.",tags:["Étude des champs","Plan des champs","Choix espace","ETSO","Objet infini"]},
  {id:"ol_ch11",prompt:"Le grossissement angulaire d'une lunette astronomique (G = α'/α) est égal à :",choices:["f'oc / f'obj","f'obj / f'oc (focale objectif / focale oculaire)","Diamètre objectif / diamètre oculaire","(f'obj + f'oc) / f'oc"],answer:1,diff:1,explication:"G = f'obj / f'oc. Pour augmenter G : augmenter f'obj (objectif à longue focale) ou diminuer f'oc (changer d'oculaire). Réglage dioptrique : déplacement axial de l'oculaire (+ vers H→ compense hypermétropie ; - vers H → compense myopie).",tags:["Lunette astronomique","Grossissement","Focale","Instruments optiques"]},
  {id:"ol_ch12",prompt:"Pour une lunette astronomique avec système pignon-crémaillère de rayon primitif Rp = 5 mm, le déplacement pour 1 tour de pignon est :",choices:["5 mm","2π × 5 ≈ 31,4 mm","5/2π ≈ 0,8 mm","π × 5 = 15,7 mm"],answer:1,diff:3,explication:"Système pignon-crémaillère : pour 1 tour du pignon, le déplacement = périmètre du cercle primitif = 2πRp = 2 × π × 5 ≈ 31,4 mm. Formule générale : d = 2πRp × n (n = nombre de tours). Système vis-écrou (mise au point fine) : d = n × pas du filet.",tags:["Lunette astronomique","Pignon-crémaillère","Mécanisme","Mise au point","Calcul"]},
];

export const QB_OL_CE_DF = [
  {id:"ol_df1",prompt:"Lors du contrôle d'un verre double-foyer Essilor CT28, l'écart pupillaire est mesuré :",choices:["En VL (vision de loin) à la croix principale","En VP (vision de près) à la MOITIÉ de la pastille (spécificité Essilor)","En VL à l'aide d'une règle de Ditest","En vision intermédiaire"],answer:1,diff:2,explication:"CT28 Essilor : mesure de l'écart en VP (vision de près) à la moitié de la pastille. Pour la mesure du prisme compensateur : se fait en VL (+5 en horizontal / +2,5 mm en temporal par rapport à la mesure VP). C'est une spécificité Essilor — à différencier du Rodenstock qui mesure l'écart en VL.",tags:["Contrôle équipement","Double-foyer","CT28","Essilor","VP","Mesure écart"]},
  {id:"ol_df2",prompt:"La différence principale entre l'Essilor CT28 (organique) et l'Essilor Telarc 28 (minéral) lors du contrôle est :",choices:["Le Telarc est plus épais","Au toucher, le CT28 présente une boursouflure à la jonction VL/VP (organique) — le Telarc ne présente pas de différence d'épaisseur (pastille fusionnée, minéral)","Le Telarc a une taille de pastille plus grande","Le CT28 n'a pas de prisme"],answer:1,diff:2,explication:"CT28 organique : la pastille est collée/surmoulée → différence d'épaisseur détectable au toucher à la jonction VL-VP. Telarc 28 minéral : pastille fusionnée dans la masse → surface continue sans boursouflure. Même géométrie (pastille 28 mm, décentrement 2,5 mm temporal, hauteur 18-19 mm).",tags:["Contrôle équipement","CT28","Telarc 28","Minéral","Organique","Double-foyer"]},
  {id:"ol_df3",prompt:"Pour le Rodenstock Trilentar 28, la hauteur de pastille (mesurée du bas du calibre à la tangente inférieure de la pastille) est de :",choices:["19 mm (identique au CT28)","14 mm (différent d'Essilor : 18-19 mm)","22 mm","8 mm"],answer:1,diff:2,explication:"Rodenstock Trilentar 28 : hauteur pastille = 14 mm. Essilor CT28 : 18 mm. Essilor Telarc : 19 mm. Cette différence est critique lors du contrôle : confondre les hauteurs peut entraîner une adaptation incorrecte. Le Trilentar a aussi une mesure d'écart en VL (≠ Essilor en VP) et un écart de prisme de +2 en H (≠ Essilor +5 en H).",tags:["Rodenstock","Trilentar 28","Hauteur pastille","14mm","Contrôle équipement"]},
  {id:"ol_df4",prompt:"La différence de mesure du prisme compensateur entre l'Essilor CT28 et le Rodenstock Trilentar est :",choices:["CT28 : prisme mesuré en VP ; Trilentar : en VP aussi","CT28 : en VL à +5 H / +2,5 temporal depuis VP ; Trilentar : en VL à +2 H / +2,5 temporal depuis VP","Aucune différence","CT28 : en VP ; Trilentar : en vision intermédiaire"],answer:1,diff:3,explication:"Essilor CT28 : prisme compensateur mesuré en VL, décalé de +5 en horizontal ET +2,5 mm en temporal par rapport à la position VP. Rodenstock Trilentar : décalé de +2 en horizontal ET +2,5 mm en temporal. Les 2,5 mm temporaux sont communs, mais le décalage horizontal diffère (+5 vs +2).",tags:["Contrôle équipement","Prisme compensateur","CT28","Trilentar","Mesure"]},
  {id:"ol_df5",prompt:"Lors du contrôle d'équipement de verres double-foyers, 'oublier de cocher les cases de conformité' entraîne :",choices:["Une pénalité partielle","Zéro à l'épreuve entière (règle stricte de l'examen BTS OL)","Un avertissement uniquement","Une note abaissée de 2 points"],answer:1,diff:1,explication:"Règle stricte du contrôle d'équipement BTS OL : oublier une case de conformité = zéro à la totalité de cette case. Une seule erreur dans une case de conformité = zéro. Il faut donc cocher systématiquement 'oui' ou 'non' pour CHAQUE critère, même si le verre semble correct.",tags:["Contrôle équipement","BTS OL","Conformité","Règles examen"]},
  {id:"ol_df6",prompt:"L'ADD (addition) d'un verre double-foyer se calcule et se commande comme suit :",choices:["On prescrit directement l'ADD en dioptries","On commande la VL ; l'ADD se calcule : ADD = VP − VL (mesurées au frontofocusmètre avant taillage)","On prescrit VP uniquement","On commande en donnant la puissance VP directement"],answer:1,diff:2,explication:"Double-foyer (CT28, Telarc) : commande au laboratoire = vergence VL prescrite. L'ADD est calculée : ADD = VP − VL. Le laboratoire fabrique le verre avec la VL demandée et ajoute l'ADD. Après montage et taillage, on vérifie la VL au frontofocusmètre en zone VL et la VP en zone pastille.",tags:["Double-foyer","ADD","Commande","Frontofocusmètre","Formule"]},
  {id:"ol_df7",prompt:"L'Essilor Telex est un verre double-foyer particulier pour lequel :",choices:["La zone VP couvre la totalité du verre (lire de loin aussi bien que de près)","La zone VP est intégrale — l'écart VL est pointé au frontofocusmètre — impossible de retrouver les centrages par géométrie une fois le verre taillé","La pastille fait 35 mm de diamètre","Le décentrement est de 5 mm"],answer:1,diff:2,explication:"Essilor Telex : verre à zone VP intégrale (toute la surface VP). Particularité : une fois le verre taillé dans la monture, on ne peut plus retrouver les centrages géométriquement. L'écart VL doit être pointé au frontofocusmètre avant taillage. Spécificité importante pour le contrôle.",tags:["Telex","Essilor","Double-foyer","Taillage","Centrage"]},
  {id:"ol_df8",prompt:"L'Essilor Telemil 28 (verre double-foyer) présente une pastille avec un décentrement de :",choices:["2,5 mm temporal","10° (angulaire, différent des autres modèles en mm)","5 mm nasal","0 mm (centré)"],answer:1,diff:2,explication:"Essilor Telemil 28 : particularité = décentrement angulaire de 10° (et non en mm comme le CT28/Telarc). Hauteur pastille : 5 mm (très basse, différent des autres modèles). Mesure écart : en VL avec règle de Ditest. Ces spécificités le différencient nettement des autres verres double-foyers.",tags:["Telemil","Essilor","Double-foyer","Décentrement","10 degrés"]},
  {id:"ol_df9",prompt:"Pour vérifier l'horizontalité des pastilles VP d'un montage double-foyer, on utilise :",choices:["Le frontofocusmètre uniquement","La règle pantoscopique","La vérification visuelle de l'horizontalité des tangentes supérieures des pastilles (les deux pastilles doivent être au même niveau dans la monture)","Le pachymètre"],answer:2,diff:2,explication:"L'horizontalité des pastilles VP est un critère critique du contrôle d'équipement double-foyer. On vérifie que les tangentes supérieures des deux pastilles sont parallèles et au même niveau dans la monture. Une pastille inclinée crée un effet prismatique vertical gênant en VP.",tags:["Contrôle équipement","Horizontalité","Pastille VP","Double-foyer","Critère"]},
  {id:"ol_df10",prompt:"La hauteur de montage d'un verre double-foyer est mesurée :",choices:["Du centre pupillaire au centre de la pastille","De la tangente horizontale inférieure du calibre (bas du verre) à la tangente inférieure de la pastille VP","Du bord supérieur du verre au bord supérieur de la pastille","De l'axe de la monture au bord de la pastille"],answer:1,diff:2,explication:"Hauteur double-foyer = distance mesurée de la tangente horizontale inférieure du calibre (bord inférieur du verre) jusqu'à la tangente inférieure de la pastille VP. Cette mesure positionne la pastille par rapport au bas du verre — elle diffère selon le modèle (CT28 : 18 mm, Telarc : 19 mm, Trilentar : 14 mm).",tags:["Double-foyer","Hauteur de montage","Mesure","Calibre","Pastille VP"]},
];

export const QB_OL_CONTROLE_EQ = [
  {id:"ol_ceq1",prompt:"La profondeur de champ augmente quand le diamètre pupillaire :",choices:["Augmente (grande pupille → grande profondeur de champ)","Diminue (petite pupille → grande profondeur de champ, comme un diaphragme en photographie)","Ne change pas — seule la vergence influence la profondeur de champ","Double — la profondeur de champ double aussi"],answer:1,diff:1,explication:"Profondeur de champ ∝ 1/D (D = diamètre pupillaire). Petite pupille (myosis solaire, sénescence) → grande profondeur de champ → masque la presbytie débutante. C'est pourquoi les presbytes plissent les yeux pour lire sans lunettes et pourquoi le soleil 'aide' à voir net de près. Même principe que le diaphragme en photographie.",tags:["Profondeur de champ","Pupille","Presbytie","Contrôle équipement","Myosis"]},
  {id:"ol_ceq2",prompt:"Le contrôle d'équipement d'un verre progressif comprend obligatoirement la vérification de :",choices:["La couleur du verre uniquement","La vergence VL (zone loin), l'ADD (VL puis VP), le centrage (EP, hauteur), le prisme, l'axe du cylindre — avec tolérances ISO 21987","Uniquement la vergence de loin","Uniquement le prisme"],answer:1,diff:2,explication:"Contrôle progressif : 1) Vergence VL en zone loin (centre optique marqué par croix) 2) ADD = V(VP) − V(VL) 3) Centrage : EP correct, hauteur de montage correcte 4) Prisme éventuel 5) Axe du cylindre. Tolérances ISO 21987 : vergence ± 0,09 δ (< 6 δ), ADD ± 0,12 δ, prisme ± 0,09 Δ.",tags:["Contrôle équipement","Progressif","ISO 21987","Frontofocusmètre","ADD"]},
  {id:"ol_ceq3",prompt:"Les gravures permanentes sur un verre progressif permettent de :",choices:["Identifier l'indice du verre","Identifier le modèle, les points de mesure (croix nasale/temporale) et positionner les zones VL/VP pour le contrôle au frontofocusmètre","Mesurer le traitement antireflet","Identifier la marque de la monture"],answer:1,diff:1,explication:"Gravures permanentes des verres progressifs : les fabricants gravent des repères invisibles à l'œil nu (révélés par loupe ou lampe UV) — croix de centrage, cercles indiquant le modèle et l'ADD, points VP et VL. Ces gravures sont indispensables pour positionner le verre correctement au frontofocusmètre lors du contrôle.",tags:["Progressif","Gravures permanentes","Frontofocusmètre","Contrôle","Repères"]},
  {id:"ol_ceq4",prompt:"Pour détecter une inversion des verres OD/OG lors du montage d'une paire de lunettes, on utilise :",choices:["L'œil nu uniquement","Le frontofocusmètre : mesure de l'axe du cylindre et de l'effet prismatique différentiel — une inversion crée un prisme différentiel vertical anormal","Une règle millimétrique","Un kératomètre"],answer:1,diff:2,explication:"Inversion OD/OG : les axes des cylindres sont inversés (effet miroir). Au frontofocusmètre : les prismes différentiels créés par l'anisométropie sont anormalement orientés. En pratique : comparer l'axe mesuré avec l'ordonnance et vérifier la cohérence sphère/cylindre. Une inversion se détecte aussi par l'astigmatisme oblique résultant.",tags:["Contrôle équipement","Inversion OD OG","Axe","Frontofocusmètre","Montage"]},
  {id:"ol_ceq5",prompt:"Un verre progressif est orienté correctement sur le frontofocusmètre quand :",choices:["La face convexe est vers le frontofocusmètre","La croix nasale (gravure permanente) est côté nasal et la croix temporale côté temporal — côté convexe (face avant) vers le bas sur la table","Le verre est posé à plat sans orientation particulière","La face concave est vers l'opérateur"],answer:1,diff:2,explication:"Pour mesurer un verre progressif au frontofocusmètre : verre posé côté convexe (face avant) vers le bas sur l'appui. Les gravures permanentes (croix nasale à gauche pour OD, à droite pour OG) aident à orienter et positionner le verre pour mesurer en VL puis en VP.",tags:["Frontofocusmètre","Progressif","Orientation","Gravures","Contrôle"]},
];



export const QB_OL_MIROIR_SPH = [
  {id:"ol_ms1",prompt:"La relation de conjugaison d'un miroir sphérique est :",choices:["1/SA' - 1/SA = 1/f'","1/SA' + 1/SA = 2/SC = 1/f'","n'/SA' - n/SA = (n'-n)/R","SA' × SA = f'²"],answer:1,diff:2,explication:"Miroir sphérique : 1/SA' + 1/SA = 2/SC = 1/f'. F = F' = milieu entre S et C (f' = SC/2). Les signes sont algébriques — sens positif = sens de la lumière incidente.",tags:["Miroir sphérique","Conjugaison","ETSO"]},
  {id:"ol_ms2",prompt:"Pour un miroir sphérique, le foyer est situé :",choices:["À l'infini","Au centre de courbure C","À mi-distance entre le sommet S et le centre C","Derrière le miroir"],answer:2,diff:1,explication:"F = F' = milieu de [SC]. f' = SC/2. Pour un miroir concave (C devant le miroir) : foyer réel devant le miroir. Pour un miroir convexe : foyer virtuel derrière le miroir.",tags:["Miroir sphérique","Foyer","ETSO"]},
  {id:"ol_ms3",prompt:"Un objet réel situé entre S et F d'un miroir concave donne une image :",choices:["Réelle, renversée","Virtuelle, droite, agrandie (derrière le miroir)","Réelle, droite","Réelle, réduite"],answer:1,diff:2,explication:"Objet entre S et F → image virtuelle (derrière le miroir), droite, agrandie. G > +1. Même principe qu'une lentille convergente avec objet entre F et O.",tags:["Miroir sphérique","Image virtuelle","ETSO"]},
  {id:"ol_ms4",prompt:"Le grandissement transversal d'un miroir sphérique est donné par :",choices:["G = SA/SA'","G = SA'/SA","G = f'/(f' - SA)","G = -SA'/SA (avec convention de sens)"],answer:3,diff:2,explication:"G = A'B'/AB = SA'/SA (en valeur algébrique). G > 0 → image droite. G < 0 → image renversée. |G| > 1 → agrandissement. |G| < 1 → réduction.",tags:["Miroir sphérique","Grandissement","ETSO"]},
  {id:"ol_ms5",prompt:"Un objet au-delà du centre C d'un miroir concave donne une image :",choices:["Virtuelle, derrière le miroir","Réelle, renversée, réduite, entre F et C","Réelle, droite, agrandie","À l'infini"],answer:1,diff:2,explication:"A au-delà de C → A' entre F et C. Image réelle (en avant du miroir), renversée (G < 0), réduite (|G| < 1). Cas du rétroviseur concave de camion.",tags:["Miroir sphérique","Image réelle","Cas particuliers"]},
  {id:"ol_ms6",prompt:"Pour un miroir sphérique, F et F' sont :",choices:["Distincts comme pour une lentille","Confondus au même point F = F'","Séparés par la distance 2f'","Symétriques par rapport à S"],answer:1,diff:1,explication:"Pour un miroir : l'espace objet et l'espace image sont le même espace (la lumière revient du même côté). F = F' = point unique = milieu de SC. C'est une différence fondamentale avec les lentilles.",tags:["Miroir sphérique","Foyers confondus","ETSO"]},
  {id:"ol_ms7",prompt:"Parmi les rayons particuliers pour construire l'image dans un miroir sphérique :",choices:["Rayon vers C → réfléchi sans déviation (retour sur lui-même)","Rayon parallèle à l'axe → réfléchi vers F'","Rayon vers F → réfléchi parallèle à l'axe","Toutes ces réponses sont exactes"],answer:3,diff:1,explication:"3 rayons particuliers : (1) parallèle à l'axe → passe par F après réflexion ; (2) vers C → retour sur lui-même ; (3) vers F → ressort parallèle à l'axe. Ces 3 rayons sont valides pour toute construction graphique.",tags:["Miroir sphérique","Construction","Rayons particuliers"]},
  {id:"ol_ms8",prompt:"L'utilisation d'un miroir sphérique concave en opticien est notamment :",choices:["La taille des verres ophtalmiques","La lampe de Burton (examen de la peau), les loupes de salle de bain, les réflecteurs","La mesure du prisme prismatique","L'adaptation des lentilles de contact souples"],answer:1,diff:2,explication:"Miroir concave : grossit les images des objets placés entre S et F → utilité en loupes de salle de bain. Concave de grande ouverture → concentre la lumière → projecteurs, phares. En OL : lentille cornéenne rigide sur cornée aplatie.",tags:["Miroir sphérique","Applications","OL"]},
  {id:"ol_ms9",prompt:"Pour A situé en C (centre de courbure) d'un miroir concave, l'image A' est :",choices:["En F","À l'infini","En C également (image confondue avec l'objet)","Virtuelle derrière le miroir"],answer:2,diff:2,explication:"A en C → A' en C. La conjugaison donne : 1/SA' + 1/SC = 2/SC → 1/SA' = 1/SC → SA' = SC. Image réelle, renversée, même taille (G = -1). Cas particulier remarquable.",tags:["Miroir sphérique","Point en C","Conjugaison"]},
  {id:"ol_ms10",prompt:"La vergence d'un miroir sphérique concave de rayon R = 40 cm est :",choices:["2,5 δ","5,0 δ","1,25 δ","−5,0 δ"],answer:1,diff:2,explication:"V = 1/f' = 2/R = 2/0,40 m = 5,0 δ. Miroir concave → foyer réel devant → vergence positive. Attention : R en mètres pour obtenir des dioptries.",tags:["Miroir sphérique","Vergence","Calcul"]},
  {id:"ol_ms11",prompt:"Un miroir convexe (centre C derrière le miroir) donne des images :",choices:["Toujours réelles et renversées","Toujours virtuelles, droites, réduites (quel que soit la position de l'objet)","Réelles si l'objet est au-delà de F","Virtuelles agrandies pour l'objet entre S et F"],answer:1,diff:2,explication:"Miroir convexe : foyer virtuel derrière le miroir → pour tout objet réel en avant du miroir, l'image est toujours virtuelle, droite, réduite. Applications : rétroviseurs extérieurs de voiture (grand angle de vue).",tags:["Miroir convexe","Image","Propriétés"]},
  {id:"ol_ms12",prompt:"La relation 1/SA' + 1/SA = 2/SC est valable :",choices:["Uniquement pour les miroirs concaves","Uniquement pour les miroirs convexes","Pour les deux types de miroirs sphériques (avec convention de signe)","Uniquement en lumière monochromatique"],answer:2,diff:1,explication:"La formule 1/SA' + 1/SA = 2/SC est valable pour tous les miroirs sphériques (concave et convexe) à condition de respecter les conventions algébriques : sens positif = sens de la lumière incidente, SC positif si C est devant le miroir (concave).",tags:["Miroir sphérique","Formule universelle","Convention"]},
];

export const QB_OL_DIOPTRE_SPH = [
  {id:"ol_ds1",prompt:"La relation de conjugaison d'un dioptre sphérique est :",choices:["1/SA' - 1/SA = V","n'/SA' - n/SA = (n'-n)/R","n/SA' + n'/SA = 2n'/R","SA' × SA = -f × f'"],answer:1,diff:2,explication:"Dioptre sphérique : n'/SA' - n/SA = (n'-n)/R. Ici n = indice espace objet, n' = indice espace image, R = SC = rayon algébrique de courbure, S = sommet du dioptre.",tags:["Dioptre sphérique","Conjugaison","ETSO"]},
  {id:"ol_ds2",prompt:"La vergence d'un dioptre sphérique est définie par :",choices:["D = 1/f'","D = (n'-n)/R","D = n'/SA' - n/SA","D = n/f'"],answer:1,diff:1,explication:"Vergence du dioptre : D = (n'-n)/R où n et n' sont les indices de part et d'autre du dioptre, R le rayon de courbure en mètres. D en dioptries (δ).",tags:["Dioptre sphérique","Vergence","Formule"]},
  {id:"ol_ds3",prompt:"Le foyer objet F d'un dioptre sphérique vérifie :",choices:["SF = n/D","SF = -n/D = -n × R/(n'-n)","SF = f' = n'/D","SF = -R"],answer:1,diff:3,explication:"Foyer objet F : SF = -n/D = -nR/(n'-n). Pour l'image : SF' = n'/D = n'R/(n'-n). Les relations SF = -n/D et SF' = n'/D sont les équivalents des formules f = -f' pour les lentilles en milieux identiques.",tags:["Dioptre sphérique","Foyers","Formule"]},
  {id:"ol_ds4",prompt:"L'indice de la cornée (première surface réfractante de l'œil) est environ :",choices:["1,000 (air)","1,336 (humeur aqueuse)","1,377 (cornée)","1,420 (cristallin)"],answer:2,diff:1,explication:"n_cornée ≈ 1,377. Valeurs à connaître : n_air = 1,000 ; n_cornée = 1,377 ; n_humeur aqueuse = n_larmes = n_corps vitré = 1,336 ; n_cristallin = 1,420.",tags:["Dioptre sphérique","Oeil","Indices de réfraction"]},
  {id:"ol_ds5",prompt:"Le grandissement transversal d'un dioptre sphérique est :",choices:["G = SA'/SA","G = (n × SA')/(n' × SA)","G = n'/n","G = f'/SA"],answer:1,diff:2,explication:"Grandissement dioptre sphérique : G = (n × SA')/(n' × SA). Ce n'est pas simplement SA'/SA comme pour les lentilles en air ! La présence des indices n et n' modifie l'expression.",tags:["Dioptre sphérique","Grandissement","Formule"]},
  {id:"ol_ds6",prompt:"Pour un dioptre plan (R → ∞), la relation de conjugaison devient :",choices:["n'/SA' = n/SA → SA' = (n'/n) × SA","1/SA' + 1/SA = 0","SA' = SA","n/SA' = n'/SA"],answer:0,diff:2,explication:"Pour R → ∞ : (n'-n)/R → 0 → n'/SA' = n/SA → SA' = (n'/n) × SA. Cas air→verre (n=1, n'=1,5) : SA' = 1,5 SA (objet apparent plus profond). Cas verre→air : SA' = (2/3) SA.",tags:["Dioptre plan","Conjugaison","Cas limite"]},
  {id:"ol_ds7",prompt:"La vergence de la cornée (dioptre air-cornée, R = 7,7 mm, n' = 1,377) est environ :",choices:["22 δ","49 δ","7 δ","100 δ"],answer:1,diff:3,explication:"D = (n'-n)/R = (1,377 - 1,000)/0,0077 m ≈ 0,377/0,0077 ≈ 49 δ. La cornée représente environ 2/3 de la puissance totale de l'œil (≈ 60 δ). Puissance totale œil emmétrope ≈ 60 δ.",tags:["Dioptre sphérique","Cornée","Puissance oeil"]},
  {id:"ol_ds8",prompt:"Deux dioptres sphériques de vergences D₁ et D₂ accolés (lentille mince) ont une vergence totale :",choices:["D = D₁ × D₂","D = D₁ + D₂","D = 1/(1/D₁ + 1/D₂)","D = D₁ + D₂ + e/(n') × D₁ × D₂"],answer:1,diff:2,explication:"Systèmes accolés (e → 0) : D_total = D₁ + D₂. Pour des systèmes épais séparés par e : formule de Gullstrand D = D₁ + D₂ - (e/n') × D₁ × D₂. En optique de l'oeil : D_total ≈ D_cornée + D_cristallin ≈ 49 + 20 = 60 δ (environ).",tags:["Dioptre sphérique","Vergences combinées","Gullstrand"]},
  {id:"ol_ds9",prompt:"Pour un objet virtuel (espace image du système précédent) rencontrant un dioptre sphérique, on place SA :",choices:["Toujours négatif","Du côté image (SA > 0 si C du côté objet)","SA est compté dans le sens négatif de la lumière","La convention algébrique reste la même — SA est du côté image"],answer:3,diff:3,explication:"Un objet virtuel est du côté image (droite si lumière vient de gauche). SA > 0 (sens positif de la lumière). La formule n'/SA' - n/SA = D reste valide avec les conventions algébriques habituelles.",tags:["Dioptre sphérique","Objet virtuel","Convention"]},
  {id:"ol_ds10",prompt:"La puissance de l'œil humain emmétrope standard est d'environ :",choices:["17 δ (cristallin seul)","60 δ (cornée + cristallin ensemble)","100 δ","30 δ"],answer:1,diff:1,explication:"Œil emmétrope : P_total ≈ 60 δ (Listing). Cornée ≈ 43 δ (dioptre air/cornée + face post cornée) ; cristallin au repos ≈ 17-20 δ. Distance cornée-rétine ≈ 24 mm. f' = n_vit/P_total ≈ 1,336/60 ≈ 22 mm.",tags:["Dioptre sphérique","Oeil","Puissance"]},
];

export const QB_OL_FRONTO = [
  {id:"ol_fr1",prompt:"Le rôle du frontofocusmètre est :",choices:["Mesurer la courbure de la cornée","Mesurer la vergence (sphère, cylindre, axe) et le prisme d'un verre ophtalmique","Mesurer la distance interpupillaire","Mesurer l'épaisseur d'un verre"],answer:1,diff:1,explication:"Le frontofocusmètre (ou focimètre) mesure : vergence sphérique, vergence cylindrique, axe du cylindre, prisme et base du prisme, centrage. Il est l'instrument de référence pour le contrôle d'équipement ophtalmique (ISO 21987).",tags:["Frontofocusmètre","Contrôle","Mesure"]},
  {id:"ol_fr2",prompt:"Dans un frontofocusmètre réglé pour un observateur emmétrope, la condition est :",choices:["L'image finale du test est à 25 cm","F'_collimateur = F_verre → faisceau parallèle en sortie du verre → image finale à l'infini","Le test est au centre optique du verre","Le verre est posé face concave vers le bas"],answer:1,diff:2,explication:"Condition de réglage : F'c (foyer image du collimateur) coïncide avec le foyer objet du verre Fv → le verre redirige le faisceau parallèlement → ensemble objectif+oculaire (afocal) donne une image nette à l'infini pour l'observateur emmétrope.",tags:["Frontofocusmètre","Principe","Condition de réglage"]},
  {id:"ol_fr3",prompt:"La chaîne des conjugués du frontofocusmètre (de la source au collimateur) est :",choices:["Test T0 → Ob → Oc → Œil","T0 (en F_coll) → Collimateur → faisceau parallèle → Verre V → Objectif Ob → Réticule → Oculaire → Œil","Verre → Test → Oculaire","Ob → Oc → Verre → T0"],answer:1,diff:2,explication:"Chaîne : Source T0 en F_coll → collimateur → faisceau parallèle → verre V à mesurer → objectif Ob → réticule (en F'Ob) → oculaire → œil. Le diaphragme [D] est dans le plan du verre V pour limiter le faisceau.",tags:["Frontofocusmètre","Chaîne conjugués","ETSO"]},
  {id:"ol_fr4",prompt:"Pour mesurer un verre progressif au frontofocusmètre, on positionne le verre :",choices:["Face convexe (avant) vers le bas, gravures permanentes orientées","Face concave vers le bas","Peu importe l'orientation","Face arrière vers l'objectif"],answer:0,diff:1,explication:"Verre progressif : côté convexe (face avant) vers le bas sur l'appui. Identifier les gravures permanentes (croix nasale à gauche pour OD). Mesurer d'abord VL (zone du haut), puis déplacer vers la zone VP pour mesurer V(VP). ADD = V(VP) - V(VL).",tags:["Frontofocusmètre","Progressif","Technique mesure"]},
  {id:"ol_fr5",prompt:"Si l'ensemble objectif + oculaire du frontofocusmètre est afocal, cela signifie :",choices:["F'ob et Foc ne coïncident pas","F'ob coïncide avec Foc → faisceau parallèle entrant ressort parallèle","L'instrument ne peut pas mesurer les prismes","L'instrument n'a pas de grossissement"],answer:1,diff:2,explication:"Ensemble afocal : F'ob = Foc. Un faisceau parallèle rentrant sort parallèle. Grossissement angulaire = f'ob/f'oc (constant). Cela correspond au cas d'un observateur emmétrope non accommodé.",tags:["Frontofocusmètre","Ensemble afocal","Optique instrumentale"]},
  {id:"ol_fr6",prompt:"Un verre décentré (centre optique non sur l'axe du frontofocusmètre) génère :",choices:["Une mesure de vergence erronée","Un effet prisme P = D × d (D = vergence en δ, d = décentrement en cm) en plus de l'effet vergence","Une erreur sur l'axe du cylindre uniquement","Aucun effet particulier"],answer:1,diff:2,explication:"Prisme induit par décentrement : P = D × d. D = vergence du verre (δ), d = décentrement (cm). Base vers le bord épais. Utile en clinique pour créer un prisme par décentrement d'une correction — mais au frontofocusmètre, un décentrement parasite fausse la mesure du prisme.",tags:["Frontofocusmètre","Prisme","Décentrement"]},
  {id:"ol_fr7",prompt:"La tolérance ISO 21987 sur la vergence sphérique pour un verre < 6 δ est :",choices:["± 0,25 δ","± 0,09 δ","± 0,12 δ","± 0,50 δ"],answer:1,diff:1,explication:"Tolérance ISO 21987 : vergence ± 0,09 δ (pour vergence nominale < 6 δ), ± 0,12 δ au-delà. ADD : ± 0,12 δ. Prisme < 2 Δ : ± 0,25 Δ. Axe : ± 2° à ± 5° selon la puissance cylindrique.",tags:["Frontofocusmètre","ISO 21987","Tolérances"]},
  {id:"ol_fr8",prompt:"Le réticule du frontofocusmètre est placé :",choices:["Dans le plan focal image F'ob de l'objectif","Sur la source lumineuse","Dans le plan focal objet Foc de l'oculaire","Entre l'objectif et l'oculaire sans position précise"],answer:0,diff:2,explication:"Le réticule est placé en F'ob (foyer image de l'objectif) et simultanément en Foc (foyer objet de l'oculaire) quand l'ensemble est afocal (observateur emmétrope). L'observateur voit le réticule net en même temps que l'image du test.",tags:["Frontofocusmètre","Réticule","Optique"]},
  {id:"ol_fr9",prompt:"Pour mesurer l'axe du cylindre d'un verre au frontofocusmètre, on :",choices:["Mesure la vergence dans 3 méridiens différents","Utilise un test cruciforme (croix) — on tourne le verre jusqu'à ce que la ligne soit nette puis on lit l'angle","Utilise le kératomètre","Utilise la polarisation"],answer:1,diff:1,explication:"Test cruciforme (ou cible ligne) : on tourne le verre (ou le test) jusqu'à ce que les lignes apparaissent nettes et non déformées. L'angle lu correspond à l'axe du cylindre. La méridien de plus fort cylindre est celui qui met au point en dernier.",tags:["Frontofocusmètre","Axe cylindre","Technique"]},
  {id:"ol_fr10",prompt:"Après mesure au frontofocusmètre d'un verre progressif, on obtient VL = +1,50 δ et VP = +3,25 δ. L'ADD est :",choices:["1,75 δ","4,75 δ","0,75 δ","3,25 δ"],answer:0,diff:1,explication:"ADD = V(VP) - V(VL) = 3,25 - 1,50 = 1,75 δ. L'ADD est toujours positive pour un presbyte — elle représente la puissance supplémentaire ajoutée en vision de près pour compenser la perte d'accommodation.",tags:["Frontofocusmètre","ADD","Calcul"]},
];

export const QB_OL_LUNETTE_GALILEE = [
  {id:"ol_lg1",prompt:"La condition d'afocalisme d'une lunette astronomique est :",choices:["f'_obj = f'_oc","F'_obj = F_oc (foyer image de l'objectif coïncide avec foyer objet de l'oculaire)","La longueur du tube = f'_obj + f'_oc","f'_oc > f'_obj"],answer:1,diff:2,explication:"Lunette afocale : F'obj = Foc. Le plan intermédiaire (image de l'objet à l'infini par l'objectif) coincide avec le plan focal objet de l'oculaire → faisceau parallèle en entrée ressort parallèle en sortie (pour un objet à l'infini).",tags:["Lunette astronomique","Afocalisme","ETSO"]},
  {id:"ol_lg2",prompt:"Le grossissement commercial G d'une lunette astronomique est :",choices:["G = f'_oc / f'_obj","G = f'_obj / f'_oc","G = -f'_obj / f'_oc","G = D_obj / D_oc"],answer:2,diff:1,explication:"G = f'_obj / f'_oc (valeur absolue, positive par convention). Plus f'obj grand et f'oc petit, plus G est grand. Ex : f'obj = 1000 mm, f'oc = 25 mm → G = 40×. La lunette astronomique donne une image renversée (G commercial négatif ≈ renversé).",tags:["Lunette astronomique","Grossissement","Formule"]},
  {id:"ol_lg3",prompt:"La différence fondamentale entre la lunette astronomique et le système Galilée est :",choices:["L'astronomique a un objectif divergent","Galilée utilise un oculaire DIVERGENT → image droite + tube plus court","L'astronomique n'est pas afocale","Galilée grossit plus"],answer:1,diff:1,explication:"Galilée : L1 convergente + L2 divergente (oculaire). F'1 = F2 (foyer objet de L2 négatif, donc entre les deux lentilles). Résultat : image droite (G > 0), tube plus court que l'astronomique. Inconvénient : champ plus petit.",tags:["Galilée","Lunette astronomique","Comparaison"]},
  {id:"ol_lg4",prompt:"Dans un système de Galilée afocal, le foyer objet F2 de la lentille divergente est :",choices:["En arrière de L2 (côté image)","Entre L1 et L2 (coïncide avec F'1 → tube plus court)","En avant de L1","À l'infini"],answer:1,diff:2,explication:"L2 divergente : son foyer objet F2 est à droite de L2 (dans l'espace image, côté image). Or F'1 est entre L1 et L2. La condition afocale F'1 = F2 place donc F2 entre les deux lentilles → tube = f'1 + f2 = f'1 - |f2| → tube plus court qu'une lunette astronomique.",tags:["Galilée","Afocalisme","Construction"]},
  {id:"ol_lg5",prompt:"Le plan des champs d'une lunette astronomique est :",choices:["Dans le plan de l'objectif","Dans le plan focal image F'obj de l'objectif = plan focal objet Foc de l'oculaire (plan intermédiaire)","Dans le plan focal image F'oc de l'oculaire","Sur la pupille de sortie"],answer:1,diff:2,explication:"Le plan intermédiaire F'obj = Foc est le plan des champs. C'est là que se forme l'image intermédiaire réelle (lunette astronomique). On y place le réticule ou le diaphragme de champ [Dc] pour supprimer le champ de contour.",tags:["Lunette astronomique","Plan des champs","Réticule"]},
  {id:"ol_lg6",prompt:"La pupille d'entrée d'une lunette astronomique est :",choices:["L'oculaire","L'objectif (diaphragme D1 sur l'objectif)","Le diaphragme de champ Dc","La pupille de l'observateur"],answer:1,diff:2,explication:"Pupille d'entrée = image du diaphragme limitant le flux dans l'espace objet. C'est l'objectif (D1 = diaphragme de l'objectif). La pupille de sortie (œil de sortie) est le conjugué de D1 par l'oculaire, placé juste derrière l'oculaire — le placement de l'œil de l'observateur.",tags:["Lunette astronomique","Pupille","Champs"]},
  {id:"ol_lg7",prompt:"Pour construire le faisceau dans un système afocal (Galilée ou astronomique) avec 2 diaphragmes, on :",choices:["Trace directement les rayons depuis l'objet","Compare les diaphragmes dans le même espace intermédiaire (conjuguer chaque diaphragme dans cet espace) puis trace le faisceau limité","Utilise uniquement le foyer image","Superpose les deux systèmes de conjugaison"],answer:1,diff:2,explication:"Méthode des champs : 1) Projeter D1 et D2 dans l'espace intermédiaire. 2) Le plus petit des deux conjugués = pupille [P] (limite le flux). 3) L'autre = lucarne [L] (limite le champ). 4) Tracer le faisceau PL (pleine lumière), T (bord), M (mi-champ).",tags:["Systèmes afocaux","Champs","Méthode"]},
  {id:"ol_lg8",prompt:"Pour supprimer le champ de contour (vignettage) dans une lunette astronomique, on :",choices:["Augmente le diamètre de l'oculaire","Place un diaphragme Dc dans le plan intermédiaire (F'obj = Foc), de diamètre égal au champ PL","Réduit la vergence de l'objectif","Augmente f'oc"],answer:1,diff:2,explication:"Champ de contour = zone où l'éclairement baisse progressivement (vignettage). Pour le supprimer : placer un diaphragme [Dc] réel sur le plan intermédiaire (seul plan où on peut physiquement le placer pour délimiter nettement le champ). Le bord de Dc = bord du champ PL.",tags:["Lunette astronomique","Champ de contour","Vignettage"]},
  {id:"ol_lg9",prompt:"Les applications du système de Galilée en opticien-lunetier sont notamment :",choices:["Adapté pour les grandes lunettes longue-vue uniquement","Les loupes télescopiques de basse vision (champ plus étroit mais image droite portable), les réticules HUD, les verres progressifs","Aucune application directe en optique","Uniquement les télescopes amateurs"],answer:1,diff:2,explication:"Galilée en OL : 1) Loupes télescopiques pour basse vision (image droite, compact). 2) Télescopes de poche (jumelles compactes). 3) Compensateurs d'anisométropie. 4) Certains verres ophtalmiques à effet télescopique (basse vision). L'avantage image droite + compacité est déterminant.",tags:["Galilée","Basse vision","Applications OL"]},
  {id:"ol_lg10",prompt:"L'angle limite de réflexion totale dans un prisme de verre d'indice 1,5 est :",choices:["30°","41,8° (arcsin(1/1,5))","45°","60°"],answer:1,diff:2,explication:"Réflexion totale interne : sin(ic) = n2/n1 = 1/1,5 → ic = arcsin(0,667) ≈ 41,8°. Pour les angles d'incidence > 41,8°, le rayon est totalement réfléchi (pas de réfraction). C'est le principe des prismes réflecteurs dans les jumelles et les prismes optiques.",tags:["Prisme","Réflexion totale","Indice"]},
];

export const QB_OL_FAISCEAU_SC = [
  {id:"ol_fsc1",prompt:"Un système centré est défini par :",choices:["Un ensemble de miroirs plans","Un ensemble de surfaces optiques dont les centres de courbure sont alignés sur un axe optique commun","Un système de lentilles toutes de même vergence","Un système optique sans aberration"],answer:1,diff:1,explication:"Système centré : toutes les surfaces de révolution ont leurs centres alignés sur un axe optique. Éléments cardinaux : plans principaux H, H', foyers objet F et image F', distances focales f et f'. La plupart des systèmes optiques (œil, objectif photo, lunette) sont approximativement centrés.",tags:["Systèmes centrés","Définition","ETSO"]},
  {id:"ol_fsc2",prompt:"Pour tracer un faisceau dans un système centré, on doit d'abord :",choices:["Tracer les rayons au hasard","Construire le tableau des conjugués (objet, diaphragme) puis identifier l'espace de départ","Mesurer le diamètre de toutes les lentilles","Trouver le grossissement"],answer:1,diff:1,explication:"Méthode : 1) Tableau des conjugués de l'objet A → A', et du diaphragme D → D'. 2) Identifier l'espace où se trouvent simultanément un conjugué de A ET le diaphragme. 3) Tracer les rayons extrêmes depuis A, passant par les bords de D. 4) Propager à travers le système.",tags:["Faisceau","Méthode","Systèmes centrés"]},
  {id:"ol_fsc3",prompt:"La 'pupille' d'un système optique est :",choices:["Toujours l'iris de l'œil","Le diaphragme qui, dans l'espace courant, vu depuis l'objet, sous-tend le plus petit angle","La première lentille du système","Le diaphragme le plus proche de l'objectif"],answer:1,diff:2,explication:"La pupille [P] est le diaphragme (ou son conjugué) qui limite l'ouverture angulaire du faisceau. Vue depuis l'objet A, c'est le diaphragme vu sous l'angle le plus faible. En pratique, on compare les demi-angles sous-tendus par tous les diaphragmes dans le même espace.",tags:["Pupille","Diaphragme","Systèmes centrés"]},
  {id:"ol_fsc4",prompt:"Un objet virtuel est :",choices:["Un objet dont l'image est virtuelle","Un faisceau convergent entrant dans le système — l'intersection du prolongement des rayons incidents (côté image)","Un objet à l'infini","Un objet derrière le système"],answer:1,diff:2,explication:"Objet virtuel : les rayons incidents convergent vers un point situé dans l'espace image du système (côté droit si lumière vient de gauche). SA > 0. Cela se produit quand un premier système forme une image qui sert d'objet à un second système avant que les rayons n'aient convergé.",tags:["Objet virtuel","Systèmes centrés","Espace"]},
  {id:"ol_fsc5",prompt:"Le conjugué antérieur d'un diaphragme est utilisé quand :",choices:["Le diaphragme est trop petit","Le diaphragme est dans l'espace image du système → son image dans l'espace objet (objet virtuel) est nécessaire pour tracer le faisceau","Le diaphragme est sur la lentille","Le système est afocal"],answer:1,diff:2,explication:"Si le diaphragme D est dans l'espace image (après H'), son conjugué antérieur D0 dans l'espace objet est un objet virtuel. Pour tracer le faisceau depuis A (dans l'espace objet), on utilise D0 — le faisceau est limité en semblant venir des bords de D0.",tags:["Conjugué antérieur","Diaphragme","Espace objet"]},
  {id:"ol_fsc6",prompt:"Le 'code couleur' conventionnel pour tracer un faisceau dans un système centré est :",choices:["Rouge = rayon réfracté, bleu = rayon réfléchi","Rouge = espace de départ (objet), Vert = second espace (image)","Bleu = rayon axial, rouge = rayon marginal","Pas de convention — au choix"],answer:1,diff:1,explication:"Convention B. Piboule (ETSO) : rouge = espace de départ du faisceau, vert = second espace. Cela permet de distinguer visuellement l'espace objet de l'espace image lors de la construction graphique. Les rayons ne se croisent qu'au niveau des plans principaux H et H'.",tags:["Faisceau","Code couleur","ETSO"]},
  {id:"ol_fsc7",prompt:"Pour un objet réel A en avant du foyer objet F, l'image A' est :",choices:["Virtuelle, du même côté que A","Réelle, de l'autre côté (espace image)","Toujours à 2f'","Toujours agrandie"],answer:1,diff:1,explication:"Objet réel A entre l'infini et F (A plus à gauche que F) → A' réelle dans l'espace image (à droite de H'). Si A est entre F et H (cas lentille mince) → A' virtuelle (à gauche de H). Mémoriser : objet réel entre F et le système → image virtuelle (côté objet).",tags:["Systèmes centrés","Image","Position objet"]},
  {id:"ol_fsc8",prompt:"La vergence d'un système optique centré est définie par :",choices:["V = 1/f' (f' = H'F')","V = n'/f' (si l'espace image a un indice n')","V = -n/f (foyer objet)","V = (n'-n)/R"],answer:1,diff:1,explication:"Vergence générale : V = n'/f' où f' = H'F' (distance focale image mesurée depuis le plan principal image H'). En air (n' = 1) : V = 1/f'. Pour l'œil (n' = 1,336) : V = n'/f' ≠ 1/f' — important pour les calculs de l'optique de l'œil.",tags:["Vergence","Systèmes centrés","Formule"]},
  {id:"ol_fsc9",prompt:"Dans la construction graphique d'un faisceau, les rayons particuliers sont :",choices:["Rayon passant par H sans déviation (système mince)","Rayon parallèle → passe par F' ; rayon vers F → ressort parallèle ; rayon vers H → ressort de H' sans déviation","Uniquement le rayon parallèle","Uniquement le rayon central"],answer:1,diff:1,explication:"3 rayons particuliers pour système centré : (1) Parallèle à l'axe → passe par F' en sortie. (2) Vers F (foyer objet) → ressort parallèle à l'axe. (3) Vers H (plan principal objet) → ressort de H' parallèle (pas de déviation entre plans principaux, juste décalage transversal pour système épais).",tags:["Systèmes centrés","Rayons particuliers","Construction"]},
  {id:"ol_fsc10",prompt:"Si la vergence d'un système centré est nulle (V = 0), c'est un système :",choices:["Divergent fort","Afocal (vergence nulle, foyers à l'infini)","Sans plans principaux","Un simple prisme"],answer:1,diff:2,explication:"Système afocal : V = 0, f' = infini, F et F' à l'infini. Un faisceau parallèle reste parallèle en sortie (mais dévié en angle). Grossissement angulaire constant. Exemples : lunette astronomique, Galilée — ce sont des systèmes afocaux.",tags:["Systèmes centrés","Afocal","Vergence nulle"]},
];
// ─── FICHES ───
export const FICHES_OL = [
  {id:"ol_f1",title:"Optique géométrique appliquée à l'opticien",bloc:"Bloc 1",tags:["Optique","Vergence","Lentilles"],duree:20,niveau:"Fondations",qbank:"ol_optique_geo",
    contenu:"**Vergence (δ) :** V = 1/f' (dioptries). Convergent (+), Divergent (-)\n\n**Formule de conjugaison :** 1/OA' - 1/OA = V\n\n**Formule des verriers :** V = (n-1)(1/R1 - 1/R2)\n\n**Grossissement :** G = -OA'/OA = A'B'/AB\n\n**Indices courants :**\n• CR39 (standard) : n = 1.50, Vd = 58\n• Polycarbonate : n = 1.59, Vd = 30\n• Haute index 1.67 : n = 1.67, Vd = 32\n• Haute index 1.74 : n = 1.74, Vd = 33\n\n**Prisme :** 1 Δ = 1 cm de déviation à 1 m\n\n**Aberration chromatique :** Nombre d'Abbe élevé = peu de dispersion = meilleure qualité\n\n**Profondeur de champ :** inversement proportionnelle au diamètre pupillaire"},
  {id:"ol_f2",title:"Optique physiologique et amétropies",bloc:"Bloc 2",tags:["Optique physiologique","Myopie","Hypermétropie","Astigmatisme","Presbytie"],duree:22,niveau:"Fondations",qbank:"ol_optique_physio",
    contenu:"**Amétropies :**\n• Myopie : globe trop long → image AVANT rétine → verre divergent (-)\n• Hypermétropie : globe trop court → image ARRIÈRE rétine → verre convergent (+)\n• Astigmatisme : asymétrie cornée → 2 foyers → verre torique (sph/cyl × axe)\n• Presbytie : perte élasticité cristallin → verre correcteur près (+ADD)\n\n**Accommodation :**\n• Amplitude = PP - PR (en dioptries)\n• Diminue avec l'âge (presbytie)\n• PP : point le plus proche vu net\n• PR : point le plus lointain vu net\n\n**Mesure de l'AV :**\n• Loin : échelle de Monoyer à 5m (lettres noires sur fond blanc)\n• Près : Parinaud (P2 à P14)\n• AV normale : 10/10 de loin, P2 de près\n\n**ECL :** distance cornée-verre (≈12-13 mm). Influence la vergence effective pour fortes amétropies."},
  {id:"ol_f3",title:"Examen de vue et réfraction",bloc:"Bloc 3",tags:["Réfraction","Examen de vue","Optométrie"],duree:18,niveau:"Intermédiaire",qbank:"ol_optique_physio",
    contenu:"**Réfraction objective :**\n• Auto-réfractomètre : résultat rapide (sphère/cylindre/axe), point de départ\n• Skiascopie : reflet rétinien éclairage mouvant, plus précis\n\n**Réfraction subjective :**\n• Boîte de verres d'essai ou phoropter\n• Méthode du brouillard : convergence + pour détendre accommodation\n• Choix subjectif du patient (quelle est la meilleure vision ?)\n• Test de l'horloge pour l'axe de l'astigmatisme\n\n**Vision binoculaire :**\n• Test de Worth : 4 points (fusion/suppression/diplopie)\n• Test de Maddox : mesure de la phorie\n• Test de l'écran (cover test)\n\n**Progressifs : mesures obligatoires**\n• EP (écart pupillaire) de loin\n• Hauteur de montage\n• Angle pantoscopique de la monture"},
  {id:"ol_f4",title:"Réalisation technique et contrôle",bloc:"Bloc 4",tags:["Réalisation technique","Montage","Contrôle","Normes"],duree:18,niveau:"Intermédiaire",qbank:"ol_reali_tech",
    contenu:"**Mesures du montage :**\n• EP de loin (et de près pour les progressifs)\n• Hauteur de montage (obligatoire pour progressifs et bifocaux)\n• Angle pantoscopique : 8-12° idéalement\n• Galbe : courbure temporale de la monture\n\n**Frontofocusmètre :**\n• Mesure vergence sphère, cylindre, axe\n• Mesure du prisme et de sa base\n• Vérification du centrage\n• Tolérance ISO 21987 : ± 0.09 δ (< 6 δ)\n\n**Traitements de surface :**\n• Antireflet (AR) : couches minces λ/4, interférences destructives\n• Antirayures : couche dure minérale\n• Antibuée : couche hydrophile\n• Photochromique : molécules activées par UV\n• Polarisant : filtre lumière diffusée (conduite, sport nautique)\n\n**Verres progressifs :** zone loin (haut) + corridor progressif + zone près (bas)"},
  {id:"ol_f5",title:"Gestion commerciale et relation client",bloc:"Bloc 5",tags:["Gestion","Relation client","Commercial"],duree:15,niveau:"Fondations",qbank:null,
    contenu:"**Rôle de l'opticien-lunetier :**\n• Professionnel de santé réglementé (Livre IV du CSP)\n• Peut délivrer, adapter et renouveler les corrections (dans la limite des règles)\n• Collabore avec l'ophtalmologiste\n\n**Renouvellement de la prescription :**\n• Adulte 16-42 ans : renouvellement possible si prescription < 5 ans\n• Presbyte : adaptation possible dans la limite de +/- 0.50 δ\n• Mineur : obligation de prescription médicale\n\n**Gestion du magasin :**\n• Stock et approvisionnement (tournants)\n• Merchandising\n• Éco-contribution (REP - Responsabilité Élargie du Producteur)\n• Tiers payant : CMU-C, ALD, contrats mutuelles\n\n**Garanties légales :** conformité + vices cachés. Délai de réflexion 14 jours (vente à distance)."},
  {id:"ol_f6",title:"Gestion commerciale et financière d'un magasin d'optique",bloc:"Bloc 5",tags:["Gestion","SIG","CAF","Seuil de rentabilité","Statuts juridiques"],duree:20,niveau:"Intermédiaire",qbank:"ol_gestion",
    contenu:"**Soldes Intermédiaires de Gestion (SIG) :**\n• Marge commerciale = CA - Coût d'achat revendu\n• Valeur Ajoutée = Marge + Production - Consommations externes\n• EBE = VA - Salaires et charges sociales\n• REX = EBE - Dotations aux amortissements\n• Résultat Net = REX - Charges financières - IS\n\n**CAF = Résultat Net + Amortissements**\n(trésorerie potentielle générée)\n\n**Seuil de rentabilité = Charges fixes / Taux MCV**\n• En dessous = perte. Au-dessus = bénéfice.\n\n**Statuts juridiques :**\n• EI : simple, responsabilité illimitée, fiscalité IR\n• SARL/EURL : responsabilité limitée, gérant TNS, forme classique PME\n• SAS/SASU : flexible, Président assimilé salarié\n\n**100% Santé (2020) :**\n• Panier A (classe 1) : sans reste à charge pour bénéficiaires complémentaire\n• Panier B (classe 2) : libre tarification\n• LPPR : tarifs de remboursement SS (très faibles en optique)"},
  ,{id:"ol_f8",title:"🎓 Annale 2024 — Analyse de la vision, binoculaire & lentilles",bloc:"Bloc 2",tags:["Annale 2024","Analyse de la vision","Cataracte","Phorie","Aniséiconie","Prisme de Prentice","BUT","Dk/e","Lentilles"],duree:30,niveau:"Avancé",qbank:"ol_av",
    contenu:"**Contexte (U.5 AV 2024 — Gérard CHOUYE, 35 ans, plombier) :**\nAnisométropie : OD -1 δ, OG -5 δ → problèmes de vision double en regard vers le haut.\n\n**Cataracte :**\n• Opacification du cristallin → baisse d'acuité, halos, éblouissements, diplopie monoculaire\n• Origines : âge (sénile), traumatisme, congénitale, UV, corticoïdes, diabète\n• Dépistage : lampe à fente (biomicroscopie). NB : tonométrie = dépistage du GLAUCOME\n\n**Autoréfractomètre :**\n• Réfraction OBJECTIVE (patient passif) → ticket avec S/C/Axe pour chaque œil\n• Point de départ. La réfraction subjective (test avec le patient) peut différer\n• Sphère équivalente : Seq = S + C/2\n\n**Cadran de Parent :**\n• Sujet légèrement myopisé → méridien vu le plus NET = axe de la FOCALE ARRIÈRE\n• Cylindre négatif compensateur : axe perpendiculaire au méridien vu net\n\n**Cover test (masquage) :**\n• Mouvement au MASQUAGE → tropia (déviation manifeste)\n• Mouvement au DÉMASQUAGE uniquement → phorie (déviation latente, compensée par fusion)\n\n**Phories et test de Maddox :**\n• Exophorie : déviation en divergence (VP : barre rouge à gauche du point → exophorie)\n• Cylindre de Maddox 250 Δ : forte dissociation → inconvénient : sur-estimation possible vs von Graefe\n• Réserves fusionnelles verticales (point de bris) : ≈ 2-3 Δ statistiquement\n\n**Prisme de Prentice :**\n• P = D × d (D en δ, d en cm)\n• Verre divergent, regard 1 cm au-dessus du CO : P = D × 1 base inférieure\n• Anisométropie → prismes différentiels entre OD et OG → diplopie verticale en regard excentré\n\n**Aniséiconie & lentilles de contact :**\n• Aniséiconie = différence de grossissement OD/OG (M ≈ 1 + d×P/1000)\n• En lunettes, d ≈ 27 mm → aniséiconie significative pour forte anisométropie\n• En lentilles, d ≈ 0 mm → aniséiconie quasi nulle → solution pour les fortes anisométropies\n\n**Examen pré-adaptation LC :**\n• Kératométrie : rayons de courbure cornéenne (Rc) → choix du rayon de base (Rb)\n• BUT ≥ 10 s = film lacrymal stable (12 s dans le cas → adapté)\n• Prisme lacrymal : évaluation du menisc lacrymal\n• Biomicroscopie : pinguecula, néovascularisation, œdème\n• Dk/e : transmissibilité O₂ (silicone hydrogel > 100 Fatt → port prolongé possible)"}
  ,{id:"ol_f7",title:"Marques, labels et Made in France en optique",bloc:"Bloc 3",tags:["Marques","Labels","Made in France","Propriété industrielle","Contrefaçon"],duree:18,niveau:"Intermédiaire",qbank:"ol_marques",
    contenu:"**Dépôt de marque (INPI) :**\n• Coût : ~250 €/classe de produits\n• Protection : 10 ans renouvelables indéfiniment\n• Conditions : distinctivité + licéité + disponibilité\n• Marque nationale (INPI) / Marque UE (EUIPO) / Marque internationale (OMPI – protocole de Madrid)\n\n**Made in France :**\n• Règlement UE 952/2013 (Code des douanes de l'Union)\n• Critère : dernière transformation substantielle réalisée en France\n• Pour les montures : fabrication en France avec ≥ 45 % de valeur ajoutée locale\n• Fabricants emblématiques : Morel (Oyonnax), Vuarnet, Atelier Pauline\n\n**Labels et certifications :**\n• **OFG (Origine France Garantie)** : label privé Pro France, outil de production en France + ≥ 50 % du prix de revient d'origine FR\n• **Marquage CE** : obligatoire pour les verres correcteurs (DM classe IIa – règlement UE 2017/745). Atteste la conformité aux exigences essentielles — ce n'est PAS un label qualité\n• **NF** : marque de certification AFNOR (qualité produit)\n• **ISO 9001** : certification du système de management qualité (processus, amélioration continue)\n• **EPV (Entreprise du Patrimoine Vivant)** : label d'État pour savoir-faire artisanal d'excellence (ex : Morel Eyewear)\n\n**Marques de luxe et licences :**\n• Grandes maisons (Chanel, Gucci, Cartier…) accordent des licences à des fabricants spécialisés\n• Principaux licenciés : Luxottica (EssilorLuxottica), Safilo, Kering Eyewear\n• Les opticiens achètent les collections auprès de ces groupes\n\n**Contrefaçon :**\n• Juridiction compétente : Tribunal judiciaire\n• Actions possibles : saisie-contrefaçon (constitution de preuves), action civile (dommages-intérêts), action pénale\n• Risques : peines d'emprisonnement et amendes pour les contrefacteurs"}
  ,{id:"ol_f9",title:"Verres progressifs : conception, mesures et adaptation",bloc:"Bloc 4",tags:["Progressif","ADD","Presbytie","Corridor","Zones","Hauteur de montage"],duree:22,niveau:"Intermédiaire",qbank:"ol_progressifs",
    contenu:"**Structure du verre progressif :**\n• Zone loin (haut) : vergence = Rx loin\n• Corridor progressif (centre) : vergence croissante\n• Zone près (bas) : vergence = Rx loin + ADD\n• Zones latérales : aberrations → adaptation nécessaire\n\n**Paramètres :**\n• ADD : +0.75 à +3.50 δ. Augmente avec l'âge.\n• Hauteur de montage : OBLIGATOIRE (pupille → bas de la monture) ≥ 20-22 mm\n• EP loin + EP près (légèrement inférieur)\n• Angle pantoscopique : 8-12° idéalement\n\n**Sphère équivalente :** Seq = S + C/2\n\n**Conseils patient :**\n• Vision de loin : tête droite, regard par le haut\n• Vision de près : pointer le nez vers la lecture\n• Adaptation : 2-4 semaines en général\n• Intolérance : essayer ADD réduite ou design différent"}
  ,{id:"ol_f10",title:"Réfraction : brouillard, bichromie et équilibre binoculaire",bloc:"Bloc 3",tags:["Réfraction","Brouillard","Bichromie","Worth","Cover test","Balance binoculaire","Maddox"],duree:20,niveau:"Avancé",qbank:"ol_refraction",
    contenu:"**Méthode du brouillard :**\n• Sur-addition positive → myopisation artificielle → relâchement de l'accommodation\n• Débrouillardage progressif (lentilles négatives) jusqu'à meilleure AVsc\n• Évite la sur-correction en hypermétropie\n\n**Test de bichromie :**\n• Rouge et vert → foyers à distance différente (aberration chromatique)\n• Fin de réfraction : optotype aussi net sur les DEUX fonds\n• Sur rouge uniquement → ajouter du (-) / Sur vert → ajouter du (+)\n\n**Tests binoculaires :**\n• Worth (4 points) : 4 pts = fusion ; 2 rouges = suppression OG ; 3 verts = suppression OD ; 5 pts = diplopie\n• Cover test : mouvement au masquage = tropia ; au démasquage = phorie\n• Cylindre de Maddox : mesure de la phorie (forte dissociation)\n\n**Équilibre binoculaire :**\n• Von Graefe (prismatique) ou méthode polarisée\n• Réserves fusionnelles : convergence VP, divergence VL\n\n**Stéréoscopie :**\n• Lang, Randot, cercles de Wirt\n• Normale : < 40 secondes d'arc"}
  ,{id:"ol_f11",title:"Réglementation optique : 100% Santé, MDR et renouvellement",bloc:"Bloc 5",tags:["100% Santé","MDR 2017/745","LPPR","Renouvellement","Devis normalisé","Tiers payant","Classe 1","Classe 2"],duree:20,niveau:"Fondations",qbank:"ol_reglement",
    contenu:"**100% Santé (2020) :**\n• Classe 1 : sans reste à charge (bénéficiaire complémentaire responsable)\n  - Monture : plafond 30 €\n  - Verres : grille remboursement 30-235 € selon correction\n• Classe 2 : libre tarification\n• Devis normalisé : 2 paniers côte à côte (obligatoire)\n\n**MDR 2017/745 :**\n• Verres correcteurs = DM classe IIa\n• Lentilles de contact = DM classe IIb\n• Marquage CE + déclaration de conformité\n• Incidents graves → déclaration ANSM\n\n**Renouvellement :**\n• Adulte (16-44 ans) : ordonnance < 5 ans, adaptation ± 1.00 δ max\n• Presbyte (> 42 ans) : adaptation ± 0.50 δ max\n• Enfant (< 16 ans) : ordonnance médicale OBLIGATOIRE\n• Lentilles : ordonnance < 3 ans\n\n**Tiers payant :**\n• CSS/CMU-C : prise en charge intégrale (panier A garanti)\n• ALD, ACS : remboursements majorés\n• Réseaux mutuelles : Noé, EDI"}
  ,{id:"ol_f12",title:"Lentilles de contact : kératocône, fit, complications et entretien",bloc:"Bloc 3",tags:["Lentilles de contact","Kératocône","Fit","Dk/e","Acanthamoeba","GPLS","Entretien","Port prolongé"],duree:22,niveau:"Avancé",qbank:"ol_lentilles2",
    contenu:"**Kératocône :**\n• Amincissement et ectasie de la cornée → astigmatisme irrégulier progressif\n• Signes : anneaux de Fleischer, stries de Vogt, signe de Munson\n• Traitement : lunettes → LRPG (rigide perméable gaz) → anneaux intracornéens → kératoplastie\n\n**Paramètres d'adaptation :**\n• Rayon de base (Rb) : kératométrie → légèrement supérieur au rayon K\n• Mobilité : 1-2 mm souples, 0.5-1 mm rigides\n• Fluorescéine (LRPG) : répartition uniforme idéale\n\n**Transmissibilité O₂ :**\n• Dk/e : transmissibilité (Dk perméabilité / e épaisseur)\n• Silicone-hydrogel : Dk/e > 100 Fatt → port continu 30j possible\n• Seuils : 24 Fatt (journalier), 87 Fatt (port continu)\n\n**Complications :**\n• Œdème cornéen → hypoxie → changer pour silicone-hydrogel haute Dk/e\n• Néovascularisation superficielle → arrêt port LC\n• Acanthameobiase : Acanthamoeba (eau du robinet) → kératite gravissime\n  → JAMAIS rincer lentilles à l'eau du robinet\n• GPLS : papilles géantes sous la paupière supérieure (réaction allergo-mécanique)\n\n**Entretien :**\n• Solution multifonction : nettoie + rince + désinfecte + conserve\n• Peroxyde H₂O₂ : désinfection puissante (60 min neutraliseur obligatoire)\n• Renouvellement étui : tous les 3 mois minimum"}
  ,{id:"ol_f13",title:"Amétropies du sujet âgé, DMLA et basse vision",bloc:"Bloc 2",tags:["Presbytie","ADD","DMLA","Cataracte","Glaucome","Basse vision","Amblyopie"],duree:20,niveau:"Avancé",qbank:"ol_ametropies_pa",
    contenu:"**Évolution des amétropies avec l'âge :**\n• Presbytie : ADD croissante de +0,75 à 40 ans → +3,00-3,50 à 65 ans+\n• Cataracte nucléaire → myopie de l'index\n• Hypermétrope : accommodation disparaissant → correction de loin ↑\n\n**Pathologies fréquentes :**\n• DMLA : atteinte maculaire → AV centrale ↓, métamorphopsies (grille d'Amsler). Forme humide → anti-VEGF en urgence\n• Cataracte : chirurgie (phacoémulsification + LIO)\n• GCAO : PIO + excavation papillaire + scotome arciforme → prostaglandines\n\n**Basse vision :**\n• AV meilleur oeil corrigé entre 1/20 et 3/10 (OMS)\n• Cécité légale France : AV ≤ 1/20 ou CV < 10°\n• Aides : loupes, télescopiques, logiciels d'agrandissement\n\n**Amblyopie fonctionnelle :**\n• AV < 7/10 sans cause organique\n• Causes : strabisme, anisométropie, déprivation\n• Traitement : correction optique + occlusion (< 7 ans)\n\n**LC presbyte :**\n• Monovision (oeil dominant = loin)\n• Multifocales à conception simultanée\n• Vergence effective : V_lc = V_lun / (1 + d × V_lun)"}
  ,{id:"ol_f14",title:"Instruments et équipements optométriques",bloc:"Bloc 3",tags:["Kératomètre","Tonomètre","Lampe à fente","OCT","Frontofocusmètre","Topographe","Skiascopie","BUT","Pachymétrie"],duree:20,niveau:"Avancé",qbank:"ol_etso_instr",
    contenu:"**Mesure de la réfraction :**\n• Auto-réfractomètre : réfraction objective (IR) — point de départ\n• Skiascopie : réfraction objective (reflet rétinien) — indispensable enfant/cycloplégique\n• Phoropter/verres d'essai : réfraction subjective\n\n**Mesure cornéenne :**\n• Kératomètre (Javal) : rayons de courbure → astigmatisme + Rb LC\n• Topographe (Placido) : cartographie complète cornée (kératocône OBLIGATOIRE avant chirurgie)\n• Pachymètre : épaisseur (normale 540-560 µm) — glaucome, LASIK\n\n**Pression intra-oculaire :**\n• Tonomètre de Goldmann : aplanation 3,06 mm, référence (PIO normale 10-21 mmHg)\n\n**Examen oculaire :**\n• Lampe à fente : biomicroscopie cornée, cristallin + fond d'oeil (condenseur 90 D)\n• OCT : coupes rétine haute résolution (DMLA, glaucome RNFL) sans contact\n\n**Vérification optique :**\n• Frontofocusmètre : vergence + prisme + marquage (ISO 21987)\n\n**Film lacrymal :**\n• BUT ≥ 10 s = stable (fluorescéine + filtre cobalt)\n• Schirmer : volume lacrymal\n\n**AV objective bébé :**\n• Regard préférentiel (Teller), NOC, PEV"}
  ,{id:"ol_f15",title:"Gestion financière : amortissements et emprunts",bloc:"Bloc 5",tags:["Amortissement","Emprunt","Tableau d'amortissement","CAF","BFR","Seuil de rentabilité","TVA","Marge commerciale"],duree:20,niveau:"Avancé",qbank:"ol_gestion_amort",
    contenu:"**Amortissements :**\n• Linéaire : annuité = Valeur brute / Durée (constante)\n• Dégressif : annuité = VNC × taux dégressif (coefficient 1,25 à 2,25)\n  → charges plus fortes en début → avantage fiscal\n• VNC = Valeur brute - Cumul amortissements\n\n**Tableau d'amortissement d'emprunt :**\n• Amortissement constant du capital : annuités décroissantes\n  Annuité N = (Capital/n) + (Capital restant dû × i)\n• Annuités constantes (française) : part intérêts ↓, part capital ↑, annuité fixe\n  Formule : a = K × i / (1 - (1+i)^-n)\n\n**Indicateurs de gestion :**\n• Marge commerciale = CA - Coût d'achat marchandises vendues (CAMV)\n• CAF = Résultat net + Dotations aux amortissements\n• BFR = Stocks + Créances - Dettes fournisseurs\n• FR = Capitaux permanents - Actif immobilisé\n• Trésorerie nette = FR - BFR\n\n**Seuil de rentabilité :**\n• SR = Charges fixes / TMCV\n• TMCV = (CA - Charges variables) / CA\n• Point mort (jours) = SR / (CA/360)\n\n**TVA optique :**\n• Taux normal 20% (équipements optiques)\n• TVA à décaisser = TVA collectée - TVA déductible"}
  ,{id:"ol_f16",title:"Marketing et gestion commerciale avancée",bloc:"Bloc 5",tags:["Marketing","Merchandising","SWOT","NPS","Segmentation","Fidélisation","Communication digitale","100% Santé"],duree:20,niveau:"Intermédiaire",qbank:"ol_gestion_mkt",
    contenu:"**Diagnostic stratégique :**\n• SWOT : Forces/Faiblesses (internes) + Opportunités/Menaces (externes)\n• Segmentation + Ciblage + Positionnement (STP)\n\n**Merchandising :**\n• Zones chaudes (parcours naturel) vs zones froides\n• PLV : présentoirs, stops-rayons, vitrines animées\n• Marketing sensoriel : olfactif (parfum signature), musical (tempo ↓ → visite longue)\n\n**KPI commerciaux :**\n• Taux de transformation = Nb achats / Nb visiteurs × 100\n• Panier moyen = CA / Nb actes\n• NPS = % Promoteurs (9-10) - % Détracteurs (0-6)\n\n**Communication digitale :**\n• SEO local (Google My Business, avis clients)\n• Instagram (visuel), Facebook (événements)\n• Email/SMS — consentement RGPD obligatoire\n\n**100% Santé :**\n• Classe 1 : monture adulte ≤ 30 €, RAC zéro (complémentaire responsable)\n• Classe 2 : prix libre\n• Devis normalisé : 2 paniers côte à côte\n\n**Fidélisation :**\n• Cycle renouvellement 2-4 ans → maintenir la relation\n• Rappels renouvellement, programme fidélité, CRM"}
  ,{id:"ol_f17",title:"Acuité visuelle et scalimétrie",bloc:"Bloc 2",tags:["Acuité visuelle","Monoyer","Snellen","Parinaud","Landolt","Skiascopie","Réfraction"],duree:20,niveau:2,qbank:"QB_OL_ACUITEVIS_SCAL",
    contenu:"## Acuité visuelle et scalimétrie\n\n### Échelles d'acuité\n| Échelle | Pays | Usage | Notation |\n|---------|------|-------|----------|\n| Monoyer | France | Vision de loin | 1/10 à 20/10 |\n| Snellen | Anglo-saxon | Vision de loin | 20/20, 20/40... |\n| Parinaud | France | Vision de près | P1 à P14 à 33 cm |\n| Landolt | International | Étalon ISO 8596 | Orientation coupure |\n\n### Correspondances clés\n- 10/10 (Monoyer) = 20/20 (Snellen) = acuité normale\n- Minimum légal permis conduire loin : **5/10 binoculaire** (groupe 1)\n- Minimum légal permis conduire près : **P2** à 33 cm\n\n### Bases anatomiques\n- **Minimum visible** : détection d'un point (~1 cône stimulé)\n- **Minimum séparable** : 2 cônes séparés par 1 cône libre → **1 minute d'arc** → 10/10\n- **Hyperacuité de Vernier** : alignement 2 segments → **~5 secondes d'arc**\n\n### Méthode de réfraction subjective\n1. Brouillard **+3,00 D** (relâche accommodation)\n2. Diminution progressive des sphères (+0,25 D par étape)\n3. **Rosace de Lancaster** → axe du cylindre\n4. **Cylindres croisés de Jackson** → puissance du cylindre\n5. **Équilibre binoculaire** (Humphriss ou polarisation)\n\n### Skiascopie\n- Distance de travail 1 m → **lentille de travail −1,00 D** à soustraire\n- Mouvement **direct** = hypermétrope ou myope faible\n- Mouvement **inverse** = myope (point neutre dépassé)\n- Cycloplégie : **cyclopentolate 1 %** (enfant) ou **atropine 1 %** (ésotropie)"},
  ,{id:"ol_f18",title:"Prismes et systèmes optiques instrumentaux (ETSO)",bloc:"Bloc 1",tags:["Prisme","Dioptre plan","Miroir plan","Doublet","Oculaire","Pupille","Lucarne","Champs"],duree:25,niveau:"Avancé",qbank:"ol_prismes_sys",
    contenu:"**Prisme à réflexion totale interne (n=1,5) — 3 surfaces :**\n• S1 : dioptre plan air→verre (n=1 → n=1,5)\n• S2 : miroir plan (réflexion totale interne)\n• S3 : dioptre plan verre→air (n=1,5 → n=1)\n\n**Formules de conjugaison :**\n• Dioptre plan : SA' = (n'/n) × SA\n  - Air→verre (n=1→1,5) : SA' = **1,5 × SA**\n  - Verre→air (n=1,5→1) : SA' = **(2/3) × SA**\n• Miroir plan : SA' = **−SA** (symétrie, G=+1)\n\n**Espaces optiques du prisme déroulé :**\nEspace 1 (n=1) | S1 | Espace 2 (n=1,5) | S2 | Espace 2 | S3 | Espace 3 (n=1)\n\n**Méthode de construction graphique :**\n1. Remonter de P' vers S1 (conjugués antérieurs surface par surface)\n2. Construire les images du diaphragme\n3. Tracer le faisceau limité (rouge = espace départ, vert = second)\n\n**Oculaire lunette astronomique pour emmétrope :**\n• Condition de réglage : **F'₁ = F₂ = Foc** (image intermédiaire en foyer objet de L2)\n• Image finale à l'infini → faisceau parallèle sortant de L2\n\n**Théorie des champs :**\n| Notion | Définition |\n|--------|------------|\n| Pupille [P] | Limite l'ouverture angulaire (flux lumineux) |\n| Lucarne [L] | Limite le champ d'observation (angle de vue) |\n| Champ PL | 100 % du flux transmis |\n| Champ Total | Au moins un rayon passe |\n| Champ de contour | Zone 0 < E < 100 % (vignettage progressif) |\n\n**Supprimer le champ de contour :** placer [Dc] dans le plan image intermédiaire (F'₁ = F₂)\n\n**Éclairement relatif :** E% = (d_utile / d_max)² × 100"}
  ,{id:"ol_f19",title:"Parcours accommodatifs de l'œil non compensé",bloc:"Bloc 2",tags:["Ponctum remotum","Ponctum proximum","Accommodation","Parcours","Asthénopie","Myopie","Hypermétropie","Presbytie"],duree:22,niveau:"Intermédiaire",qbank:"ol_parcours_acc",
    contenu:"**3 points fondamentaux du parcours accommodatif :**\n\n| Point | Notation | Définition | Accommodation |\n|-------|----------|------------|---------------|\n| Ponctum remotum | R | Conjugué rétine à l'œil au repos | 0 δ |\n| Ponctum de confort | C | Limite de vision confortable | Aconf = Amax/2 |\n| Ponctum proximum | P | Point le plus proche vu net | Amax |\n\n**Formules clés :**\n• R = 1 / HR_barre (proximité en δ, distance en mètres)\n• **Amax = 15 − âge/4** (valable < 55 ans ; si ≥ 55 ans : Amax = 1,00 δ)\n• P = R − Amax\n• Aconf = Amax / 2\n• C = R − Aconf\n\n**Types d'yeux selon le signe de R :**\n• Emmétrope : R = 0 δ, HR = ∞\n• Myope : R < 0 (ex : −3 δ → HR = −33 cm, espace réel)\n• Hypermétrope : R > 0 (ex : +2 δ → HR = +50 cm, espace **virtuel** = derrière H)\n\n**Représentation sur axe (myope R = −3 δ, 24 ans) :**\n```\n[P ≈ −82mm] [C ≈ −167mm] [R ≈ −333mm]    [H]    [espace virtuel +]\n```\n\n**Lecture clinique :**\n• Objet dans [R, C] → vision nette ET confortable ✓\n• Objet dans [C, P] → vision nette MAIS inconfortable (asthénopie)\n• Objet hors parcours → vision floue ✗\n\n**Asthénopie accommodative :** maux de tête, yeux qui piquent/brûlent/tirent, larmoiement — signal que la distance de travail dépasse le confort. Cause fréquente : hypermétropie sous-corrigée."}
  ,{id:"ol_f20",title:"Gestion juridique du magasin d'optique",bloc:"Bloc 5",tags:["Contrat de travail","CDI","CDD","Rupture conventionnelle","Statuts juridiques","SARL","SAS","Fonds de commerce","Cession"],duree:22,niveau:"Intermédiaire",qbank:"ol_gestion_jur",
    contenu:"**CONTRAT DE TRAVAIL — Éléments essentiels :**\n• 3 éléments cumulatifs : prestation de travail + lien de subordination + rémunération\n• CDI : forme normale — période d'essai 2 mois (ouvriers) / 4 mois (cadres)\n• CDD : exception — motifs limitatifs — durée max 18 mois — indemnité précarité **10 %**\n\n**Ruptures :**\n| Mode | Droits chômage | Indemnités |\n|------|---------------|------------|\n| Démission | ✗ | Aucune |\n| Licenciement | ✓ | Légale (selon ancienneté) |\n| **Rupture conventionnelle** | ✓ | ≥ indemnité licenciement |\n\n**Clauses spéciales :** non-concurrence (5 conditions cumulatives dont contrepartie financière 30-50 %), mobilité, dédit-formation, télétravail\n\n---\n\n**STATUTS JURIDIQUES — Comparatif :**\n| Forme | Responsabilité | Régime dirigeant | Recommandation |\n|-------|----------------|------------------|----------------|\n| EI | Illimitée | TNS | ⚠️ Déconseillée |\n| EURL | Limitée aux apports | TNS | ✓ Opticien seul |\n| SARL | Limitée aux apports | Gérant maj. : TNS | ✓ Associés |\n| SASU/SAS | Limitée aux apports | Président : Assimilé salarié | ✓ Flexible |\n\n**Modèles commerciaux :** Coopérative (Optic 2000, Krys) ~40 % | Succursale (Atol) ~30 % | Franchise (Afflelou) ~15 % | Indépendant ~15 %\n\n---\n\n**FONDS DE COMMERCE :**\n• Nature juridique : **bien meuble incorporel**\n• Éléments incorporels (50-80 % valeur) : clientèle, droit au bail, nom commercial, licences\n• Évaluation préférentielle : **multiple de l'EBE** (3 à 5×)\n• Cession : 7 étapes — promesse → audits → financement → acte notarié → publication JAL (15j) → RCS\n• 5 pièges : surévaluer clientèle, négliger matériel, oublier bail, sous-estimer BFR, ne pas auditer\n\n**Autorisations ouverture magasin :** diplôme OL + enregistrement **ARS** + immatriculation **RCS**"}


  ,{id:"ol_f21",title:"Étude des champs — Théorie complète (ETSO)",bloc:"Bloc 1",tags:["Étude des champs","Pupille","Lucarne","PL","Champ total","Vignettage","Lunette astronomique","ETSO"],duree:25,niveau:"Avancé",qbank:"ol_champs",
    contenu:"**Définition :** L'étude des champs analyse l'éclairement d'un système optique — du maximum uniforme au centre à l'extinction en périphérie.\n\n**4 éléments fondamentaux :**\n| Élément | Définition | Tracé |\n|---------|------------|-------|\n| **Pupille [P]** | Diaphragme vu sous αmini depuis le CENTRE DU PLAN DES CHAMPS | Non fléché, sans ponctué |\n| **Lucarne [L]** | Diaphragme vu sous βmini depuis le CENTRE DE [P] | Fléché et ponctué |\n| **Champ PL** | 100 % flux transmis (faisceau pleine ouverture) | Surface — colorier |\n| **Champ T** | Un seul rayon passe (0 % flux) | Ligne |\n| **Champ M** | ~50 % (faisceau demi-ouverture, rayon vers bord [L]) | Ligne |\n\n**Règle d'or :** Comparer les diaphragmes dans le MÊME espace — conjuguer si nécessaire\n\n**Relation obligatoire à vérifier :** ØPL ≤ ØM ≤ ØT\n\n**Champ de contour** (entre PL et T) : vignettage progressif — image moins contrastée mais PAS plus floue\n\n**Supprimer le champ de contour :** placer [Dc] réel sur le plan intermédiaire réel, à la taille de PL\n\n**Vues :**\n• Vue de face : champs = points\n• Vue de gauche : vraie grandeur — PL = disque plein, T et M = arcs/lignes\n\n**Lunette astronomique :**\n• G = f'obj / f'oc\n• Plan intermédiaire réel = F'obj = Foc\n• αlim réflexion totale (n=1,5) = 41,8°\n• Mécanisme pignon-crémaillère : d = 2πRp × n (tours)"}
  ,{id:"ol_f22",title:"Contrôle d'équipement — Verres double-foyers",bloc:"Bloc 4",tags:["Double-foyer","CT28","Telarc","Trilentar","Telemil","Telex","Contrôle équipement","Pastille","Hauteur","Prisme"],duree:22,niveau:"Avancé",qbank:"ol_ce_df",
    contenu:"**Verres double-foyers — Comparatif des modèles :**\n\n| Modèle | Matière | Pastille | Hauteur | Ecart | Prisme H |\n|--------|---------|----------|---------|-------|----------|\n| **CT28** (Essilor) | Organique 1,5 | 28 mm, courbe | 18 mm | VP (moitié pastille) | +5 depuis VP |\n| **Telarc 28** (Essilor) | Minéral 1,5 | 28 mm, fusionnée | 19 mm | VP (moitié pastille) | +5 depuis VP |\n| **Trilentar 28** (Rodenstock) | Minéral | 28 mm | **14 mm** | **VL** (≠ Essilor) | **+2** depuis VP |\n| **Telemil 28** | Organique | 28 mm | 5 mm | VL (Ditest) | VL |\n| **Telex** | - | VP intégrale | - | VL (frontofoc.) | Impossible après taillage |\n\n**Différence au toucher :**\n• CT28 : boursouflure palpable à la jonction VL/VP (organique — pastille rapportée)\n• Telarc 28 : surface lisse (minéral — pastille fusionnée)\n\n**Formule ADD :** ADD = VP − VL\n(Commander la VL ; ajouter l'ADD calculée)\n\n**Règles d'examen BTS OL :**\n• Oublier de cocher une conformité = **ZÉRO à toute la case**\n• Renseigner intégralement la case produit même si les verres ne sont pas gravés\n\n**Points critiques :**\n• Horizontalité des pastilles VP (les deux au même niveau)\n• Hauteur mesurée de la tangente inférieure du calibre à la tangente inférieure de la pastille"}
  ,{id:"ol_f23",title:"Contrôle d'équipement — Progressifs & Généralités",bloc:"Bloc 4",tags:["Contrôle équipement","Progressifs","ISO 21987","Gravures","Profondeur de champ","Inversion OD OG","Frontofocusmètre"],duree:18,niveau:"Intermédiaire",qbank:"ol_controle_eq",
    contenu:"**Profondeur de champ :**\n• ∝ 1/D pupillaire — petite pupille → grande profondeur de champ\n• Myosis solaire, sénescence → masque presbytie débutante\n• Myope qui plisse les yeux → effet sténopéique (diamètre ↓ → netteté ↑)\n\n**Contrôle progressif au frontofocusmètre :**\n1. Positionner verre : côté convexe (face avant) vers le bas\n2. Repérer les gravures permanentes (croix nasale/temporale)\n3. Mesurer VL en zone de loin (au centre optique marqué)\n4. Déplacer vers zone VP → mesurer V(VP)\n5. ADD = V(VP) − V(VL) → vérifier ± 0,12 δ (ISO 21987)\n\n**Tolérances ISO 21987 :**\n| Paramètre | Tolérance |\n|-----------|----------|\n| Vergence sphérique (< 6 δ) | ± 0,09 δ |\n| Vergence cylindrique | ± 0,09 δ |\n| ADD | ± 0,12 δ |\n| Prisme (< 2 Δ) | ± 0,25 Δ |\n| Axe (cylindre ≥ 0,50 δ) | ± 2° à 5° |\n\n**Inversion OD/OG :** axes cylindres inversés — détection : axe mesuré ≠ ordonnance + effet prismatique différentiel anormal\n\n**Gravures permanentes :** révélées à la loupe ou lampe UV — identifient le modèle, l'ADD, les points de mesure VL/VP"}

  ,{id:"ol_f24",title:"Miroir sphérique — Conjugaison et construction",bloc:"Bloc 1",tags:["Miroir sphérique","Conjugaison","Foyer","Grandissement","ETSO"],duree:20,niveau:"Intermédiaire",qbank:"ol_miroir_sph",
    contenu:"**Relation de conjugaison (convention algébrique) :**\n1/SA' + 1/SA = 2/SC = 1/f'\n\n**f' = SC/2** (foyer au milieu de [SC])\n\n**Différence clé / lentilles :** F = F' (foyer unique)\n\n**Grandissement :** G = SA'/SA\n• G > 0 → image droite\n• G < 0 → image renversée\n\n**3 rayons particuliers :**\n• Parallèle à l'axe → réfléchi vers F\n• Vers F → réfléchi parallèle à l'axe\n• Vers C → retour sur lui-même\n\n**Tableau des positions :**\n| Position de A | Image A' |\n|---|---|\n| Avant C (au-delà) | Réelle, renversée, réduite entre F et C |\n| En C | Réelle, renversée, même taille en C |\n| Entre C et F | Réelle, renversée, agrandie au-delà de C |\n| En F | À l'infini |\n| Entre F et S | Virtuelle, droite, agrandie |\n\n**Miroir concave :** foyer réel (devant) → V > 0\n**Miroir convexe :** foyer virtuel (derrière) → V < 0 → image toujours virtuelle, droite, réduite\n\n**Vergence :** V = 2/R = 1/f' (R en mètres)"}
  ,{id:"ol_f25",title:"Dioptre sphérique — Réfraction et application à l'œil",bloc:"Bloc 1",tags:["Dioptre sphérique","Réfraction","Indices","Œil","Formules","ETSO"],duree:22,niveau:"Avancé",qbank:"ol_dioptre_sph",
    contenu:"**Relation de conjugaison :**\nn'/SA' - n/SA = (n'-n)/R\n\nAvec n = indice espace objet, n' = indice espace image, R = SC (rayon algébrique)\n\n**Vergence :** D = (n'-n)/R\n\n**Foyers :**\n• SF = -n/D (foyer objet)\n• SF' = n'/D (foyer image)\n\n**Grandissement :**\nG = (n × SA')/(n' × SA)\n\n**(≠ lentilles en air où G = SA'/SA)**\n\n**Dioptre plan (R → ∞) :**\nSA' = (n'/n) × SA\n• Air → verre (n=1 → n=1,5) : SA' = 1,5 × SA\n• Verre → air (n=1,5 → n=1) : SA' = (2/3) × SA\n\n**Indices de l'œil :**\n| Milieu | Indice n |\n|--------|----------|\n| Air | 1,000 |\n| Cornée | 1,377 |\n| Humeur aqueuse / Corps vitré | 1,336 |\n| Cristallin | 1,420 |\n\n**Puissance de la cornée :**\nD_cornée = (1,377 - 1,000)/0,0077 ≈ **49 δ**\n\n**Puissance totale de l'œil emmétrope ≈ 60 δ**\n(cornée + cristallin)\n\n**Vergences additives (systèmes accolés) :**\nD_total = D₁ + D₂\n(Pour systèmes séparés : formule de Gullstrand)"}
  ,{id:"ol_f26",title:"Frontofocusmètre — Principe et mesures",bloc:"Bloc 4",tags:["Frontofocusmètre","Vergence","Contrôle","ISO 21987","ADD","Prisme"],duree:20,niveau:"Intermédiaire",qbank:"ol_fronto",
    contenu:"**Structure :** [Collimateur C] → [Verre V à mesurer] → [Objectif Ob] → [Réticule] → [Oculaire Oc] → [Œil]\n\n**Condition de réglage :**\nF'_collimateur = F_verre → faisceau parallèle → image nette à l'infini (observateur emmétrope)\n\n**Mesures :**\n• Vergence sphérique D (δ)\n• Cylindre et axe\n• Prisme et base\n• Centrage du verre\n\n**Ensemble Ob+Oc afocal :** F'ob = Foc\n\n**Tolérances ISO 21987 :**\n| Paramètre | Tolérance |\n|-----------|----------|\n| Vergence < 6 δ | ± 0,09 δ |\n| ADD | ± 0,12 δ |\n| Prisme < 2 Δ | ± 0,25 Δ |\n| Axe (cyl ≥ 0,50 δ) | ± 2° à 5° |\n\n**Progressif — Protocole :**\n1. Verre côté convexe vers le bas\n2. Orienter avec les gravures (croix nasale)\n3. Mesurer VL → V(VL)\n4. Glisser vers zone VP → V(VP)\n5. ADD = V(VP) - V(VL)\n\n**Prisme par décentrement :** P = D × d (D en δ, d en cm)\n\n**Pièges :**\n• Confondre F'ob et Foc (afocal seulement pour emmétrope)\n• Oublier d'orienter le progressif avant mesure"}
  ,{id:"ol_f27",title:"Lunette astronomique & système Galilée (ETSO)",bloc:"Bloc 1",tags:["Lunette astronomique","Galilée","Afocalisme","Grossissement","Champs","ETSO"],duree:25,niveau:"Avancé",qbank:"ol_lunette_galilee",
    contenu:"**Condition d'afocalisme :** F'_obj = F_oc\n(plan intermédiaire = plan focal objet de l'oculaire)\n\n**Grossissement commercial :**\nG = f'_obj / f'_oc\n\n**Comparatif :**\n| Critère | Lunette astro | Galilée |\n|---------|--------------|--------|\n| Oculaire | Convergent | **Divergent** |\n| Image | Renversée | **Droite** |\n| Longueur tube | f'obj + f'oc | f'obj - \|f2\| (plus court) |\n| Champ | Plus large | Plus étroit |\n\n**Plan des champs :** plan intermédiaire F'obj = Foc\n\n**Pupille d'entrée :** objectif (D1)\n**Pupille de sortie (œil de sortie) :** conjugué de D1 par l'oculaire → juste derrière l'oc\n\n**Méthode champs (2 diaphragmes) :**\n1. Projeter D1 et D2 dans l'espace intermédiaire\n2. Le plus petit conjugué = pupille [P]\n3. L'autre = lucarne [L]\n4. Tracer PL (pleine lumière), T (bord), M (mi-champ)\n\n**Supprimer le champ de contour :**\nPlacer [Dc] réel dans le plan intermédiaire (F'obj = Foc)\n\n**Applications OL :**\n• Galilée : loupes télescopiques basse vision, compact, image droite\n• Astronomique : jumelles (avec prismes inverseurs)"}
  ,{id:"ol_f28",title:"Faisceau lumineux & systèmes centrés",bloc:"Bloc 1",tags:["Systèmes centrés","Faisceau","Conjugaison","Vergence","Plans principaux","Méthode ETSO"],duree:22,niveau:"Intermédiaire",qbank:"ol_faisceau_sc",
    contenu:"**Système centré :** surfaces de révolution autour d'un axe optique\n\n**Éléments cardinaux :**\n• Plans principaux H, H'\n• Foyers objet F (SF = -f), image F' (H'F' = f')\n• Vergence V = n'/f'\n\n**Méthode de tracé de faisceau :**\n1. Tableau des conjugués : A → A' et D → D'\n2. Identifier l'espace de départ (A ET D dans le même espace)\n3. Tracer depuis A, bords de D\n4. Propager via H → H'\n\n**Code couleur :** Rouge = espace de départ | Vert = second espace\n\n**3 rayons particuliers :**\n• Parallèle à l'axe → passe par F'\n• Vers F → ressort parallèle\n• Vers H → sort de H' sans déviation\n\n**Objet/image :**\n| Position A | Image A' |\n|---|---|\n| A à l'infini | A' en F' |\n| A en F | A' à l'infini |\n| A entre F et H | A' virtuelle (côté A) |\n\n**Objet virtuel :** SA > 0, faisceau convergent entrant\n**Conjugué antérieur [D0] :** image de D dans l'espace objet (si D est dans espace image)\n\n**Vergence nulle (système afocal) :** foyers à l'infini → faisceau parallèle reste parallèle\n\n**Vergence en milieu d'indice n' :** V = n'/f' (≠ 1/f' si n' ≠ 1)"}

];

